                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie data={borraChartData} cx="50%" cy="50%" outerRadius={100} innerRadius={60} dataKey="borra" nameKey="name" label={renderCustomizedLabel} paddingAngle={2}>
