               </div>

               <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex flex-col h-[520px]">
                  <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">⏱️ Tempo de Parada</h3>
                  {stopsOverviewData.length > 0 ? (
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie data={stopsOverviewData} cx="50%" cy="50%" outerRadius={100} innerRadius={60} dataKey="value" nameKey="name" label={renderCustomizedLabel} paddingAngle={2}>
                          <Cell fill="#ef4444" stroke="none" />
                          <Cell fill="#f59e0b" stroke="none" />
                          <Cell fill="#64748b" stroke="none" />
                        </Pie>
