                  <button onClick={() => setTeamViewMode('shifts')} className={`text-xs font-black uppercase tracking-widest pb-1 border-b-2 whitespace-nowrap transition-all ${teamViewMode === 'shifts' ? 'border-orange-600 text-orange-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Turnos</button>
                  <button onClick={() => setTeamViewMode('vacancies')} className={`text-xs font-black uppercase tracking-widest pb-1 border-b-2 whitespace-nowrap transition-all ${teamViewMode === 'vacancies' ? 'border-red-600 text-red-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}>Vagas</button>
