                  return (
                    <div key={key} className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
                      <div className="bg-slate-50 px-4 py-2 font-black text-[9px] text-slate-500 uppercase border-b">{key}</div>
