      />

      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
      <EmployeeModal isOpen={isEmployeeModalOpen} onClose={() => setIsEmployeeModalOpen(false)} onSave={(e) => setOperators(prev => [...prev, e.name])} availableShifts={shifts} availableMachines={['Cast 1', 'Cast 2']} />
    </div>
  );
};

