                      <td className="px-6 py-4">{e.date}</td>
                      <td className="px-6 py-4">{e.operator}</td>
                      <td className="px-6 py-4">{e.netWeight} kg</td>
                      <td className="px-6 py-4 text-emerald-600">{e.ecoA} kg</td>
                      <td className="px-6 py-4 text-red-500">{e.borraTotal} kg</td>
