import { ProductionEntry } from './types';

// Lista de operadores para testes
export const DEFAULT_OPERATORS: string[] = [
  "Adaias Melo",
  "João Silva",
  "Ricardo Souza",
  "Bruno Oliveira",
  "Marcos Santos"
];

// Função auxiliar para gerar dados fake de forma programática para o INITIAL_DATA
const generateFakeData = (): ProductionEntry[] => {
  const data: ProductionEntry[] = [];
  const today = new Date();
  const start = new Date();
  start.setDate(today.getDate() - 1); // Define início como ontem para ter exatamente 2 dias

  const machines = ["Cast 1", "Cast 2", "Erema 1"];
  const shifts = ["Diurno 1", "Noturno 1"];

  let currentDate = new Date(start);

  while (currentDate <= today) {
    const dateStr = currentDate.toISOString().split('T')[0];

    // Simular produção para cada máquina no dia
    machines.forEach(machine => {
      const isMaintenance = Math.random() < 0.1; // 10% de chance de ser dia de manutenção
      const operator = DEFAULT_OPERATORS[Math.floor(Math.random() * DEFAULT_OPERATORS.length)];

      if (isMaintenance) {
        data.push({
          id: Math.random().toString(36).substr(2, 9),
          date: dateStr,
          operator: operator,
          machine: machine,
          shift: shifts[Math.floor(Math.random() * shifts.length)],
          grossWeight: 0,
          tara: 0,
          netWeight: 0,
          volumes: 0,
          tubetes: 0,
          ecoA: 0,
          ecoBP: 0,
          ecoBM: Math.floor(Math.random() * 50),
          borraTotal: 0,
          manutencaoMin: 120 + Math.floor(Math.random() * 240),
          manutencaoMotivo: "Troca de filtro / Limpeza",
          processoMin: 0,
          outrosMin: 0,
          isMaintenanceEntry: true
        });
      } else {
        const gross = 1200 + Math.floor(Math.random() * 800);
        const tara = 100 + Math.floor(Math.random() * 50);
        const net = gross - tara;

        data.push({
          id: Math.random().toString(36).substr(2, 9),
          date: dateStr,
          operator: operator,
          machine: machine,
          shift: shifts[Math.floor(Math.random() * shifts.length)],
          grossWeight: gross,
          tara: tara,
          netWeight: net,
          volumes: Math.floor(net / 25),
          tubetes: Math.floor(net / 50),
          ecoA: Math.floor(Math.random() * 100),
          ecoBP: Math.floor(Math.random() * 80),
          ecoBM: 0,
          borraTotal: 20 + Math.floor(Math.random() * 40),
          manutencaoMin: 0,
          processoMin: Math.floor(Math.random() * 45),
          outrosMin: 0,
          isMaintenanceEntry: false
        });
      }
    });

    currentDate.setDate(currentDate.getDate() + 1);
  }

  return data.reverse(); // Mais recentes primeiro
};

// Histórico de produção populado com dados gerados
export const INITIAL_DATA: ProductionEntry[] = generateFakeData();

