                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes },
                { title: '📊 Prod vs Reciclagem', key: 'prod', color: COLORS, formatter: formatWeight }
              ].map((chart, idx) => {
                const chartData = stats.filter(s => s[chart.key as keyof OperatorStat] > 0);
                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-[400px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
                    <div className="flex-1">
                      {chartData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                          <PieChart>
                            <Pie 
                              data={chartData} 
                              cx="50%" 
                              cy="50%" 
                              innerRadius={60} 
                              outerRadius={85} 
                              dataKey={chart.key} 
                              nameKey="name" 
                              label={renderCustomizedLabel}
                              paddingAngle={2}
                            >
                              {chartData.map((_, i) => <Cell key={i} fill={chart.color[i % chart.color.length]} stroke="none" />)}
                            </Pie>
                            <Tooltip formatter={(val: any) => chart.formatter(val)} />
                            <Legend iconType="circle" />
                          </PieChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="h-full flex items-center justify-center text-slate-300 font-bold text-xs uppercase">Sem dados</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : activeTab === 'reports' ? (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between gap-4">
              <div className="relative flex-1 max-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Pesquisar registros..." 
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none" 
                />
              </div>
              <div className="flex items-center gap-2 no-print">
                {selectedIds.length > 0 && (
                  <button 
                    onClick={() => {
                      const count = selectedIds.length;
                      if (window.confirm(`Confirma a exclusão de ${count} registros selecionados?`)) {
                        const idsToRemove = new Set(selectedIds);
                        setProductionData(prev => prev.filter(item => !idsToRemove.has(item.id)));
                        setSelectedIds([]);
                      }
                    }} 
                    className="flex items-center gap-2 px-4 py-2.5 bg-red-50 text-red-600 rounded-xl text-[10px] font-black uppercase hover:bg-red-100 transition-all animate-in fade-in"
                  >
                    <Trash2 size={16} /> Excluir ({selectedIds.length})
                  </button>
                )}
                <button onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[600px]">
                <thead>
                  <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4 w-10 no-print">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                        checked={selectedIds.length > 0 && selectedIds.length === productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).length}
                        onChange={(ev) => {
                          if (ev.target.checked) {
                            const filteredIds = productionData.filter(item => item.operator.toLowerCase().includes(searchTerm.toLowerCase())).map(item => item.id);
                            setSelectedIds(filteredIds);
                          } else {
                            setSelectedIds([]);
                          }
                        }}
                      />
                    </th>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Operador</th>
                    <th className="px-6 py-4">Líquido</th>
                    <th className="px-6 py-4">Eco A</th>
                    <th className="px-6 py-4">Borra</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-xs font-bold">
                  {productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).map((e) => (
                    <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/50' : ''}`}>
                      <td className="px-6 py-4 w-10 no-print">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                          checked={selectedIds.includes(e.id)}
                          onChange={() => {
                            setSelectedIds(prev => prev.includes(e.id) ? prev.filter(id => id !== e.id) : [...prev, e.id]);
                          }}
                        />
                      </td>
                      <td className="px-6 py-4">{e.date}</td>
                      <td className="px-6 py-4">{e.operator}</td>
                      <td className="px-6 py-4">{e.netWeight} kg</td>
                      <td className="px-6 py-4 text-emerald-600">{e.ecoA} kg</td>
                      <td className="px-6 py-4 text-red-500">{e.borraTotal} kg</td>
                      <td className="px-6 py-4 text-right space-x-2">
                        <button onClick={() => { setEditingEntry(e); setIsModalOpen(true); }} className="text-blue-500 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={14} /></button>
                        <button onClick={() => {
                          if (window.confirm('Deseja excluir este registro?')) {
                            setProductionData(prev => prev.filter(x => x.id !== e.id));
                            setSelectedIds(prev => prev.filter(id => id !== e.id));
                          }
                        }} className="text-red-400 p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
              <div className="flex justify-between items-center mb-6">
                <h3 className="font-black text-xs uppercase tracking-widest text-slate-800">Operadores</h3>
                <button onClick={() => setIsEmployeeModalOpen(true)} className="p-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-100"><Plus size={16} /></button>
              </div>
              <div className="space-y-3">
                {operators.map((op, i) => (
                  <div key={i} className="flex items-center justify-between p-3 bg-slate-50 rounded-2xl">
                    <span className="text-xs font-bold text-slate-700">{op}</span>
                    <button onClick={() => setOperators(prev => prev.filter(x => x !== op))} className="text-slate-300 hover:text-red-500"><Trash2 size={14} /></button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </main>

      <div className={`fixed inset-0 z-50 transition-all ${isMenuOpen ? 'visible' : 'invisible'}`}>
        <div className={`absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} onClick={() => setIsMenuOpen(false)} />
        <div className={`absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl transition-transform duration-300 transform p-8 flex flex-col gap-8 ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2"><Settings size={22} /> Ajustes</h2>
            <button onClick={() => setIsMenuOpen(false)} className="p-2 text-slate-400"><X size={24} /></button>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nova Meta Mensal (KG)</label>
              <input 
                type="number" 
                value={goalValue} 
                onChange={(e) => setGoalValue(parseFloat(e.target.value) || 0)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-black text-blue-600 outline-none" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Adicionar Operador</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  value={newOpName} 
                  onChange={e => setNewOpName(e.target.value)}
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-4 py-2 text-xs font-bold" 
                />
                <button 
                  onClick={() => { if (newOpName) { setOperators(prev => [...prev, newOpName]); setNewOpName(''); } }}
                  className="bg-blue-600 text-white p-3 rounded-2xl"
                >
                  <Plus size={18} />
                </button>
              </div>
            </div>
            <div className="pt-8 border-t border-slate-100 space-y-3">
              <button onClick={() => {
                const data = { productionData, employees, shifts, goalValue, operators };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'backup_manupackaging.json';
                a.click();
              }} className="w-full flex items-center justify-center gap-3 bg-slate-100 py-4 rounded-2xl text-[10px] font-black uppercase text-slate-600"><Download size={16} /> Exportar Backup</button>

              <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 bg-blue-50 py-4 rounded-2xl text-[10px] font-black uppercase text-blue-600"><Upload size={16} /> Importar Backup</button>

              <button onClick={() => { localStorage.removeItem('manupackaging_session'); setIsAuthenticated(false); }} className="w-full flex items-center justify-center gap-3 bg-red-50 py-4 rounded-2xl text-[10px] font-black uppercase text-red-600"><LogOut size={16} /> Sair do Sistema</button>
            </div>
          </div>
        </div>
      </div>

      <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />

      <LaunchModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingEntry(null); }} 
        onSave={handleSaveEntry} 
        operators={operators} 
        activeMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        availableShifts={shifts} 
        initialData={editingEntry} 
      />

      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
      <EmployeeModal isOpen={isEmployeeModalOpen} onClose={() => setIsEmployeeModalOpen(false)} onSave={(e) => setOperators(prev => [...prev, e.name])} availableShifts={shifts} availableMachines={['Cast 1', 'Cast 2']} />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, Settings, BarChart3, FileText, Users2, Search, 
  Printer, ShieldCheck, Download, Upload, Trash2, Cpu, 
  Clock, Save, X, Edit2, LogOut, Briefcase, MapPin, Activity
} from 'lucide-react';
import { 
  Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { ProductionEntry, Shift } from './types';
import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';
import EmployeeModal from './components/EmployeeModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.1;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports' | 'personnel'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'year' | 'day' | 'week' | 'all'>('all');

  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    const saved = localStorage.getItem('manupackaging_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [employees, setEmployees] = useState<any[]>(() => {
    const saved = localStorage.getItem('manupackaging_employees');
    return saved ? JSON.parse(saved) : [];
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [isEmployeeModalOpen, setIsEmployeeModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<any | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_employees', JSON.stringify(employees)); }, [employees]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  const handleSaveEmployee = (empData: any) => {
    let updatedEmployees;
    if (empData.id) {
      updatedEmployees = employees.map(e => e.id === empData.id ? empData : e);
    } else {
      updatedEmployees = [...employees, { ...empData, id: Math.random().toString(36).substr(2, 9) }];
    }
    setEmployees(updatedEmployees);

    // Sincroniza operadores (apenas ativos ou em férias, omitindo vagas abertas na lista de lançamento se desejar)
    const activeNames = updatedEmployees
      .filter(e => e.status !== 'Vaga Aberta')
      .map(e => e.name);

    // Mantém operadores que podem ter sido adicionados manualmente mas não estão no RH (se houver)
    const existingManual = operators.filter(op => !employees.find(e => e.name === op));
    setOperators(Array.from(new Set([...activeNames, ...existingManual])));
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.productionData) setProductionData(data.productionData);
        if (data.operators) setOperators(data.operators);
        if (data.goalValue) setGoalValue(data.goalValue);
        if (data.shifts) setShifts(data.shifts);
        if (data.employees) setEmployees(data.employees);
        alert('Dados importados com sucesso!');
      } catch (err) {
        alert('Erro ao importar arquivo.');
      }
    };
    reader.readAsText(file);
  };

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'year') return e.date.startsWith(now.getFullYear().toString());
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const todayStr = new Date().toLocaleDateString('sv-SE');
    const monthPrefix = new Date().toISOString().slice(0, 7);
    return productionData.reduce((acc, e) => {
      acc.month += e.date.startsWith(monthPrefix) ? e.netWeight : 0;
      acc.day += e.date === todayStr ? e.netWeight : 0;
      return acc;
    }, { month: 0, day: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => { setEditingEntry(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-700 text-white font-black px-5 py-2.5 rounded-xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
          >
            <Plus size={16} /> Novo Lançamento
          </button>
          <button onClick={() => setIsMenuOpen(true)} className="p-2.5 text-slate-400 hover:bg-slate-100 rounded-xl transition-all">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto px-4 mt-6 no-print">
        <div className="bg-slate-200/50 p-1 rounded-2xl inline-flex gap-1 overflow-x-auto no-scrollbar max-w-full">
          {[
            { id: 'dashboard', icon: <BarChart3 size={14} />, label: 'Dashboard' },
            { id: 'reports', icon: <FileText size={14} />, label: 'Relatórios' },
            { id: 'personnel', icon: <Users2 size={14} />, label: 'Operadores' }
          ].map((tab) => (
            <button 
              key={tab.id} 
              onClick={() => { 
                setActiveTab(tab.id as any);
                setSelectedIds([]); 
              }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-4 space-y-6">
        {activeTab === 'dashboard' ? (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 space-y-4">
                <div className="flex justify-between items-end">
                  <div>
                    <span className="text-[10px] uppercase font-black tracking-widest text-slate-400">Meta do Mês</span>
                    <div className="text-3xl font-black text-slate-800">{(totals.month / 1000).toFixed(1)} T</div>
                  </div>
                  <div className="text-right">
                    <div className="text-2xl font-black text-blue-600">{goalValue > 0 ? Math.round((totals.month / goalValue) * 100) : 0}%</div>
                    <span className="text-[10px] font-bold text-slate-300">de {(goalValue/1000).toFixed(0)} T</span>
                  </div>
                </div>
                <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
