  useEffect(() => { localStorage.setItem('manupackaging_employees', JSON.stringify(employees)); }, [employees]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  const handleSaveEmployee = (empData: any) => {
    let updatedEmployees;
    if (empData.id) {
      updatedEmployees = employees.map(e => e.id === empData.id ? empData : e);
    } else {
      updatedEmployees = [...employees, { ...empData, id: Math.random().toString(36).substr(2, 9) }];
    }
    setEmployees(updatedEmployees);

    // Sincroniza operadores (apenas ativos ou em férias, omitindo vagas abertas na lista de lançamento se desejar)
    const activeNames = updatedEmployees
      .filter(e => e.status !== 'Vaga Aberta')
      .map(e => e.name);

    // Mantém operadores que podem ter sido adicionados manualmente mas não estão no RH (se houver)
    const existingManual = operators.filter(op => !employees.find(e => e.name === op));
    setOperators(Array.from(new Set([...activeNames, ...existingManual])));
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.productionData) setProductionData(data.productionData);
        if (data.operators) setOperators(data.operators);
        if (data.goalValue) setGoalValue(data.goalValue);
        if (data.shifts) setShifts(data.shifts);
        if (data.employees) setEmployees(data.employees);
        alert('Dados importados com sucesso!');
      } catch (err) {
        alert('Erro ao importar arquivo.');
      }
    };
    reader.readAsText(file);
  };

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'year') return e.date.startsWith(now.getFullYear().toString());
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const todayStr = new Date().toLocaleDateString('sv-SE');
    const monthPrefix = new Date().toISOString().slice(0, 7);
    return productionData.reduce((acc, e) => {
      acc.month += e.date.startsWith(monthPrefix) ? e.netWeight : 0;
      acc.day += e.date === todayStr ? e.netWeight : 0;
      return acc;
    }, { month: 0, day: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => { setEditingEntry(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-700 text-white font-black px-5 py-2.5 rounded-xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
          >
            <Plus size={16} /> Novo Lançamento
          </button>
          <button onClick={() => setIsMenuOpen(true)} className="p-2.5 text-slate-400 hover:bg-slate-100 rounded-xl transition-all">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto px-4 mt-6 no-print">
        <div className="bg-slate-200/50 p-1 rounded-2xl inline-flex gap-1 overflow-x-auto no-scrollbar max-w-full">
          {[
            { id: 'dashboard', icon: <BarChart3 size={14} />, label: 'Dashboard' },
            { id: 'reports', icon: <FileText size={14} />, label: 'Relatórios' },
            { id: 'personnel', icon: <Users2 size={14} />, label: 'Operadores' }
          ].map((tab) => (
            <button 
              key={tab.id} 
              onClick={() => { 
                setActiveTab(tab.id as any);
                setSelectedIds([]); 
              }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-4 space-y-6">
        {activeTab === 'dashboard' ? (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 space-y-4">
                <div className="flex justify-between items-end">
                  <div>
                    <span className="text-[10px] uppercase font-black tracking-widest text-slate-400">Meta do Mês</span>
                    <div className="text-3xl font-black text-slate-800">{(totals.month / 1000).toFixed(1)} T</div>
                  </div>
                  <div className="text-right">
                    <div className="text-2xl font-black text-blue-600">{goalValue > 0 ? Math.round((totals.month / goalValue) * 100) : 0}%</div>
                    <span className="text-[10px] font-bold text-slate-300">de {(goalValue/1000).toFixed(0)} T</span>
                  </div>
                </div>
                <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
                  <div className="h-full bg-blue-600 rounded-full transition-all duration-1000" style={{ width: `${Math.min((totals.month / (goalValue || 1)) * 100, 100)}%` }}></div>
                </div>
              </div>

              <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex items-center justify-between">
                <div>
                  <span className="text-[10px] uppercase font-black tracking-widest text-emerald-500">Produção Hoje</span>
                  <div className="text-3xl font-black text-slate-800">{formatWeight(totals.day)}</div>
                </div>
                <div className="w-12 h-12 bg-emerald-50 rounded-2xl flex items-center justify-center text-emerald-600">
                  <Cpu size={24} />
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes },
                { title: '📊 Prod vs Reciclagem', key: 'prod', color: COLORS, formatter: formatWeight }
              ].map((chart, idx) => {
                const chartData = stats.filter(s => s[chart.key as keyof OperatorStat] > 0);
                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-[400px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
                    <div className="flex-1">
                      {chartData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                          <PieChart>
                            <Pie 
                              data={chartData} 
                              cx="50%" 
                              cy="50%" 
                              innerRadius={60} 
                              outerRadius={85} 
                              dataKey={chart.key} 
                              nameKey="name" 
                              label={renderCustomizedLabel}
                              paddingAngle={2}
                            >
                              {chartData.map((_, i) => <Cell key={i} fill={chart.color[i % chart.color.length]} stroke="none" />)}
                            </Pie>
                            <Tooltip formatter={(val: any) => chart.formatter(val)} />
                            <Legend 
                              iconType="circle" 
                              formatter={(value) => {
                                const item = chartData.find(d => d.name === value);
                                const val = item ? item[chart.key as keyof OperatorStat] : 0;
                                return <span className="text-[10px] font-bold text-slate-500">{value} ({chart.formatter(val as number)})</span>;
                              }}
                            />
                          </PieChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="h-full flex items-center justify-center text-slate-300 font-bold text-xs uppercase">Sem dados</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : activeTab === 'reports' ? (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between gap-4">
              <div className="relative flex-1 max-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Pesquisar registros..." 
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none" 
                />
              </div>
              <div className="flex items-center gap-2 no-print">
                {selectedIds.length > 0 && (
                  <button 
                    onClick={() => {
                      const count = selectedIds.length;
                      if (window.confirm(`Confirma a exclusão de ${count} registros selecionados?`)) {
                        const idsToRemove = new Set(selectedIds);
                        setProductionData(prev => prev.filter(item => !idsToRemove.has(item.id)));
                        setSelectedIds([]);
                      }
                    }} 
                    className="flex items-center gap-2 px-4 py-2.5 bg-red-50 text-red-600 rounded-xl text-[10px] font-black uppercase hover:bg-red-100 transition-all animate-in fade-in"
                  >
                    <Trash2 size={16} /> Excluir ({selectedIds.length})
                  </button>
                )}
                <button onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[600px]">
                <thead>
                  <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4 w-10 no-print">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                        checked={selectedIds.length > 0 && selectedIds.length === productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).length}
                        onChange={(ev) => {
                          if (ev.target.checked) {
                            const filteredIds = productionData.filter(item => item.operator.toLowerCase().includes(searchTerm.toLowerCase())).map(item => item.id);
                            setSelectedIds(filteredIds);
                          } else {
                            setSelectedIds([]);
                          }
                        }}
                      />
                    </th>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Operador</th>
                    <th className="px-6 py-4">Líquido</th>
                    <th className="px-6 py-4">Eco A</th>
                    <th className="px-6 py-4">Borra</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-xs font-bold">
                  {productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).map((e) => (
                    <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/50' : ''}`}>
                      <td className="px-6 py-4 w-10 no-print">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                          checked={selectedIds.includes(e.id)}
                          onChange={() => {
                            setSelectedIds(prev => prev.includes(e.id) ? prev.filter(id => id !== e.id) : [...prev, e.id]);
                          }}
                        />
                      </td>
                      <td className="px-6 py-4">{e.date}</td>
                      <td className="px-6 py-4">{e.operator}</td>
                      <td className="px-6 py-4">{e.netWeight} kg</td>
                      <td className="px-6 py-4 text-emerald-600">{e.ecoA} kg</td>
                      <td className="px-6 py-4 text-red-500">{e.borraTotal} kg</td>
                      <td className="px-6 py-4 text-right space-x-2">
                        <button onClick={() => { setEditingEntry(e); setIsModalOpen(true); }} className="text-blue-500 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={14} /></button>
                        <button onClick={() => {
                          if (window.confirm('Deseja excluir este registro?')) {
                            setProductionData(prev => prev.filter(x => x.id !== e.id));
                            setSelectedIds(prev => prev.filter(id => id !== e.id));
                          }
                        }} className="text-red-400 p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex items-center justify-between bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
              <div>
                <h2 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Equipe de Operação</h2>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Gestão de Colaboradores e Escalas</p>
              </div>
              <button 
                onClick={() => { setEditingEmployee(null); setIsEmployeeModalOpen(true); }}
                className="bg-blue-600 hover:bg-blue-700 text-white font-black px-6 py-3 rounded-2xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
              >
                <Plus size={18} /> Novo Colaborador
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {employees.length > 0 ? employees.map((emp) => (
                <div key={emp.id} className="bg-white rounded-[2rem] p-6 shadow-sm border border-slate-100 relative group transition-all hover:shadow-xl hover:shadow-slate-200/50">
                  <div className="flex justify-between items-start mb-6">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-slate-100 rounded-2xl flex items-center justify-center text-slate-400 border border-slate-200">
                        <Briefcase size={24} />
                      </div>
                      <div>
                        <h3 className="text-sm font-black text-slate-800 leading-none mb-1">{emp.name || "Vaga Aberta"}</h3>
                        <span className="text-[10px] font-bold text-blue-600 uppercase tracking-widest">{emp.role}</span>
                      </div>
                    </div>
                    <div className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest ${
                      emp.status === 'Ativo' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                      emp.status === 'Férias' ? 'bg-orange-50 text-orange-600 border border-orange-100' :
                      'bg-red-50 text-red-600 border border-red-100'
                    }`}>
                      {emp.status}
                    </div>
                  </div>

                  <div className="space-y-3 mb-6">
                    <div className="flex items-center gap-3 text-slate-500">
                      <MapPin size={14} className="text-slate-300" />
                      <span className="text-[11px] font-bold">Setor: <b className="text-slate-700">{emp.sector}</b></span>
                    </div>
                    <div className="flex items-center gap-3 text-slate-500">
                      <Cpu size={14} className="text-slate-300" />
                      <span className="text-[11px] font-bold">Máquina: <b className="text-slate-700">{emp.machine}</b></span>
                    </div>
                    <div className="flex items-center gap-3 text-slate-500">
                      <Clock size={14} className="text-slate-300" />
                      <span className="text-[11px] font-bold">Turno: <b className="text-slate-700">{emp.shift || emp.group}</b></span>
                    </div>
                  </div>

                  <div className="flex gap-2 pt-4 border-t border-slate-50">
                    <button 
                      onClick={() => { setEditingEmployee(emp); setIsEmployeeModalOpen(true); }}
                      className="flex-1 bg-slate-50 hover:bg-blue-50 text-slate-400 hover:text-blue-600 p-2.5 rounded-xl transition-all flex items-center justify-center gap-2 text-[10px] font-black uppercase"
                    >
                      <Edit2 size={14} /> Editar
                    </button>
                    <button 
                      onClick={() => {
                        if (window.confirm(`Deseja excluir o cadastro de ${emp.name}?`)) {
                          const updated = employees.filter(e => e.id !== emp.id);
                          setEmployees(updated);
                          setOperators(updated.map(e => e.name));
                        }
                      }}
                      className="bg-slate-50 hover:bg-red-50 text-slate-400 hover:text-red-500 p-2.5 rounded-xl transition-all flex items-center justify-center"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                </div>
              )) : (
                <div className="col-span-full py-12 flex flex-col items-center justify-center bg-white rounded-3xl border border-dashed border-slate-300 text-slate-400">
                   <Users2 size={48} className="mb-4 opacity-20" />
                   <p className="text-sm font-black uppercase tracking-widest opacity-40">Nenhum colaborador cadastrado</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      <div className={`fixed inset-0 z-50 transition-all ${isMenuOpen ? 'visible' : 'invisible'}`}>
        <div className={`absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} onClick={() => setIsMenuOpen(false)} />
        <div className={`absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl transition-transform duration-300 transform p-8 flex flex-col gap-8 ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2"><Settings size={22} /> Ajustes</h2>
            <button onClick={() => setIsMenuOpen(false)} className="p-2 text-slate-400"><X size={24} /></button>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nova Meta Mensal (KG)</label>
              <input 
                type="number" 
                value={goalValue} 
                onChange={(e) => setGoalValue(parseFloat(e.target.value) || 0)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-black text-blue-600 outline-none" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Adicionar Operador</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  value={newOpName} 
                  onChange={e => setNewOpName(e.target.value)}
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-4 py-2 text-xs font-bold" 
                />
                <button 
                  onClick={() => { if (newOpName) { handleSaveEmployee({ name: newOpName, status: 'Ativo', role: 'Operador 1', sector: 'Extrusão', machine: 'Cast 1' }); setNewOpName(''); } }}
                  className="bg-blue-600 text-white p-3 rounded-2xl"
                >
                  <Plus size={18} />
                </button>
              </div>
            </div>
            <div className="pt-8 border-t border-slate-100 space-y-3">
              <button onClick={() => {
                const data = { productionData, employees, shifts, goalValue, operators };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'backup_manupackaging.json';
                a.click();
              }} className="w-full flex items-center justify-center gap-3 bg-slate-100 py-4 rounded-2xl text-[10px] font-black uppercase text-slate-600"><Download size={16} /> Exportar Backup</button>

              <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 bg-blue-50 py-4 rounded-2xl text-[10px] font-black uppercase text-blue-600"><Upload size={16} /> Importar Backup</button>

              <button onClick={() => { localStorage.removeItem('manupackaging_session'); setIsAuthenticated(false); }} className="w-full flex items-center justify-center gap-3 bg-red-50 py-4 rounded-2xl text-[10px] font-black uppercase text-red-600"><LogOut size={16} /> Sair do Sistema</button>
            </div>
          </div>
        </div>
      </div>

      <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />

      <LaunchModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingEntry(null); }} 
        onSave={handleSaveEntry} 
        operators={operators} 
        activeMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        availableShifts={shifts} 
        initialData={editingEntry} 
      />

      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
      <EmployeeModal 
        isOpen={isEmployeeModalOpen} 
        onClose={() => { setIsEmployeeModalOpen(false); setEditingEmployee(null); }} 
        onSave={handleSaveEmployee} 
        availableShifts={shifts} 
        availableMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        editingEmployee={editingEmployee}
      />
    </div>
  );
};

export default App;

import { ProductionEntry } from './types';

// Lista de operadores para testes
export const DEFAULT_OPERATORS: string[] = [
  "Adaias Melo",
  "João Silva",
  "Ricardo Souza",
  "Bruno Oliveira",
  "Marcos Santos"
];

// Função auxiliar para gerar dados fake de forma programática para o INITIAL_DATA
const generateFakeData = (): ProductionEntry[] => {
  const data: ProductionEntry[] = [];
  const today = new Date();
  const start = new Date();
  start.setDate(today.getDate() - 1); // Define início como ontem para ter exatamente 2 dias

  const machines = ["Cast 1", "Cast 2", "Erema 1"];
  const shifts = ["Diurno 1", "Noturno 1"];

  let currentDate = new Date(start);

  while (currentDate <= today) {
    const dateStr = currentDate.toISOString().split('T')[0];

    // Simular produção para cada máquina no dia
    machines.forEach(machine => {
      const isMaintenance = Math.random() < 0.1; // 10% de chance de ser dia de manutenção
      const operator = DEFAULT_OPERATORS[Math.floor(Math.random() * DEFAULT_OPERATORS.length)];

      if (isMaintenance) {
        data.push({
          id: Math.random().toString(36).substr(2, 9),
          date: dateStr,
          operator: operator,
          machine: machine,
          shift: shifts[Math.floor(Math.random() * shifts.length)],
          grossWeight: 0,
          tara: 0,
          netWeight: 0,
          volumes: 0,
          tubetes: 0,
          ecoA: 0,
          ecoBP: 0,
          ecoBM: Math.floor(Math.random() * 50),
          borraTotal: 0,
          manutencaoMin: 120 + Math.floor(Math.random() * 240),
          manutencaoMotivo: "Troca de filtro / Limpeza",
          processoMin: 0,
          outrosMin: 0,
          isMaintenanceEntry: true
        });
      } else {
        const gross = 1200 + Math.floor(Math.random() * 800);
        const tara = 100 + Math.floor(Math.random() * 50);
        const net = gross - tara;

        data.push({
          id: Math.random().toString(36).substr(2, 9),
          date: dateStr,
          operator: operator,
          machine: machine,
          shift: shifts[Math.floor(Math.random() * shifts.length)],
          grossWeight: gross,
          tara: tara,
          netWeight: net,
          volumes: Math.floor(net / 25),
          tubetes: Math.floor(net / 50),
          ecoA: Math.floor(Math.random() * 100),
          ecoBP: Math.floor(Math.random() * 80),
          ecoBM: 0,
          borraTotal: 20 + Math.floor(Math.random() * 40),
          manutencaoMin: 0,
          processoMin: Math.floor(Math.random() * 45),
          outrosMin: 0,
          isMaintenanceEntry: false
        });
      }
    });

    currentDate.setDate(currentDate.getDate() + 1);
  }

  return data.reverse(); // Mais recentes primeiro
};

// Histórico de produção com dados gerados para teste (últimos 2 dias)
export const INITIAL_DATA: ProductionEntry[] = generateFakeData();

// Meta mensal inicial (60 Toneladas)
export const GOAL_VALUE = 60000;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, Settings, BarChart3, FileText, Users2, Search, 
  Printer, ShieldCheck, Download, Upload, Trash2, Cpu, 
  Clock, Save, X, Edit2, LogOut, Briefcase, MapPin, Activity
} from 'lucide-react';
import { 
  Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { ProductionEntry, Shift } from './types';
import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';
import EmployeeModal from './components/EmployeeModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.1;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports' | 'personnel'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'year' | 'day' | 'week' | 'all'>('all');

  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    const saved = localStorage.getItem('manupackaging_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [employees, setEmployees] = useState<any[]>(() => {
    const saved = localStorage.getItem('manupackaging_employees');
    return saved ? JSON.parse(saved) : [];
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [isEmployeeModalOpen, setIsEmployeeModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [editingEmployee, setEditingEmployee] = useState<any | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_employees', JSON.stringify(employees)); }, [employees]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  const handleSaveEmployee = (empData: any) => {
    let updatedEmployees;
    if (empData.id) {
      updatedEmployees = employees.map(e => e.id === empData.id ? empData : e);
    } else {
      updatedEmployees = [...employees, { ...empData, id: Math.random().toString(36).substr(2, 9) }];
    }
    setEmployees(updatedEmployees);

    // Sincroniza operadores (apenas ativos ou em férias, omitindo vagas abertas na lista de lançamento se desejar)
    const activeNames = updatedEmployees
      .filter(e => e.status !== 'Vaga Aberta')
      .map(e => e.name);

    // Mantém operadores que podem ter sido adicionados manualmente mas não estão no RH (se houver)
    const existingManual = operators.filter(op => !employees.find(e => e.name === op));
    setOperators(Array.from(new Set([...activeNames, ...existingManual])));
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.productionData) setProductionData(data.productionData);
        if (data.operators) setOperators(data.operators);
        if (data.goalValue) setGoalValue(data.goalValue);
        if (data.shifts) setShifts(data.shifts);
        if (data.employees) setEmployees(data.employees);
        alert('Dados importados com sucesso!');
      } catch (err) {
        alert('Erro ao importar arquivo.');
      }
    };
    reader.readAsText(file);
  };

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'year') return e.date.startsWith(now.getFullYear().toString());
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const todayStr = new Date().toLocaleDateString('sv-SE');
    const monthPrefix = new Date().toISOString().slice(0, 7);
    return productionData.reduce((acc, e) => {
      acc.month += e.date.startsWith(monthPrefix) ? e.netWeight : 0;
      acc.day += e.date === todayStr ? e.netWeight : 0;
      return acc;
    }, { month: 0, day: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => { setEditingEntry(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-700 text-white font-black px-5 py-2.5 rounded-xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
          >
            <Plus size={16} /> Novo Lançamento
          </button>
          <button onClick={() => setIsMenuOpen(true)} className="p-2.5 text-slate-400 hover:bg-slate-100 rounded-xl transition-all">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto px-4 mt-6 no-print">
        <div className="bg-slate-200/50 p-1 rounded-2xl inline-flex gap-1 overflow-x-auto no-scrollbar max-w-full">
          {[
            { id: 'dashboard', icon: <BarChart3 size={14} />, label: 'Dashboard' },
            { id: 'reports', icon: <FileText size={14} />, label: 'Relatórios' },
            { id: 'personnel', icon: <Users2 size={14} />, label: 'Operadores' }
          ].map((tab) => (
            <button 
              key={tab.id} 
              onClick={() => { 
                setActiveTab(tab.id as any);
                setSelectedIds([]); 
              }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-4 space-y-6">
        {activeTab === 'dashboard' ? (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 space-y-4">
                <div className="flex justify-between items-end">
                  <div>
                    <span className="text-[10px] uppercase font-black tracking-widest text-slate-400">Meta do Mês</span>
                    <div className="text-3xl font-black text-slate-800">{(totals.month / 1000).toFixed(1)} T</div>
                  </div>
                  <div className="text-right">
                    <div className="text-2xl font-black text-blue-600">{goalValue > 0 ? Math.round((totals.month / goalValue) * 100) : 0}%</div>
                    <span className="text-[10px] font-bold text-slate-300">de {(goalValue/1000).toFixed(0)} T</span>
                  </div>
                </div>
                <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
                  <div className="h-full bg-blue-600 rounded-full transition-all duration-1000" style={{ width: `${Math.min((totals.month / (goalValue || 1)) * 100, 100)}%` }}></div>
                </div>
              </div>

              <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex items-center justify-between">
                <div>
                  <span className="text-[10px] uppercase font-black tracking-widest text-emerald-500">Produção Hoje</span>
                  <div className="text-3xl font-black text-slate-800">{formatWeight(totals.day)}</div>
                </div>
                <div className="w-12 h-12 bg-emerald-50 rounded-2xl flex items-center justify-center text-emerald-600">
                  <Cpu size={24} />
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes },
                { title: '📊 Prod vs Reciclagem', key: 'prod', color: COLORS, formatter: formatWeight }
              ].map((chart, idx) => {
                const chartData = stats.filter(s => s[chart.key as keyof OperatorStat] > 0);
                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-[400px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
                    <div className="flex-1">
                      {chartData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                          <PieChart>
                            <Pie 
                              data={chartData} 
                              cx="50%" 
                              cy="50%" 
                              innerRadius={60} 
                              outerRadius={85} 
                              dataKey={chart.key} 
                              nameKey="name" 
                              label={renderCustomizedLabel}
                              paddingAngle={2}
                            >
                              {chartData.map((_, i) => <Cell key={i} fill={chart.color[i % chart.color.length]} stroke="none" />)}
                            </Pie>
                            <Tooltip formatter={(val: any) => chart.formatter(val)} />
                            <Legend iconType="circle" />
                          </PieChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="h-full flex items-center justify-center text-slate-300 font-bold text-xs uppercase">Sem dados</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : activeTab === 'reports' ? (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between gap-4">
              <div className="relative flex-1 max-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Pesquisar registros..." 
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none" 
                />
              </div>
              <div className="flex items-center gap-2 no-print">
                {selectedIds.length > 0 && (
                  <button 
                    onClick={() => {
                      const count = selectedIds.length;
                      if (window.confirm(`Confirma a exclusão de ${count} registros selecionados?`)) {
                        const idsToRemove = new Set(selectedIds);
                        setProductionData(prev => prev.filter(item => !idsToRemove.has(item.id)));
                        setSelectedIds([]);
                      }
                    }} 
                    className="flex items-center gap-2 px-4 py-2.5 bg-red-50 text-red-600 rounded-xl text-[10px] font-black uppercase hover:bg-red-100 transition-all animate-in fade-in"
                  >
                    <Trash2 size={16} /> Excluir ({selectedIds.length})
                  </button>
                )}
                <button onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[600px]">
                <thead>
                  <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4 w-10 no-print">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                        checked={selectedIds.length > 0 && selectedIds.length === productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).length}
                        onChange={(ev) => {
                          if (ev.target.checked) {
                            const filteredIds = productionData.filter(item => item.operator.toLowerCase().includes(searchTerm.toLowerCase())).map(item => item.id);
                            setSelectedIds(filteredIds);
                          } else {
                            setSelectedIds([]);
                          }
                        }}
                      />
                    </th>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Operador</th>
                    <th className="px-6 py-4">Líquido</th>
                    <th className="px-6 py-4">Eco A</th>
                    <th className="px-6 py-4">Borra</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-xs font-bold">
                  {productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).map((e) => (
                    <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/50' : ''}`}>
                      <td className="px-6 py-4 w-10 no-print">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                          checked={selectedIds.includes(e.id)}
                          onChange={() => {
                            setSelectedIds(prev => prev.includes(e.id) ? prev.filter(id => id !== e.id) : [...prev, e.id]);
                          }}
                        />
                      </td>
                      <td className="px-6 py-4">{e.date}</td>
                      <td className="px-6 py-4">{e.operator}</td>
                      <td className="px-6 py-4">{e.netWeight} kg</td>
                      <td className="px-6 py-4 text-emerald-600">{e.ecoA} kg</td>
                      <td className="px-6 py-4 text-red-500">{e.borraTotal} kg</td>
                      <td className="px-6 py-4 text-right space-x-2">
                        <button onClick={() => { setEditingEntry(e); setIsModalOpen(true); }} className="text-blue-500 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={14} /></button>
                        <button onClick={() => {
                          if (window.confirm('Deseja excluir este registro?')) {
                            setProductionData(prev => prev.filter(x => x.id !== e.id));
                            setSelectedIds(prev => prev.filter(id => id !== e.id));
                          }
                        }} className="text-red-400 p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex items-center justify-between bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
              <div>
                <h2 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Equipe de Operação</h2>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Gestão de Colaboradores e Escalas</p>
              </div>
              <button 
                onClick={() => { setEditingEmployee(null); setIsEmployeeModalOpen(true); }}
                className="bg-blue-600 hover:bg-blue-700 text-white font-black px-6 py-3 rounded-2xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
              >
                <Plus size={18} /> Novo Colaborador
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {employees.length > 0 ? employees.map((emp) => (
                <div key={emp.id} className="bg-white rounded-[2rem] p-6 shadow-sm border border-slate-100 relative group transition-all hover:shadow-xl hover:shadow-slate-200/50">
                  <div className="flex justify-between items-start mb-6">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-slate-100 rounded-2xl flex items-center justify-center text-slate-400 border border-slate-200">
                        <Briefcase size={24} />
                      </div>
                      <div>
                        <h3 className="text-sm font-black text-slate-800 leading-none mb-1">{emp.name || "Vaga Aberta"}</h3>
                        <span className="text-[10px] font-bold text-blue-600 uppercase tracking-widest">{emp.role}</span>
                      </div>
                    </div>
                    <div className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest ${
                      emp.status === 'Ativo' ? 'bg-emerald-50 text-emerald-600 border border-emerald-100' :
                      emp.status === 'Férias' ? 'bg-orange-50 text-orange-600 border border-orange-100' :
                      'bg-red-50 text-red-600 border border-red-100'
                    }`}>
                      {emp.status}
                    </div>
                  </div>

                  <div className="space-y-3 mb-6">
                    <div className="flex items-center gap-3 text-slate-500">
                      <MapPin size={14} className="text-slate-300" />
                      <span className="text-[11px] font-bold">Setor: <b className="text-slate-700">{emp.sector}</b></span>
                    </div>
                    <div className="flex items-center gap-3 text-slate-500">
                      <Cpu size={14} className="text-slate-300" />
                      <span className="text-[11px] font-bold">Máquina: <b className="text-slate-700">{emp.machine}</b></span>
                    </div>
                    <div className="flex items-center gap-3 text-slate-500">
                      <Clock size={14} className="text-slate-300" />
                      <span className="text-[11px] font-bold">Turno: <b className="text-slate-700">{emp.shift || emp.group}</b></span>
                    </div>
                  </div>

                  <div className="flex gap-2 pt-4 border-t border-slate-50">
                    <button 
                      onClick={() => { setEditingEmployee(emp); setIsEmployeeModalOpen(true); }}
                      className="flex-1 bg-slate-50 hover:bg-blue-50 text-slate-400 hover:text-blue-600 p-2.5 rounded-xl transition-all flex items-center justify-center gap-2 text-[10px] font-black uppercase"
                    >
                      <Edit2 size={14} /> Editar
                    </button>
                    <button 
                      onClick={() => {
                        if (window.confirm(`Deseja excluir o cadastro de ${emp.name}?`)) {
                          const updated = employees.filter(e => e.id !== emp.id);
                          setEmployees(updated);
                          setOperators(updated.map(e => e.name));
                        }
                      }}
                      className="bg-slate-50 hover:bg-red-50 text-slate-400 hover:text-red-500 p-2.5 rounded-xl transition-all flex items-center justify-center"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                </div>
              )) : (
                <div className="col-span-full py-12 flex flex-col items-center justify-center bg-white rounded-3xl border border-dashed border-slate-300 text-slate-400">
                   <Users2 size={48} className="mb-4 opacity-20" />
                   <p className="text-sm font-black uppercase tracking-widest opacity-40">Nenhum colaborador cadastrado</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      <div className={`fixed inset-0 z-50 transition-all ${isMenuOpen ? 'visible' : 'invisible'}`}>
        <div className={`absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} onClick={() => setIsMenuOpen(false)} />
        <div className={`absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl transition-transform duration-300 transform p-8 flex flex-col gap-8 ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2"><Settings size={22} /> Ajustes</h2>
            <button onClick={() => setIsMenuOpen(false)} className="p-2 text-slate-400"><X size={24} /></button>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nova Meta Mensal (KG)</label>
              <input 
                type="number" 
                value={goalValue} 
                onChange={(e) => setGoalValue(parseFloat(e.target.value) || 0)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-black text-blue-600 outline-none" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Adicionar Operador</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  value={newOpName} 
                  onChange={e => setNewOpName(e.target.value)}
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-4 py-2 text-xs font-bold" 
                />
                <button 
                  onClick={() => { if (newOpName) { handleSaveEmployee({ name: newOpName, status: 'Ativo', role: 'Operador 1', sector: 'Extrusão', machine: 'Cast 1' }); setNewOpName(''); } }}
                  className="bg-blue-600 text-white p-3 rounded-2xl"
                >
                  <Plus size={18} />
                </button>
              </div>
            </div>
            <div className="pt-8 border-t border-slate-100 space-y-3">
              <button onClick={() => {
                const data = { productionData, employees, shifts, goalValue, operators };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'backup_manupackaging.json';
                a.click();
              }} className="w-full flex items-center justify-center gap-3 bg-slate-100 py-4 rounded-2xl text-[10px] font-black uppercase text-slate-600"><Download size={16} /> Exportar Backup</button>

              <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 bg-blue-50 py-4 rounded-2xl text-[10px] font-black uppercase text-blue-600"><Upload size={16} /> Importar Backup</button>

              <button onClick={() => { localStorage.removeItem('manupackaging_session'); setIsAuthenticated(false); }} className="w-full flex items-center justify-center gap-3 bg-red-50 py-4 rounded-2xl text-[10px] font-black uppercase text-red-600"><LogOut size={16} /> Sair do Sistema</button>
            </div>
          </div>
        </div>
      </div>

      <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />

      <LaunchModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingEntry(null); }} 
        onSave={handleSaveEntry} 
        operators={operators} 
        activeMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        availableShifts={shifts} 
        initialData={editingEntry} 
      />

      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
      <EmployeeModal 
        isOpen={isEmployeeModalOpen} 
        onClose={() => { setIsEmployeeModalOpen(false); setEditingEmployee(null); }} 
        onSave={handleSaveEmployee} 
        availableShifts={shifts} 
        availableMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        editingEmployee={editingEmployee}
      />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, Settings, BarChart3, FileText, Search, 
  Printer, ShieldCheck, Download, Upload, Trash2, Cpu, 
  Save, X, Edit2, LogOut
} from 'lucide-react';
import { 
  Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { ProductionEntry, Shift } from './types';
import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.1;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'year' | 'day' | 'week' | 'all'>('all');

  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    const saved = localStorage.getItem('manupackaging_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.productionData) setProductionData(data.productionData);
        if (data.operators) setOperators(data.operators);
        if (data.goalValue) setGoalValue(data.goalValue);
        if (data.shifts) setShifts(data.shifts);
        alert('Dados importados com sucesso!');
      } catch (err) {
        alert('Erro ao importar arquivo.');
      }
    };
    reader.readAsText(file);
  };

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'year') return e.date.startsWith(now.getFullYear().toString());
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const todayStr = new Date().toLocaleDateString('sv-SE');
    const monthPrefix = new Date().toISOString().slice(0, 7);
    return productionData.reduce((acc, e) => {
      acc.month += e.date.startsWith(monthPrefix) ? e.netWeight : 0;
      acc.day += e.date === todayStr ? e.netWeight : 0;
      return acc;
    }, { month: 0, day: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => { setEditingEntry(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-700 text-white font-black px-5 py-2.5 rounded-xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
          >
            <Plus size={16} /> Novo Lançamento
          </button>
          <button onClick={() => setIsMenuOpen(true)} className="p-2.5 text-slate-400 hover:bg-slate-100 rounded-xl transition-all">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto px-4 mt-6 no-print">
        <div className="bg-slate-200/50 p-1 rounded-2xl inline-flex gap-1 overflow-x-auto no-scrollbar max-w-full">
          {[
            { id: 'dashboard', icon: <BarChart3 size={14} />, label: 'Dashboard' },
            { id: 'reports', icon: <FileText size={14} />, label: 'Relatórios' }
          ].map((tab) => (
            <button 
              key={tab.id} 
              onClick={() => { 
                setActiveTab(tab.id as any);
                setSelectedIds([]); 
              }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-4 space-y-6">
        {activeTab === 'dashboard' ? (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 space-y-4">
                <div className="flex justify-between items-end">
                  <div>
                    <span className="text-[10px] uppercase font-black tracking-widest text-slate-400">Meta do Mês</span>
                    <div className="text-3xl font-black text-slate-800">{(totals.month / 1000).toFixed(1)} T</div>
                  </div>
                  <div className="text-right">
                    <div className="text-2xl font-black text-blue-600">{goalValue > 0 ? Math.round((totals.month / goalValue) * 100) : 0}%</div>
                    <span className="text-[10px] font-bold text-slate-300">de {(goalValue/1000).toFixed(0)} T</span>
                  </div>
                </div>
                <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
                  <div className="h-full bg-blue-600 rounded-full transition-all duration-1000" style={{ width: `${Math.min((totals.month / (goalValue || 1)) * 100, 100)}%` }}></div>
                </div>
              </div>

              <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex items-center justify-between">
                <div>
                  <span className="text-[10px] uppercase font-black tracking-widest text-emerald-500">Produção Hoje</span>
                  <div className="text-3xl font-black text-slate-800">{formatWeight(totals.day)}</div>
                </div>
                <div className="w-12 h-12 bg-emerald-50 rounded-2xl flex items-center justify-center text-emerald-600">
                  <Cpu size={24} />
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes },
                { title: '📊 Prod vs Reciclagem', key: 'prod', color: COLORS, formatter: formatWeight }
              ].map((chart, idx) => {
                const chartData = stats.filter(s => s[chart.key as keyof OperatorStat] > 0);
                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-[400px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
                    <div className="flex-1">
                      {chartData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                          <PieChart>
                            <Pie 
                              data={chartData} 
                              cx="50%" 
                              cy="50%" 
                              innerRadius={60} 
                              outerRadius={85} 
                              dataKey={chart.key} 
                              nameKey="name" 
                              label={renderCustomizedLabel}
                              paddingAngle={2}
                            >
                              {chartData.map((_, i) => <Cell key={i} fill={chart.color[i % chart.color.length]} stroke="none" />)}
                            </Pie>
                            <Tooltip formatter={(val: any) => chart.formatter(val)} />
                            <Legend iconType="circle" />
                          </PieChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="h-full flex items-center justify-center text-slate-300 font-bold text-xs uppercase">Sem dados</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between gap-4">
              <div className="relative flex-1 max-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Pesquisar registros..." 
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none" 
                />
              </div>
              <div className="flex items-center gap-2 no-print">
                {selectedIds.length > 0 && (
                  <button 
                    onClick={() => {
                      const count = selectedIds.length;
                      if (window.confirm(`Confirma a exclusão de ${count} registros selecionados?`)) {
                        const idsToRemove = new Set(selectedIds);
                        setProductionData(prev => prev.filter(item => !idsToRemove.has(item.id)));
                        setSelectedIds([]);
                      }
                    }} 
                    className="flex items-center gap-2 px-4 py-2.5 bg-red-50 text-red-600 rounded-xl text-[10px] font-black uppercase hover:bg-red-100 transition-all animate-in fade-in"
                  >
                    <Trash2 size={16} /> Excluir ({selectedIds.length})
                  </button>
                )}
                <button onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[600px]">
                <thead>
                  <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4 w-10 no-print">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                        checked={selectedIds.length > 0 && selectedIds.length === productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).length}
                        onChange={(ev) => {
                          if (ev.target.checked) {
                            const filteredIds = productionData.filter(item => item.operator.toLowerCase().includes(searchTerm.toLowerCase())).map(item => item.id);
                            setSelectedIds(filteredIds);
                          } else {
                            setSelectedIds([]);
                          }
                        }}
                      />
                    </th>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Operador</th>
                    <th className="px-6 py-4">Líquido</th>
                    <th className="px-6 py-4">Eco A</th>
                    <th className="px-6 py-4">Borra</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-xs font-bold">
                  {productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).map((e) => (
                    <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/50' : ''}`}>
                      <td className="px-6 py-4 w-10 no-print">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                          checked={selectedIds.includes(e.id)}
                          onChange={() => {
                            setSelectedIds(prev => prev.includes(e.id) ? prev.filter(id => id !== e.id) : [...prev, e.id]);
                          }}
                        />
                      </td>
                      <td className="px-6 py-4">{e.date}</td>
                      <td className="px-6 py-4">{e.operator}</td>
                      <td className="px-6 py-4">{e.netWeight} kg</td>
                      <td className="px-6 py-4 text-emerald-600">{e.ecoA} kg</td>
                      <td className="px-6 py-4 text-red-500">{e.borraTotal} kg</td>
                      <td className="px-6 py-4 text-right space-x-2">
                        <button onClick={() => { setEditingEntry(e); setIsModalOpen(true); }} className="text-blue-500 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={14} /></button>
                        <button onClick={() => {
                          if (window.confirm('Deseja excluir este registro?')) {
                            setProductionData(prev => prev.filter(x => x.id !== e.id));
                            setSelectedIds(prev => prev.filter(id => id !== e.id));
                          }
                        }} className="text-red-400 p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      <div className={`fixed inset-0 z-50 transition-all ${isMenuOpen ? 'visible' : 'invisible'}`}>
        <div className={`absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} onClick={() => setIsMenuOpen(false)} />
        <div className={`absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl transition-transform duration-300 transform p-8 flex flex-col gap-8 ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2"><Settings size={22} /> Ajustes</h2>
            <button onClick={() => setIsMenuOpen(false)} className="p-2 text-slate-400"><X size={24} /></button>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nova Meta Mensal (KG)</label>
              <input 
                type="number" 
                value={goalValue} 
                onChange={(e) => setGoalValue(parseFloat(e.target.value) || 0)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-black text-blue-600 outline-none" 
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Adicionar Operador</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  value={newOpName} 
                  onChange={e => setNewOpName(e.target.value)}
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-4 py-2 text-xs font-bold" 
                />
                <button 
                  onClick={() => { if (newOpName && !operators.includes(newOpName)) { setOperators(prev => [...prev, newOpName]); setNewOpName(''); } }}
                  className="bg-blue-600 text-white p-3 rounded-2xl"
                >
                  <Plus size={18} />
                </button>
              </div>
            </div>
            <div className="pt-8 border-t border-slate-100 space-y-3">
              <button onClick={() => {
                const data = { productionData, shifts, goalValue, operators };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'backup_manupackaging.json';
                a.click();
              }} className="w-full flex items-center justify-center gap-3 bg-slate-100 py-4 rounded-2xl text-[10px] font-black uppercase text-slate-600"><Download size={16} /> Exportar Backup</button>

              <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 bg-blue-50 py-4 rounded-2xl text-[10px] font-black uppercase text-blue-600"><Upload size={16} /> Importar Backup</button>

              <button onClick={() => { localStorage.removeItem('manupackaging_session'); setIsAuthenticated(false); }} className="w-full flex items-center justify-center gap-3 bg-red-50 py-4 rounded-2xl text-[10px] font-black uppercase text-red-600"><LogOut size={16} /> Sair do Sistema</button>
            </div>
          </div>
        </div>
      </div>

      <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />

      <LaunchModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingEntry(null); }} 
        onSave={handleSaveEntry} 
        operators={operators} 
        activeMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        availableShifts={shifts} 
        initialData={editingEntry} 
      />

      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, Settings, BarChart3, FileText, Search, 
  Printer, ShieldCheck, Download, Upload, Trash2, Cpu, 
  Save, X, Edit2, LogOut
} from 'lucide-react';
import { 
  Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { ProductionEntry, Shift } from './types';
import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.1;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'year' | 'day' | 'week' | 'all'>('all');

  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    const saved = localStorage.getItem('manupackaging_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.productionData) setProductionData(data.productionData);
        if (data.operators) setOperators(data.operators);
        if (data.goalValue) setGoalValue(data.goalValue);
        if (data.shifts) setShifts(data.shifts);
        alert('Dados importados com sucesso!');
      } catch (err) {
        alert('Erro ao importar arquivo.');
      }
    };
    reader.readAsText(file);
  };

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'year') return e.date.startsWith(now.getFullYear().toString());
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const todayStr = new Date().toLocaleDateString('sv-SE');
    const monthPrefix = new Date().toISOString().slice(0, 7);
    return productionData.reduce((acc, e) => {
      acc.month += e.date.startsWith(monthPrefix) ? e.netWeight : 0;
      acc.day += e.date === todayStr ? e.netWeight : 0;
      return acc;
    }, { month: 0, day: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => { setEditingEntry(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-700 text-white font-black px-5 py-2.5 rounded-xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
          >
            <Plus size={16} /> Novo Lançamento
          </button>
          <button onClick={() => setIsMenuOpen(true)} className="p-2.5 text-slate-400 hover:bg-slate-100 rounded-xl transition-all">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto px-4 mt-6 no-print">
        <div className="bg-slate-200/50 p-1 rounded-2xl inline-flex gap-1 overflow-x-auto no-scrollbar max-w-full">
          {[
            { id: 'dashboard', icon: <BarChart3 size={14} />, label: 'Dashboard' },
            { id: 'reports', icon: <FileText size={14} />, label: 'Relatórios' }
          ].map((tab) => (
            <button 
              key={tab.id} 
              onClick={() => { 
                setActiveTab(tab.id as any);
                setSelectedIds([]); 
              }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-4 space-y-6">
        {activeTab === 'dashboard' ? (
          <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 space-y-4">
                <div className="flex justify-between items-end">
                  <div>
                    <span className="text-[10px] uppercase font-black tracking-widest text-slate-400">Meta do Mês</span>
                    <div className="text-3xl font-black text-slate-800">{(totals.month / 1000).toFixed(1)} T</div>
                  </div>
                  <div className="text-right">
                    <div className="text-2xl font-black text-blue-600">{goalValue > 0 ? Math.round((totals.month / goalValue) * 100) : 0}%</div>
                    <span className="text-[10px] font-bold text-slate-300">de {(goalValue/1000).toFixed(0)} T</span>
                  </div>
                </div>
                <div className="w-full bg-slate-100 h-3 rounded-full overflow-hidden">
                  <div className="h-full bg-blue-600 rounded-full transition-all duration-1000" style={{ width: `${Math.min((totals.month / (goalValue || 1)) * 100, 100)}%` }}></div>
                </div>
              </div>

              <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex items-center justify-between">
                <div>
                  <span className="text-[10px] uppercase font-black tracking-widest text-emerald-500">Produção Hoje</span>
                  <div className="text-3xl font-black text-slate-800">{formatWeight(totals.day)}</div>
                </div>
                <div className="w-12 h-12 bg-emerald-50 rounded-2xl flex items-center justify-center text-emerald-600">
                  <Cpu size={24} />
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes },
                { title: '📊 Prod vs Reciclagem', key: 'prod', color: COLORS, formatter: formatWeight }
              ].map((chart, idx) => {
                const chartData = stats.filter(s => s[chart.key as keyof OperatorStat] > 0);
                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-[400px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
                    <div className="flex-1">
                      {chartData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                          <PieChart>
                            <Pie 
                              data={chartData} 
                              cx="50%" 
                              cy="50%" 
                              innerRadius={60} 
                              outerRadius={85} 
                              dataKey={chart.key} 
                              nameKey="name" 
                              label={renderCustomizedLabel}
                              paddingAngle={2}
                            >
                              {chartData.map((_, i) => <Cell key={i} fill={chart.color[i % chart.color.length]} stroke="none" />)}
                            </Pie>
                            <Tooltip formatter={(val: any) => chart.formatter(val)} />
                            <Legend iconType="circle" />
                          </PieChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="h-full flex items-center justify-center text-slate-300 font-bold text-xs uppercase">Sem dados</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between gap-4">
              <div className="relative flex-1 max-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Pesquisar registros..." 
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none" 
                />
              </div>
              <div className="flex items-center gap-2 no-print">
                {selectedIds.length > 0 && (
                  <button 
                    onClick={() => {
                      const count = selectedIds.length;
                      if (window.confirm(`Confirma a exclusão de ${count} registros selecionados?`)) {
                        const idsToRemove = new Set(selectedIds);
                        setProductionData(prev => prev.filter(item => !idsToRemove.has(item.id)));
                        setSelectedIds([]);
                      }
                    }} 
                    className="flex items-center gap-2 px-4 py-2.5 bg-red-50 text-red-600 rounded-xl text-[10px] font-black uppercase hover:bg-red-100 transition-all animate-in fade-in"
                  >
                    <Trash2 size={16} /> Excluir ({selectedIds.length})
                  </button>
                )}
                <button onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[600px]">
                <thead>
                  <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4 w-10 no-print">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                        checked={selectedIds.length > 0 && selectedIds.length === productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).length}
                        onChange={(ev) => {
                          if (ev.target.checked) {
                            const filteredIds = productionData.filter(item => item.operator.toLowerCase().includes(searchTerm.toLowerCase())).map(item => item.id);
                            setSelectedIds(filteredIds);
                          } else {
                            setSelectedIds([]);
                          }
                        }}
                      />
                    </th>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Operador</th>
                    <th className="px-6 py-4">Líquido</th>
                    <th className="px-6 py-4">Eco A</th>
                    <th className="px-6 py-4">Borra</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-xs font-bold">
                  {productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).map((e) => (
                    <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/50' : ''}`}>
                      <td className="px-6 py-4 w-10 no-print">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                          checked={selectedIds.includes(e.id)}
                          onChange={() => {
                            setSelectedIds(prev => prev.includes(e.id) ? prev.filter(id => id !== e.id) : [...prev, e.id]);
                          }}
                        />
                      </td>
                      <td className="px-6 py-4">{e.date}</td>
                      <td className="px-6 py-4">{e.operator}</td>
                      <td className="px-6 py-4">{e.netWeight} kg</td>
                      <td className="px-6 py-4 text-emerald-600">{e.ecoA} kg</td>
                      <td className="px-6 py-4 text-red-500">{e.borraTotal} kg</td>
                      <td className="px-6 py-4 text-right space-x-2">
                        <button onClick={() => { setEditingEntry(e); setIsModalOpen(true); }} className="text-blue-500 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={14} /></button>
                        <button onClick={() => {
                          if (window.confirm('Deseja excluir este registro?')) {
                            setProductionData(prev => prev.filter(x => x.id !== e.id));
                            setSelectedIds(prev => prev.filter(id => id !== e.id));
                          }
                        }} className="text-red-400 p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      <div className={`fixed inset-0 z-50 transition-all ${isMenuOpen ? 'visible' : 'invisible'}`}>
        <div className={`absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} onClick={() => setIsMenuOpen(false)} />
        <div className={`absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl transition-transform duration-300 transform p-8 flex flex-col gap-8 ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2"><Settings size={22} /> Ajustes</h2>
            <button onClick={() => setIsMenuOpen(false)} className="p-2 text-slate-400"><X size={24} /></button>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nova Meta Mensal (KG)</label>
              <input 
                type="number" 
                value={goalValue} 
                onChange={(e) => setGoalValue(parseFloat(e.target.value) || 0)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-black text-blue-600 outline-none" 
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Gerenciar Operadores</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  value={newOpName} 
                  onChange={e => setNewOpName(e.target.value)}
                  placeholder="Novo operador..."
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-4 py-2 text-xs font-bold" 
                />
                <button 
                  onClick={() => { if (newOpName && !operators.includes(newOpName)) { setOperators(prev => [...prev, newOpName]); setNewOpName(''); } }}
                  className="bg-blue-600 text-white p-3 rounded-2xl"
                >
                  <Plus size={18} />
                </button>
              </div>

              <div className="mt-2 max-h-48 overflow-y-auto custom-scrollbar space-y-2 pr-1">
                {operators.map((op, idx) => (
                  <div key={idx} className="flex items-center justify-between bg-slate-50 p-3 rounded-xl border border-slate-100 hover:border-blue-100 transition-colors group">
                    <span className="text-xs font-bold text-slate-600">{op}</span>
                    <button 
                      onClick={() => setOperators(prev => prev.filter(o => o !== op))}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                      title="Remover operador"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                ))}
                {operators.length === 0 && (
                  <p className="text-[10px] text-slate-400 text-center py-2">Nenhum operador cadastrado</p>
                )}
              </div>
            </div>

            <div className="pt-8 border-t border-slate-100 space-y-3">
              <button onClick={() => {
                const data = { productionData, shifts, goalValue, operators };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'backup_manupackaging.json';
                a.click();
              }} className="w-full flex items-center justify-center gap-3 bg-slate-100 py-4 rounded-2xl text-[10px] font-black uppercase text-slate-600"><Download size={16} /> Exportar Backup</button>

              <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 bg-blue-50 py-4 rounded-2xl text-[10px] font-black uppercase text-blue-600"><Upload size={16} /> Importar Backup</button>

              <button onClick={() => { localStorage.removeItem('manupackaging_session'); setIsAuthenticated(false); }} className="w-full flex items-center justify-center gap-3 bg-red-50 py-4 rounded-2xl text-[10px] font-black uppercase text-red-600"><LogOut size={16} /> Sair do Sistema</button>
            </div>
          </div>
        </div>
      </div>

      <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />

      <LaunchModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingEntry(null); }} 
        onSave={handleSaveEntry} 
        operators={operators} 
        activeMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        availableShifts={shifts} 
        initialData={editingEntry} 
      />

      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, Settings, BarChart3, FileText, Search, 
  Printer, ShieldCheck, Download, Upload, Trash2, Cpu, 
  Save, X, Edit2, LogOut, Calendar, CalendarDays, TrendingUp
} from 'lucide-react';
import { 
  Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { ProductionEntry, Shift } from './types';
import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.1;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'month' | 'day' | 'week'>('month');

  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    const saved = localStorage.getItem('manupackaging_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.productionData) setProductionData(data.productionData);
        if (data.operators) setOperators(data.operators);
        if (data.goalValue) setGoalValue(data.goalValue);
        if (data.shifts) setShifts(data.shifts);
        alert('Dados importados com sucesso!');
      } catch (err) {
        alert('Erro ao importar arquivo.');
      }
    };
    reader.readAsText(file);
  };

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  // Filter logic based on the clickable cards
  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    const currentMonthStr = dayStr.substring(0, 7);

    // Logic for Week: From Sunday to Today
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay()); 

    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'month') return e.date.startsWith(currentMonthStr);
      if (selectedTimeframe === 'week') {
        const entryDate = new Date(e.date + 'T00:00:00');
        return entryDate >= startOfWeek;
      }
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const now = new Date();
    const todayStr = now.toLocaleDateString('sv-SE');
    const monthPrefix = now.toISOString().slice(0, 7);

    // Week start (Sunday)
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay());

    return productionData.reduce((acc, e) => {
      // Monthly Total
      if (e.date.startsWith(monthPrefix)) {
        acc.month += e.netWeight;
      }
      // Daily Total
      if (e.date === todayStr) {
        acc.day += e.netWeight;
      }
      // Weekly Total
      const entryDate = new Date(e.date + 'T00:00:00');
      if (entryDate >= startOfWeek) {
        acc.week += e.netWeight;
      }
      return acc;
    }, { month: 0, day: 0, week: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => { setEditingEntry(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-700 text-white font-black px-5 py-2.5 rounded-xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
          >
            <Plus size={16} /> Novo Lançamento
          </button>
          <button onClick={() => setIsMenuOpen(true)} className="p-2.5 text-slate-400 hover:bg-slate-100 rounded-xl transition-all">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto px-4 mt-6 no-print">
        <div className="bg-slate-200/50 p-1 rounded-2xl inline-flex gap-1 overflow-x-auto no-scrollbar max-w-full">
          {[
            { id: 'dashboard', icon: <BarChart3 size={14} />, label: 'Dashboard' },
            { id: 'reports', icon: <FileText size={14} />, label: 'Relatórios' }
          ].map((tab) => (
            <button 
              key={tab.id} 
              onClick={() => { 
                setActiveTab(tab.id as any);
                setSelectedIds([]); 
              }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-4 space-y-6">
        {activeTab === 'dashboard' ? (
          <div className="space-y-6">
            {/* Top Cards Section - Interativos */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              {/* Card Meta - Reseta para Visão Geral (Mês) */}
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all relative overflow-hidden group ${selectedTimeframe === 'month' ? 'bg-blue-600 text-white shadow-xl shadow-blue-200 border-blue-500' : 'bg-white text-slate-800 border-slate-100 hover:border-blue-200'}`}
              >
                <div className="flex justify-between items-start mb-4 relative z-10">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'month' ? 'bg-white/20 text-white' : 'bg-blue-50 text-blue-600'}`}>
                    <TrendingUp size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>Meta do Mês</span>
                </div>
                <div className="relative z-10">
                  <div className="text-2xl font-black mb-1">{(totals.month / 1000).toFixed(1)} T</div>
                  <div className="w-full bg-black/10 h-1.5 rounded-full overflow-hidden">
                    <div className={`h-full rounded-full ${selectedTimeframe === 'month' ? 'bg-white' : 'bg-blue-600'}`} style={{ width: `${Math.min((totals.month / (goalValue || 1)) * 100, 100)}%` }}></div>
                  </div>
                  <div className={`text-[9px] font-bold mt-2 ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>
                    {goalValue > 0 ? Math.round((totals.month / goalValue) * 100) : 0}% de {(goalValue/1000).toFixed(0)} T
                  </div>
                </div>
              </button>

              {/* Card Hoje */}
              <button 
                onClick={() => setSelectedTimeframe('day')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'day' ? 'bg-emerald-500 text-white shadow-xl shadow-emerald-200 border-emerald-400' : 'bg-white text-slate-800 border-slate-100 hover:border-emerald-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'day' ? 'bg-white/20 text-white' : 'bg-emerald-50 text-emerald-600'}`}>
                    <Calendar size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Hoje</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.day)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Produção do dia</p>
                </div>
              </button>

              {/* Card Semana */}
              <button 
                onClick={() => setSelectedTimeframe('week')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'week' ? 'bg-violet-500 text-white shadow-xl shadow-violet-200 border-violet-400' : 'bg-white text-slate-800 border-slate-100 hover:border-violet-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'week' ? 'bg-white/20 text-white' : 'bg-violet-50 text-violet-600'}`}>
                    <CalendarDays size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Esta Semana</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.week)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Dom - Sáb</p>
                </div>
              </button>

              {/* Card Mês (Estatística Pura) */}
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'month' ? 'ring-2 ring-blue-500 ring-offset-2' : 'bg-white hover:border-blue-200 border-slate-100'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className="p-2 rounded-xl bg-orange-50 text-orange-600">
                    <BarChart3 size={18} />
                  </div>
                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Este Mês</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1 text-slate-800">{formatWeight(totals.month)}</div>
                  <p className="text-[9px] font-bold text-slate-400">Acumulado mensal</p>
                </div>
              </button>
            </div>

            {/* Header do Gráfico dinâmico */}
            <div className="flex items-center gap-2 px-2">
              <span className="w-2 h-2 rounded-full bg-slate-300"></span>
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                Visualizando dados: <span className="text-blue-600">{
                  selectedTimeframe === 'day' ? 'Hoje' : 
                  selectedTimeframe === 'week' ? 'Esta Semana' : 
                  'Mês Atual'
                }</span>
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes },
                { title: '📊 Prod vs Reciclagem', key: 'prod', color: COLORS, formatter: formatWeight }
              ].map((chart, idx) => {
                const chartData = stats.filter(s => s[chart.key as keyof OperatorStat] > 0);
                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-[400px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
                    <div className="flex-1">
                      {chartData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                          <PieChart>
                            <Pie 
                              data={chartData} 
                              cx="50%" 
                              cy="50%" 
                              innerRadius={60} 
                              outerRadius={85} 
                              dataKey={chart.key} 
                              nameKey="name" 
                              label={renderCustomizedLabel}
                              paddingAngle={2}
                            >
                              {chartData.map((_, i) => <Cell key={i} fill={chart.color[i % chart.color.length]} stroke="none" />)}
                            </Pie>
                            <Tooltip formatter={(val: any) => chart.formatter(val)} />
                            <Legend iconType="circle" />
                          </PieChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="h-full flex items-center justify-center text-slate-300 font-bold text-xs uppercase">Sem dados neste período</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between gap-4">
              <div className="relative flex-1 max-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Pesquisar registros..." 
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none" 
                />
              </div>
              <div className="flex items-center gap-2 no-print">
                {selectedIds.length > 0 && (
                  <button 
                    onClick={() => {
                      const count = selectedIds.length;
                      if (window.confirm(`Confirma a exclusão de ${count} registros selecionados?`)) {
                        const idsToRemove = new Set(selectedIds);
                        setProductionData(prev => prev.filter(item => !idsToRemove.has(item.id)));
                        setSelectedIds([]);
                      }
                    }} 
                    className="flex items-center gap-2 px-4 py-2.5 bg-red-50 text-red-600 rounded-xl text-[10px] font-black uppercase hover:bg-red-100 transition-all animate-in fade-in"
                  >
                    <Trash2 size={16} /> Excluir ({selectedIds.length})
                  </button>
                )}
                <button onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[600px]">
                <thead>
                  <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4 w-10 no-print">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                        checked={selectedIds.length > 0 && selectedIds.length === productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).length}
                        onChange={(ev) => {
                          if (ev.target.checked) {
                            const filteredIds = productionData.filter(item => item.operator.toLowerCase().includes(searchTerm.toLowerCase())).map(item => item.id);
                            setSelectedIds(filteredIds);
                          } else {
                            setSelectedIds([]);
                          }
                        }}
                      />
                    </th>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Operador</th>
                    <th className="px-6 py-4">Líquido</th>
                    <th className="px-6 py-4">Eco A</th>
                    <th className="px-6 py-4">Borra</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-xs font-bold">
                  {productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).map((e) => (
                    <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/50' : ''}`}>
                      <td className="px-6 py-4 w-10 no-print">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                          checked={selectedIds.includes(e.id)}
                          onChange={() => {
                            setSelectedIds(prev => prev.includes(e.id) ? prev.filter(id => id !== e.id) : [...prev, e.id]);
                          }}
                        />
                      </td>
                      <td className="px-6 py-4">{e.date}</td>
                      <td className="px-6 py-4">{e.operator}</td>
                      <td className="px-6 py-4">{e.netWeight} kg</td>
                      <td className="px-6 py-4 text-emerald-600">{e.ecoA} kg</td>
                      <td className="px-6 py-4 text-red-500">{e.borraTotal} kg</td>
                      <td className="px-6 py-4 text-right space-x-2">
                        <button onClick={() => { setEditingEntry(e); setIsModalOpen(true); }} className="text-blue-500 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={14} /></button>
                        <button onClick={() => {
                          if (window.confirm('Deseja excluir este registro?')) {
                            setProductionData(prev => prev.filter(x => x.id !== e.id));
                            setSelectedIds(prev => prev.filter(id => id !== e.id));
                          }
                        }} className="text-red-400 p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      <div className={`fixed inset-0 z-50 transition-all ${isMenuOpen ? 'visible' : 'invisible'}`}>
        <div className={`absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} onClick={() => setIsMenuOpen(false)} />
        <div className={`absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl transition-transform duration-300 transform p-8 flex flex-col gap-8 ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2"><Settings size={22} /> Ajustes</h2>
            <button onClick={() => setIsMenuOpen(false)} className="p-2 text-slate-400"><X size={24} /></button>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nova Meta Mensal (KG)</label>
              <input 
                type="number" 
                value={goalValue} 
                onChange={(e) => setGoalValue(parseFloat(e.target.value) || 0)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-black text-blue-600 outline-none" 
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Gerenciar Operadores</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  value={newOpName} 
                  onChange={e => setNewOpName(e.target.value)}
                  placeholder="Novo operador..."
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-4 py-2 text-xs font-bold" 
                />
                <button 
                  onClick={() => { if (newOpName && !operators.includes(newOpName)) { setOperators(prev => [...prev, newOpName]); setNewOpName(''); } }}
                  className="bg-blue-600 text-white p-3 rounded-2xl"
                >
                  <Plus size={18} />
                </button>
              </div>

              <div className="mt-2 max-h-48 overflow-y-auto custom-scrollbar space-y-2 pr-1">
                {operators.map((op, idx) => (
                  <div key={idx} className="flex items-center justify-between bg-slate-50 p-3 rounded-xl border border-slate-100 hover:border-blue-100 transition-colors group">
                    <span className="text-xs font-bold text-slate-600">{op}</span>
                    <button 
                      onClick={() => setOperators(prev => prev.filter(o => o !== op))}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                      title="Remover operador"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                ))}
                {operators.length === 0 && (
                  <p className="text-[10px] text-slate-400 text-center py-2">Nenhum operador cadastrado</p>
                )}
              </div>
            </div>

            <div className="pt-8 border-t border-slate-100 space-y-3">
              <button onClick={() => {
                const data = { productionData, shifts, goalValue, operators };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'backup_manupackaging.json';
                a.click();
              }} className="w-full flex items-center justify-center gap-3 bg-slate-100 py-4 rounded-2xl text-[10px] font-black uppercase text-slate-600"><Download size={16} /> Exportar Backup</button>

              <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 bg-blue-50 py-4 rounded-2xl text-[10px] font-black uppercase text-blue-600"><Upload size={16} /> Importar Backup</button>

              <button onClick={() => { localStorage.removeItem('manupackaging_session'); setIsAuthenticated(false); }} className="w-full flex items-center justify-center gap-3 bg-red-50 py-4 rounded-2xl text-[10px] font-black uppercase text-red-600"><LogOut size={16} /> Sair do Sistema</button>
            </div>
          </div>
        </div>
      </div>

      <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />

      <LaunchModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingEntry(null); }} 
        onSave={handleSaveEntry} 
        operators={operators} 
        activeMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        availableShifts={shifts} 
        initialData={editingEntry} 
      />

      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, Settings, BarChart3, FileText, Search, 
  Printer, ShieldCheck, Download, Upload, Trash2, Cpu, 
  Save, X, Edit2, LogOut, Calendar, CalendarDays, TrendingUp
} from 'lucide-react';
import { 
  Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { ProductionEntry, Shift } from './types';
import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.1;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'month' | 'day' | 'week'>('month');

  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    const saved = localStorage.getItem('manupackaging_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);

        // 1. Importar dados de produção
        if (data.productionData && Array.isArray(data.productionData)) {
          setProductionData(data.productionData);
        }

        // 2. Importar Metas e Turnos
        if (data.goalValue) setGoalValue(Number(data.goalValue));
        if (data.shifts && Array.isArray(data.shifts)) setShifts(data.shifts);

        // 3. Lógica inteligente para Operadores
        let importedOperators: string[] = [];

        // Caso A: Backup novo (lista simples de strings)
        if (data.operators && Array.isArray(data.operators)) {
          importedOperators = data.operators;
        }

        // Caso B: Backup antigo (lista de objetos 'employees')
        // Extraímos apenas o nome dos funcionários para manter a compatibilidade
        if (data.employees && Array.isArray(data.employees)) {
          const namesFromEmployees = data.employees
            .map((emp: any) => emp.name)
            .filter((name: any) => typeof name === 'string' && name.trim() !== '');

          // Combinamos com o que já foi achado em 'operators'
          importedOperators = [...importedOperators, ...namesFromEmployees];
        }

        // Atualizar estado de operadores removendo duplicatas
        if (importedOperators.length > 0) {
          const uniqueOperators = Array.from(new Set(importedOperators));
          setOperators(uniqueOperators);
        }

        alert('Backup carregado! Dados de produção e lista de operadores restaurados.');
      } catch (err) {
        console.error(err);
        alert('Erro ao processar o arquivo de backup. Verifique se o formato é válido.');
      }

      // Limpar o input para permitir selecionar o mesmo arquivo novamente se necessário
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    };
    reader.readAsText(file);
  };

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  // Filter logic based on the clickable cards
  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    const currentMonthStr = dayStr.substring(0, 7);

    // Logic for Week: From Sunday to Today
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay()); 

    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'month') return e.date.startsWith(currentMonthStr);
      if (selectedTimeframe === 'week') {
        const entryDate = new Date(e.date + 'T00:00:00');
        return entryDate >= startOfWeek;
      }
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const now = new Date();
    const todayStr = now.toLocaleDateString('sv-SE');
    const monthPrefix = now.toISOString().slice(0, 7);

    // Week start (Sunday)
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay());

    return productionData.reduce((acc, e) => {
      // Monthly Total
      if (e.date.startsWith(monthPrefix)) {
        acc.month += e.netWeight;
      }
      // Daily Total
      if (e.date === todayStr) {
        acc.day += e.netWeight;
      }
      // Weekly Total
      const entryDate = new Date(e.date + 'T00:00:00');
      if (entryDate >= startOfWeek) {
        acc.week += e.netWeight;
      }
      return acc;
    }, { month: 0, day: 0, week: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => { setEditingEntry(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-700 text-white font-black px-5 py-2.5 rounded-xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
          >
            <Plus size={16} /> Novo Lançamento
          </button>
          <button onClick={() => setIsMenuOpen(true)} className="p-2.5 text-slate-400 hover:bg-slate-100 rounded-xl transition-all">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto px-4 mt-6 no-print">
        <div className="bg-slate-200/50 p-1 rounded-2xl inline-flex gap-1 overflow-x-auto no-scrollbar max-w-full">
          {[
            { id: 'dashboard', icon: <BarChart3 size={14} />, label: 'Dashboard' },
            { id: 'reports', icon: <FileText size={14} />, label: 'Relatórios' }
          ].map((tab) => (
            <button 
              key={tab.id} 
              onClick={() => { 
                setActiveTab(tab.id as any);
                setSelectedIds([]); 
              }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-4 space-y-6">
        {activeTab === 'dashboard' ? (
          <div className="space-y-6">
            {/* Top Cards Section - Interativos */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              {/* Card Meta - Reseta para Visão Geral (Mês) */}
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all relative overflow-hidden group ${selectedTimeframe === 'month' ? 'bg-blue-600 text-white shadow-xl shadow-blue-200 border-blue-500' : 'bg-white text-slate-800 border-slate-100 hover:border-blue-200'}`}
              >
                <div className="flex justify-between items-start mb-4 relative z-10">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'month' ? 'bg-white/20 text-white' : 'bg-blue-50 text-blue-600'}`}>
                    <TrendingUp size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>Meta do Mês</span>
                </div>
                <div className="relative z-10">
                  <div className="text-2xl font-black mb-1">{(totals.month / 1000).toFixed(1)} T</div>
                  <div className="w-full bg-black/10 h-1.5 rounded-full overflow-hidden">
                    <div className={`h-full rounded-full ${selectedTimeframe === 'month' ? 'bg-white' : 'bg-blue-600'}`} style={{ width: `${Math.min((totals.month / (goalValue || 1)) * 100, 100)}%` }}></div>
                  </div>
                  <div className={`text-[9px] font-bold mt-2 ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>
                    {goalValue > 0 ? Math.round((totals.month / goalValue) * 100) : 0}% de {(goalValue/1000).toFixed(0)} T
                  </div>
                </div>
              </button>

              {/* Card Hoje */}
              <button 
                onClick={() => setSelectedTimeframe('day')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'day' ? 'bg-emerald-500 text-white shadow-xl shadow-emerald-200 border-emerald-400' : 'bg-white text-slate-800 border-slate-100 hover:border-emerald-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'day' ? 'bg-white/20 text-white' : 'bg-emerald-50 text-emerald-600'}`}>
                    <Calendar size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Hoje</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.day)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Produção do dia</p>
                </div>
              </button>

              {/* Card Semana */}
              <button 
                onClick={() => setSelectedTimeframe('week')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'week' ? 'bg-violet-500 text-white shadow-xl shadow-violet-200 border-violet-400' : 'bg-white text-slate-800 border-slate-100 hover:border-violet-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'week' ? 'bg-white/20 text-white' : 'bg-violet-50 text-violet-600'}`}>
                    <CalendarDays size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Esta Semana</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.week)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Dom - Sáb</p>
                </div>
              </button>

              {/* Card Mês (Estatística Pura) */}
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'month' ? 'ring-2 ring-blue-500 ring-offset-2' : 'bg-white hover:border-blue-200 border-slate-100'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className="p-2 rounded-xl bg-orange-50 text-orange-600">
                    <BarChart3 size={18} />
                  </div>
                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Este Mês</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1 text-slate-800">{formatWeight(totals.month)}</div>
                  <p className="text-[9px] font-bold text-slate-400">Acumulado mensal</p>
                </div>
              </button>
            </div>

            {/* Header do Gráfico dinâmico */}
            <div className="flex items-center gap-2 px-2">
              <span className="w-2 h-2 rounded-full bg-slate-300"></span>
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                Visualizando dados: <span className="text-blue-600">{
                  selectedTimeframe === 'day' ? 'Hoje' : 
                  selectedTimeframe === 'week' ? 'Esta Semana' : 
                  'Mês Atual'
                }</span>
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes },
                { title: '📊 Prod vs Reciclagem', key: 'prod', color: COLORS, formatter: formatWeight }
              ].map((chart, idx) => {
                const chartData = stats.filter(s => s[chart.key as keyof OperatorStat] > 0);
                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-[400px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
                    <div className="flex-1">
                      {chartData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                          <PieChart>
                            <Pie 
                              data={chartData} 
                              cx="50%" 
                              cy="50%" 
                              innerRadius={60} 
                              outerRadius={85} 
                              dataKey={chart.key} 
                              nameKey="name" 
                              label={renderCustomizedLabel}
                              paddingAngle={2}
                            >
                              {chartData.map((_, i) => <Cell key={i} fill={chart.color[i % chart.color.length]} stroke="none" />)}
                            </Pie>
                            <Tooltip formatter={(val: any) => chart.formatter(val)} />
                            <Legend iconType="circle" />
                          </PieChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="h-full flex items-center justify-center text-slate-300 font-bold text-xs uppercase">Sem dados neste período</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between gap-4">
              <div className="relative flex-1 max-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Pesquisar registros..." 
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none" 
                />
              </div>
              <div className="flex items-center gap-2 no-print">
                {selectedIds.length > 0 && (
                  <button 
                    onClick={() => {
                      const count = selectedIds.length;
                      if (window.confirm(`Confirma a exclusão de ${count} registros selecionados?`)) {
                        const idsToRemove = new Set(selectedIds);
                        setProductionData(prev => prev.filter(item => !idsToRemove.has(item.id)));
                        setSelectedIds([]);
                      }
                    }} 
                    className="flex items-center gap-2 px-4 py-2.5 bg-red-50 text-red-600 rounded-xl text-[10px] font-black uppercase hover:bg-red-100 transition-all animate-in fade-in"
                  >
                    <Trash2 size={16} /> Excluir ({selectedIds.length})
                  </button>
                )}
                <button onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[600px]">
                <thead>
                  <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4 w-10 no-print">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                        checked={selectedIds.length > 0 && selectedIds.length === productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).length}
                        onChange={(ev) => {
                          if (ev.target.checked) {
                            const filteredIds = productionData.filter(item => item.operator.toLowerCase().includes(searchTerm.toLowerCase())).map(item => item.id);
                            setSelectedIds(filteredIds);
                          } else {
                            setSelectedIds([]);
                          }
                        }}
                      />
                    </th>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Operador</th>
                    <th className="px-6 py-4">Líquido</th>
                    <th className="px-6 py-4">Eco A</th>
                    <th className="px-6 py-4">Borra</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-xs font-bold">
                  {productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).map((e) => (
                    <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/50' : ''}`}>
                      <td className="px-6 py-4 w-10 no-print">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                          checked={selectedIds.includes(e.id)}
                          onChange={() => {
                            setSelectedIds(prev => prev.includes(e.id) ? prev.filter(id => id !== e.id) : [...prev, e.id]);
                          }}
                        />
                      </td>
                      <td className="px-6 py-4">{e.date}</td>
                      <td className="px-6 py-4">{e.operator}</td>
                      <td className="px-6 py-4">{e.netWeight} kg</td>
                      <td className="px-6 py-4 text-emerald-600">{e.ecoA} kg</td>
                      <td className="px-6 py-4 text-red-500">{e.borraTotal} kg</td>
                      <td className="px-6 py-4 text-right space-x-2">
                        <button onClick={() => { setEditingEntry(e); setIsModalOpen(true); }} className="text-blue-500 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={14} /></button>
                        <button onClick={() => {
                          if (window.confirm('Deseja excluir este registro?')) {
                            setProductionData(prev => prev.filter(x => x.id !== e.id));
                            setSelectedIds(prev => prev.filter(id => id !== e.id));
                          }
                        }} className="text-red-400 p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      <div className={`fixed inset-0 z-50 transition-all ${isMenuOpen ? 'visible' : 'invisible'}`}>
        <div className={`absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} onClick={() => setIsMenuOpen(false)} />
        <div className={`absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl transition-transform duration-300 transform p-8 flex flex-col gap-8 ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2"><Settings size={22} /> Ajustes</h2>
            <button onClick={() => setIsMenuOpen(false)} className="p-2 text-slate-400"><X size={24} /></button>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nova Meta Mensal (KG)</label>
              <input 
                type="number" 
                value={goalValue} 
                onChange={(e) => setGoalValue(parseFloat(e.target.value) || 0)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-black text-blue-600 outline-none" 
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Gerenciar Operadores</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  value={newOpName} 
                  onChange={e => setNewOpName(e.target.value)}
                  placeholder="Novo operador..."
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-4 py-2 text-xs font-bold" 
                />
                <button 
                  onClick={() => { if (newOpName && !operators.includes(newOpName)) { setOperators(prev => [...prev, newOpName]); setNewOpName(''); } }}
                  className="bg-blue-600 text-white p-3 rounded-2xl"
                >
                  <Plus size={18} />
                </button>
              </div>

              <div className="mt-2 max-h-48 overflow-y-auto custom-scrollbar space-y-2 pr-1">
                {operators.map((op, idx) => (
                  <div key={idx} className="flex items-center justify-between bg-slate-50 p-3 rounded-xl border border-slate-100 hover:border-blue-100 transition-colors group">
                    <span className="text-xs font-bold text-slate-600">{op}</span>
                    <button 
                      onClick={() => setOperators(prev => prev.filter(o => o !== op))}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                      title="Remover operador"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                ))}
                {operators.length === 0 && (
                  <p className="text-[10px] text-slate-400 text-center py-2">Nenhum operador cadastrado</p>
                )}
              </div>
            </div>

            <div className="pt-8 border-t border-slate-100 space-y-3">
              <button onClick={() => {
                const data = { productionData, shifts, goalValue, operators };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'backup_manupackaging.json';
                a.click();
              }} className="w-full flex items-center justify-center gap-3 bg-slate-100 py-4 rounded-2xl text-[10px] font-black uppercase text-slate-600"><Download size={16} /> Exportar Backup</button>

              <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 bg-blue-50 py-4 rounded-2xl text-[10px] font-black uppercase text-blue-600"><Upload size={16} /> Importar Backup</button>

              <button onClick={() => { localStorage.removeItem('manupackaging_session'); setIsAuthenticated(false); }} className="w-full flex items-center justify-center gap-3 bg-red-50 py-4 rounded-2xl text-[10px] font-black uppercase text-red-600"><LogOut size={16} /> Sair do Sistema</button>
            </div>
          </div>
        </div>
      </div>

      <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />

      <LaunchModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingEntry(null); }} 
        onSave={handleSaveEntry} 
        operators={operators} 
        activeMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        availableShifts={shifts} 
        initialData={editingEntry} 
      />

      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, Settings, BarChart3, FileText, Search, 
  Printer, ShieldCheck, Download, Upload, Trash2, Cpu, 
  Save, X, Edit2, LogOut, Calendar, CalendarDays, TrendingUp
} from 'lucide-react';
import { 
  Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { ProductionEntry, Shift } from './types';
import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.1;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'month' | 'day' | 'week'>('month');

  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    const saved = localStorage.getItem('manupackaging_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);

        // 1. Importar dados de produção
        if (data.productionData && Array.isArray(data.productionData)) {
          setProductionData(data.productionData);
        }

        // 2. Importar Metas e Turnos
        if (data.goalValue) setGoalValue(Number(data.goalValue));
        if (data.shifts && Array.isArray(data.shifts)) setShifts(data.shifts);

        // 3. Lógica inteligente para Operadores
        let importedOperators: string[] = [];

        // Caso A: Backup novo (lista simples de strings)
        if (data.operators && Array.isArray(data.operators)) {
          importedOperators = data.operators;
        }

        // Caso B: Backup antigo (lista de objetos 'employees')
        // Extraímos apenas o nome dos funcionários para manter a compatibilidade
        if (data.employees && Array.isArray(data.employees)) {
          const namesFromEmployees = data.employees
            .map((emp: any) => emp.name)
            .filter((name: any) => typeof name === 'string' && name.trim() !== '');

          // Combinamos com o que já foi achado em 'operators'
          importedOperators = [...importedOperators, ...namesFromEmployees];
        }

        // Atualizar estado de operadores removendo duplicatas
        if (importedOperators.length > 0) {
          const uniqueOperators = Array.from(new Set(importedOperators));
          setOperators(uniqueOperators);
        }

        alert('Backup carregado! Dados de produção e lista de operadores restaurados.');
      } catch (err) {
        console.error(err);
        alert('Erro ao processar o arquivo de backup. Verifique se o formato é válido.');
      }

      // Limpar o input para permitir selecionar o mesmo arquivo novamente se necessário
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    };
    reader.readAsText(file);
  };

  // --- NOVA LÓGICA DE EXCLUSÃO ---
  const handleDeleteEntry = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro permanentemente?')) {
      setProductionData(prev => prev.filter(item => item.id !== id));
      // Se estava selecionado, remove da seleção
      setSelectedIds(prev => prev.filter(selectedId => selectedId !== id));
    }
  };

  const handleBatchDelete = () => {
    if (selectedIds.length === 0) return;

    if (window.confirm(`Você está prestes a excluir ${selectedIds.length} registros. Confirmar exclusão?`)) {
      const idsToDelete = new Set(selectedIds);
      setProductionData(prev => prev.filter(item => !idsToDelete.has(item.id)));
      setSelectedIds([]); // Limpa a seleção
    }
  };
  // -------------------------------

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  // Filter logic based on the clickable cards
  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    const currentMonthStr = dayStr.substring(0, 7);

    // Logic for Week: From Sunday to Today
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay()); 

    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'month') return e.date.startsWith(currentMonthStr);
      if (selectedTimeframe === 'week') {
        const entryDate = new Date(e.date + 'T00:00:00');
        return entryDate >= startOfWeek;
      }
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const now = new Date();
    const todayStr = now.toLocaleDateString('sv-SE');
    const monthPrefix = now.toISOString().slice(0, 7);

    // Week start (Sunday)
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay());

    return productionData.reduce((acc, e) => {
      // Monthly Total
      if (e.date.startsWith(monthPrefix)) {
        acc.month += e.netWeight;
      }
      // Daily Total
      if (e.date === todayStr) {
        acc.day += e.netWeight;
      }
      // Weekly Total
      const entryDate = new Date(e.date + 'T00:00:00');
      if (entryDate >= startOfWeek) {
        acc.week += e.netWeight;
      }
      return acc;
    }, { month: 0, day: 0, week: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => { setEditingEntry(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-700 text-white font-black px-5 py-2.5 rounded-xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
          >
            <Plus size={16} /> Novo Lançamento
          </button>
          <button onClick={() => setIsMenuOpen(true)} className="p-2.5 text-slate-400 hover:bg-slate-100 rounded-xl transition-all">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto px-4 mt-6 no-print">
        <div className="bg-slate-200/50 p-1 rounded-2xl inline-flex gap-1 overflow-x-auto no-scrollbar max-w-full">
          {[
            { id: 'dashboard', icon: <BarChart3 size={14} />, label: 'Dashboard' },
            { id: 'reports', icon: <FileText size={14} />, label: 'Relatórios' }
          ].map((tab) => (
            <button 
              key={tab.id} 
              onClick={() => { 
                setActiveTab(tab.id as any);
                setSelectedIds([]); 
              }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-4 space-y-6">
        {activeTab === 'dashboard' ? (
          <div className="space-y-6">
            {/* Top Cards Section - Interativos */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              {/* Card Meta - Reseta para Visão Geral (Mês) */}
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all relative overflow-hidden group ${selectedTimeframe === 'month' ? 'bg-blue-600 text-white shadow-xl shadow-blue-200 border-blue-500' : 'bg-white text-slate-800 border-slate-100 hover:border-blue-200'}`}
              >
                <div className="flex justify-between items-start mb-4 relative z-10">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'month' ? 'bg-white/20 text-white' : 'bg-blue-50 text-blue-600'}`}>
                    <TrendingUp size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>Meta do Mês</span>
                </div>
                <div className="relative z-10">
                  <div className="text-2xl font-black mb-1">{(totals.month / 1000).toFixed(1)} T</div>
                  <div className="w-full bg-black/10 h-1.5 rounded-full overflow-hidden">
                    <div className={`h-full rounded-full ${selectedTimeframe === 'month' ? 'bg-white' : 'bg-blue-600'}`} style={{ width: `${Math.min((totals.month / (goalValue || 1)) * 100, 100)}%` }}></div>
                  </div>
                  <div className={`text-[9px] font-bold mt-2 ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>
                    {goalValue > 0 ? Math.round((totals.month / goalValue) * 100) : 0}% de {(goalValue/1000).toFixed(0)} T
                  </div>
                </div>
              </button>

              {/* Card Hoje */}
              <button 
                onClick={() => setSelectedTimeframe('day')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'day' ? 'bg-emerald-500 text-white shadow-xl shadow-emerald-200 border-emerald-400' : 'bg-white text-slate-800 border-slate-100 hover:border-emerald-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'day' ? 'bg-white/20 text-white' : 'bg-emerald-50 text-emerald-600'}`}>
                    <Calendar size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Hoje</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.day)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Produção do dia</p>
                </div>
              </button>

              {/* Card Semana */}
              <button 
                onClick={() => setSelectedTimeframe('week')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'week' ? 'bg-violet-500 text-white shadow-xl shadow-violet-200 border-violet-400' : 'bg-white text-slate-800 border-slate-100 hover:border-violet-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'week' ? 'bg-white/20 text-white' : 'bg-violet-50 text-violet-600'}`}>
                    <CalendarDays size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Esta Semana</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.week)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Dom - Sáb</p>
                </div>
              </button>

              {/* Card Mês (Estatística Pura) */}
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'month' ? 'ring-2 ring-blue-500 ring-offset-2' : 'bg-white hover:border-blue-200 border-slate-100'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className="p-2 rounded-xl bg-orange-50 text-orange-600">
                    <BarChart3 size={18} />
                  </div>
                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Este Mês</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1 text-slate-800">{formatWeight(totals.month)}</div>
                  <p className="text-[9px] font-bold text-slate-400">Acumulado mensal</p>
                </div>
              </button>
            </div>

            {/* Header do Gráfico dinâmico */}
            <div className="flex items-center gap-2 px-2">
              <span className="w-2 h-2 rounded-full bg-slate-300"></span>
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                Visualizando dados: <span className="text-blue-600">{
                  selectedTimeframe === 'day' ? 'Hoje' : 
                  selectedTimeframe === 'week' ? 'Esta Semana' : 
                  'Mês Atual'
                }</span>
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes },
                { title: '📊 Prod vs Reciclagem', key: 'prod', color: COLORS, formatter: formatWeight }
              ].map((chart, idx) => {
                const chartData = stats.filter(s => s[chart.key as keyof OperatorStat] > 0);
                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-[400px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
                    <div className="flex-1">
                      {chartData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                          <PieChart>
                            <Pie 
                              data={chartData} 
                              cx="50%" 
                              cy="50%" 
                              innerRadius={60} 
                              outerRadius={85} 
                              dataKey={chart.key} 
                              nameKey="name" 
                              label={renderCustomizedLabel}
                              paddingAngle={2}
                            >
                              {chartData.map((_, i) => <Cell key={i} fill={chart.color[i % chart.color.length]} stroke="none" />)}
                            </Pie>
                            <Tooltip formatter={(val: any) => chart.formatter(val)} />
                            <Legend iconType="circle" />
                          </PieChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="h-full flex items-center justify-center text-slate-300 font-bold text-xs uppercase">Sem dados neste período</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between gap-4">
              <div className="relative flex-1 max-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Pesquisar registros..." 
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none" 
                />
              </div>
              <div className="flex items-center gap-2 no-print">
                {selectedIds.length > 0 && (
                  <button 
                    onClick={handleBatchDelete} 
                    className="flex items-center gap-2 px-4 py-2.5 bg-red-50 text-red-600 rounded-xl text-[10px] font-black uppercase hover:bg-red-100 transition-all animate-in fade-in"
                  >
                    <Trash2 size={16} /> Excluir ({selectedIds.length})
                  </button>
                )}
                <button onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[600px]">
                <thead>
                  <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4 w-10 no-print">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                        checked={selectedIds.length > 0 && selectedIds.length === productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).length}
                        onChange={(ev) => {
                          if (ev.target.checked) {
                            const filteredIds = productionData.filter(item => item.operator.toLowerCase().includes(searchTerm.toLowerCase())).map(item => item.id);
                            setSelectedIds(filteredIds);
                          } else {
                            setSelectedIds([]);
                          }
                        }}
                      />
                    </th>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Operador</th>
                    <th className="px-6 py-4">Líquido</th>
                    <th className="px-6 py-4">Eco A</th>
                    <th className="px-6 py-4">Borra</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-xs font-bold">
                  {productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).map((e) => (
                    <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/50' : ''}`}>
                      <td className="px-6 py-4 w-10 no-print">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                          checked={selectedIds.includes(e.id)}
                          onChange={() => {
                            setSelectedIds(prev => prev.includes(e.id) ? prev.filter(id => id !== e.id) : [...prev, e.id]);
                          }}
                        />
                      </td>
                      <td className="px-6 py-4">{e.date}</td>
                      <td className="px-6 py-4">{e.operator}</td>
                      <td className="px-6 py-4">{e.netWeight} kg</td>
                      <td className="px-6 py-4 text-emerald-600">{e.ecoA} kg</td>
                      <td className="px-6 py-4 text-red-500">{e.borraTotal} kg</td>
                      <td className="px-6 py-4 text-right space-x-2">
                        <button onClick={() => { setEditingEntry(e); setIsModalOpen(true); }} className="text-blue-500 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={14} /></button>
                        <button onClick={() => handleDeleteEntry(e.id)} className="text-red-400 p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      <div className={`fixed inset-0 z-50 transition-all ${isMenuOpen ? 'visible' : 'invisible'}`}>
        <div className={`absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} onClick={() => setIsMenuOpen(false)} />
        <div className={`absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl transition-transform duration-300 transform p-8 flex flex-col gap-8 ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2"><Settings size={22} /> Ajustes</h2>
            <button onClick={() => setIsMenuOpen(false)} className="p-2 text-slate-400"><X size={24} /></button>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nova Meta Mensal (KG)</label>
              <input 
                type="number" 
                value={goalValue} 
                onChange={(e) => setGoalValue(parseFloat(e.target.value) || 0)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-black text-blue-600 outline-none" 
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Gerenciar Operadores</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  value={newOpName} 
                  onChange={e => setNewOpName(e.target.value)}
                  placeholder="Novo operador..."
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-4 py-2 text-xs font-bold" 
                />
                <button 
                  onClick={() => { if (newOpName && !operators.includes(newOpName)) { setOperators(prev => [...prev, newOpName]); setNewOpName(''); } }}
                  className="bg-blue-600 text-white p-3 rounded-2xl"
                >
                  <Plus size={18} />
                </button>
              </div>

              <div className="mt-2 max-h-48 overflow-y-auto custom-scrollbar space-y-2 pr-1">
                {operators.map((op, idx) => (
                  <div key={idx} className="flex items-center justify-between bg-slate-50 p-3 rounded-xl border border-slate-100 hover:border-blue-100 transition-colors group">
                    <span className="text-xs font-bold text-slate-600">{op}</span>
                    <button 
                      onClick={() => setOperators(prev => prev.filter(o => o !== op))}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                      title="Remover operador"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                ))}
                {operators.length === 0 && (
                  <p className="text-[10px] text-slate-400 text-center py-2">Nenhum operador cadastrado</p>
                )}
              </div>
            </div>

            <div className="pt-8 border-t border-slate-100 space-y-3">
              <button onClick={() => {
                const data = { productionData, shifts, goalValue, operators };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'backup_manupackaging.json';
                a.click();
              }} className="w-full flex items-center justify-center gap-3 bg-slate-100 py-4 rounded-2xl text-[10px] font-black uppercase text-slate-600"><Download size={16} /> Exportar Backup</button>

              <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 bg-blue-50 py-4 rounded-2xl text-[10px] font-black uppercase text-blue-600"><Upload size={16} /> Importar Backup</button>

              <button onClick={() => { localStorage.removeItem('manupackaging_session'); setIsAuthenticated(false); }} className="w-full flex items-center justify-center gap-3 bg-red-50 py-4 rounded-2xl text-[10px] font-black uppercase text-red-600"><LogOut size={16} /> Sair do Sistema</button>
            </div>
          </div>
        </div>
      </div>

      <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />

      <LaunchModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingEntry(null); }} 
        onSave={handleSaveEntry} 
        operators={operators} 
        activeMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        availableShifts={shifts} 
        initialData={editingEntry} 
      />

      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, Settings, BarChart3, FileText, Search, 
  Printer, ShieldCheck, Download, Upload, Trash2, Cpu, 
  Save, X, Edit2, LogOut, Calendar, CalendarDays, TrendingUp
} from 'lucide-react';
import { 
  Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { ProductionEntry, Shift } from './types';
import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.1;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'month' | 'day' | 'week'>('month');

  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    const saved = localStorage.getItem('manupackaging_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);

        // 1. Importar dados de produção
        if (data.productionData && Array.isArray(data.productionData)) {
          setProductionData(data.productionData);
        }

        // 2. Importar Metas e Turnos
        if (data.goalValue) setGoalValue(Number(data.goalValue));
        if (data.shifts && Array.isArray(data.shifts)) setShifts(data.shifts);

        // 3. Lógica inteligente para Operadores
        let importedOperators: string[] = [];

        // Caso A: Backup novo (lista simples de strings)
        if (data.operators && Array.isArray(data.operators)) {
          importedOperators = data.operators;
        }

        // Caso B: Backup antigo (lista de objetos 'employees')
        // Extraímos apenas o nome dos funcionários para manter a compatibilidade
        if (data.employees && Array.isArray(data.employees)) {
          const namesFromEmployees = data.employees
            .map((emp: any) => emp.name)
            .filter((name: any) => typeof name === 'string' && name.trim() !== '');

          // Combinamos com o que já foi achado em 'operators'
          importedOperators = [...importedOperators, ...namesFromEmployees];
        }

        // Atualizar estado de operadores removendo duplicatas
        if (importedOperators.length > 0) {
          const uniqueOperators = Array.from(new Set(importedOperators));
          setOperators(uniqueOperators);
        }

        alert('Backup carregado! Dados de produção e lista de operadores restaurados.');
      } catch (err) {
        console.error(err);
        alert('Erro ao processar o arquivo de backup. Verifique se o formato é válido.');
      }

      // Limpar o input para permitir selecionar o mesmo arquivo novamente se necessário
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    };
    reader.readAsText(file);
  };

  // --- NOVA LÓGICA DE EXCLUSÃO ---
  const handleDeleteEntry = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro permanentemente?')) {
      setProductionData(prev => prev.filter(item => item.id !== id));
      // Se estava selecionado, remove da seleção
      setSelectedIds(prev => prev.filter(selectedId => selectedId !== id));
    }
  };

  const handleBatchDelete = () => {
    if (selectedIds.length === 0) return;

    if (window.confirm(`Você está prestes a excluir ${selectedIds.length} registros. Confirmar exclusão?`)) {
      const idsToDelete = new Set(selectedIds);
      setProductionData(prev => prev.filter(item => !idsToDelete.has(item.id)));
      setSelectedIds([]); // Limpa a seleção
    }
  };
  // -------------------------------

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  // Filter logic based on the clickable cards
  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    const currentMonthStr = dayStr.substring(0, 7);

    // Logic for Week: From Sunday to Today
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay()); 

    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'month') return e.date.startsWith(currentMonthStr);
      if (selectedTimeframe === 'week') {
        const entryDate = new Date(e.date + 'T00:00:00');
        return entryDate >= startOfWeek;
      }
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const now = new Date();
    const todayStr = now.toLocaleDateString('sv-SE');
    const monthPrefix = now.toISOString().slice(0, 7);

    // Week start (Sunday)
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay());

    return productionData.reduce((acc, e) => {
      // Monthly Total
      if (e.date.startsWith(monthPrefix)) {
        acc.month += e.netWeight;
      }
      // Daily Total
      if (e.date === todayStr) {
        acc.day += e.netWeight;
      }
      // Weekly Total
      const entryDate = new Date(e.date + 'T00:00:00');
      if (entryDate >= startOfWeek) {
        acc.week += e.netWeight;
      }
      return acc;
    }, { month: 0, day: 0, week: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => { setEditingEntry(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-700 text-white font-black px-5 py-2.5 rounded-xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
          >
            <Plus size={16} /> Novo Lançamento
          </button>
          <button onClick={() => setIsMenuOpen(true)} className="p-2.5 text-slate-400 hover:bg-slate-100 rounded-xl transition-all">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto px-4 mt-6 no-print">
        <div className="bg-slate-200/50 p-1 rounded-2xl inline-flex gap-1 overflow-x-auto no-scrollbar max-w-full">
          {[
            { id: 'dashboard', icon: <BarChart3 size={14} />, label: 'Dashboard' },
            { id: 'reports', icon: <FileText size={14} />, label: 'Relatórios' }
          ].map((tab) => (
            <button 
              key={tab.id} 
              onClick={() => { 
                setActiveTab(tab.id as any);
                setSelectedIds([]); 
              }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-4 space-y-6">
        {activeTab === 'dashboard' ? (
          <div className="space-y-6">
            {/* Top Cards Section - Interativos */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              {/* Card Meta - Reseta para Visão Geral (Mês) */}
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all relative overflow-hidden group ${selectedTimeframe === 'month' ? 'bg-blue-600 text-white shadow-xl shadow-blue-200 border-blue-500' : 'bg-white text-slate-800 border-slate-100 hover:border-blue-200'}`}
              >
                <div className="flex justify-between items-start mb-4 relative z-10">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'month' ? 'bg-white/20 text-white' : 'bg-blue-50 text-blue-600'}`}>
                    <TrendingUp size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>Meta do Mês</span>
                </div>
                <div className="relative z-10">
                  <div className="text-2xl font-black mb-1">{(totals.month / 1000).toFixed(1)} T</div>
                  <div className="w-full bg-black/10 h-1.5 rounded-full overflow-hidden">
                    <div className={`h-full rounded-full ${selectedTimeframe === 'month' ? 'bg-white' : 'bg-blue-600'}`} style={{ width: `${Math.min((totals.month / (goalValue || 1)) * 100, 100)}%` }}></div>
                  </div>
                  <div className={`text-[9px] font-bold mt-2 ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>
                    {totals.month >= goalValue 
                      ? 'Meta atingida! 🚀' 
                      : `Faltam ${formatWeight(goalValue - totals.month)} para a meta`}
                  </div>
                </div>
              </button>

              {/* Card Hoje */}
              <button 
                onClick={() => setSelectedTimeframe('day')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'day' ? 'bg-emerald-500 text-white shadow-xl shadow-emerald-200 border-emerald-400' : 'bg-white text-slate-800 border-slate-100 hover:border-emerald-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'day' ? 'bg-white/20 text-white' : 'bg-emerald-50 text-emerald-600'}`}>
                    <Calendar size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Hoje</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.day)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Produção do dia</p>
                </div>
              </button>

              {/* Card Semana */}
              <button 
                onClick={() => setSelectedTimeframe('week')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'week' ? 'bg-violet-500 text-white shadow-xl shadow-violet-200 border-violet-400' : 'bg-white text-slate-800 border-slate-100 hover:border-violet-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'week' ? 'bg-white/20 text-white' : 'bg-violet-50 text-violet-600'}`}>
                    <CalendarDays size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Esta Semana</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.week)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Dom - Sáb</p>
                </div>
              </button>

              {/* Card Mês (Estatística Pura) */}
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'month' ? 'ring-2 ring-blue-500 ring-offset-2' : 'bg-white hover:border-blue-200 border-slate-100'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className="p-2 rounded-xl bg-orange-50 text-orange-600">
                    <BarChart3 size={18} />
                  </div>
                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Este Mês</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1 text-slate-800">{formatWeight(totals.month)}</div>
                  <p className="text-[9px] font-bold text-slate-400">Acumulado mensal</p>
                </div>
              </button>
            </div>

            {/* Header do Gráfico dinâmico */}
            <div className="flex items-center gap-2 px-2">
              <span className="w-2 h-2 rounded-full bg-slate-300"></span>
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                Visualizando dados: <span className="text-blue-600">{
                  selectedTimeframe === 'day' ? 'Hoje' : 
                  selectedTimeframe === 'week' ? 'Esta Semana' : 
                  'Mês Atual'
                }</span>
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes },
                { title: '📊 Prod vs Reciclagem', key: 'prod', color: COLORS, formatter: formatWeight }
              ].map((chart, idx) => {
                const chartData = stats.filter(s => s[chart.key as keyof OperatorStat] > 0);
                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-[400px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
                    <div className="flex-1">
                      {chartData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                          <PieChart>
                            <Pie 
                              data={chartData} 
                              cx="50%" 
                              cy="50%" 
                              innerRadius={60} 
                              outerRadius={85} 
                              dataKey={chart.key} 
                              nameKey="name" 
                              label={renderCustomizedLabel}
                              paddingAngle={2}
                            >
                              {chartData.map((_, i) => <Cell key={i} fill={chart.color[i % chart.color.length]} stroke="none" />)}
                            </Pie>
                            <Tooltip formatter={(val: any) => chart.formatter(val)} />
                            <Legend iconType="circle" />
                          </PieChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="h-full flex items-center justify-center text-slate-300 font-bold text-xs uppercase">Sem dados neste período</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between gap-4">
              <div className="relative flex-1 max-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Pesquisar registros..." 
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none" 
                />
              </div>
              <div className="flex items-center gap-2 no-print">
                {selectedIds.length > 0 && (
                  <button 
                    onClick={handleBatchDelete} 
                    className="flex items-center gap-2 px-4 py-2.5 bg-red-50 text-red-600 rounded-xl text-[10px] font-black uppercase hover:bg-red-100 transition-all animate-in fade-in"
                  >
                    <Trash2 size={16} /> Excluir ({selectedIds.length})
                  </button>
                )}
                <button onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[600px]">
                <thead>
                  <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4 w-10 no-print">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                        checked={selectedIds.length > 0 && selectedIds.length === productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).length}
                        onChange={(ev) => {
                          if (ev.target.checked) {
                            const filteredIds = productionData.filter(item => item.operator.toLowerCase().includes(searchTerm.toLowerCase())).map(item => item.id);
                            setSelectedIds(filteredIds);
                          } else {
                            setSelectedIds([]);
                          }
                        }}
                      />
                    </th>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Operador</th>
                    <th className="px-6 py-4">Líquido</th>
                    <th className="px-6 py-4">Eco A</th>
                    <th className="px-6 py-4">Borra</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-xs font-bold">
                  {productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).map((e) => (
                    <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/50' : ''}`}>
                      <td className="px-6 py-4 w-10 no-print">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                          checked={selectedIds.includes(e.id)}
                          onChange={() => {
                            setSelectedIds(prev => prev.includes(e.id) ? prev.filter(id => id !== e.id) : [...prev, e.id]);
                          }}
                        />
                      </td>
                      <td className="px-6 py-4">{e.date}</td>
                      <td className="px-6 py-4">{e.operator}</td>
                      <td className="px-6 py-4">{e.netWeight} kg</td>
                      <td className="px-6 py-4 text-emerald-600">{e.ecoA} kg</td>
                      <td className="px-6 py-4 text-red-500">{e.borraTotal} kg</td>
                      <td className="px-6 py-4 text-right space-x-2">
                        <button onClick={() => { setEditingEntry(e); setIsModalOpen(true); }} className="text-blue-500 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={14} /></button>
                        <button onClick={() => handleDeleteEntry(e.id)} className="text-red-400 p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      <div className={`fixed inset-0 z-50 transition-all ${isMenuOpen ? 'visible' : 'invisible'}`}>
        <div className={`absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} onClick={() => setIsMenuOpen(false)} />
        <div className={`absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl transition-transform duration-300 transform p-8 flex flex-col gap-8 ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2"><Settings size={22} /> Ajustes</h2>
            <button onClick={() => setIsMenuOpen(false)} className="p-2 text-slate-400"><X size={24} /></button>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nova Meta Mensal (KG)</label>
              <input 
                type="number" 
                value={goalValue} 
                onChange={(e) => setGoalValue(parseFloat(e.target.value) || 0)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-black text-blue-600 outline-none" 
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Gerenciar Operadores</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  value={newOpName} 
                  onChange={e => setNewOpName(e.target.value)}
                  placeholder="Novo operador..."
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-4 py-2 text-xs font-bold" 
                />
                <button 
                  onClick={() => { if (newOpName && !operators.includes(newOpName)) { setOperators(prev => [...prev, newOpName]); setNewOpName(''); } }}
                  className="bg-blue-600 text-white p-3 rounded-2xl"
                >
                  <Plus size={18} />
                </button>
              </div>

              <div className="mt-2 max-h-48 overflow-y-auto custom-scrollbar space-y-2 pr-1">
                {operators.map((op, idx) => (
                  <div key={idx} className="flex items-center justify-between bg-slate-50 p-3 rounded-xl border border-slate-100 hover:border-blue-100 transition-colors group">
                    <span className="text-xs font-bold text-slate-600">{op}</span>
                    <button 
                      onClick={() => setOperators(prev => prev.filter(o => o !== op))}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                      title="Remover operador"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                ))}
                {operators.length === 0 && (
                  <p className="text-[10px] text-slate-400 text-center py-2">Nenhum operador cadastrado</p>
                )}
              </div>
            </div>

            <div className="pt-8 border-t border-slate-100 space-y-3">
              <button onClick={() => {
                const data = { productionData, shifts, goalValue, operators };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'backup_manupackaging.json';
                a.click();
              }} className="w-full flex items-center justify-center gap-3 bg-slate-100 py-4 rounded-2xl text-[10px] font-black uppercase text-slate-600"><Download size={16} /> Exportar Backup</button>

              <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 bg-blue-50 py-4 rounded-2xl text-[10px] font-black uppercase text-blue-600"><Upload size={16} /> Importar Backup</button>

              <button onClick={() => { localStorage.removeItem('manupackaging_session'); setIsAuthenticated(false); }} className="w-full flex items-center justify-center gap-3 bg-red-50 py-4 rounded-2xl text-[10px] font-black uppercase text-red-600"><LogOut size={16} /> Sair do Sistema</button>
            </div>
          </div>
        </div>
      </div>

      <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />

      <LaunchModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingEntry(null); }} 
        onSave={handleSaveEntry} 
        operators={operators} 
        activeMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        availableShifts={shifts} 
        initialData={editingEntry} 
      />

      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, Settings, BarChart3, FileText, Search, 
  Printer, ShieldCheck, Download, Upload, Trash2, Cpu, 
  Save, X, Edit2, LogOut, Calendar, CalendarDays, TrendingUp
} from 'lucide-react';
import { 
  Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { ProductionEntry, Shift } from './types';
import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.1;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'month' | 'day' | 'week'>('month');

  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    const saved = localStorage.getItem('manupackaging_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);

        // 1. Importar dados de produção
        if (data.productionData && Array.isArray(data.productionData)) {
          setProductionData(data.productionData);
        }

        // 2. Importar Metas e Turnos
        if (data.goalValue) setGoalValue(Number(data.goalValue));
        if (data.shifts && Array.isArray(data.shifts)) setShifts(data.shifts);

        // 3. Lógica inteligente para Operadores
        let importedOperators: string[] = [];

        // Caso A: Backup novo (lista simples de strings)
        if (data.operators && Array.isArray(data.operators)) {
          importedOperators = data.operators;
        }

        // Caso B: Backup antigo (lista de objetos 'employees')
        // Extraímos apenas o nome dos funcionários para manter a compatibilidade
        if (data.employees && Array.isArray(data.employees)) {
          const namesFromEmployees = data.employees
            .map((emp: any) => emp.name)
            .filter((name: any) => typeof name === 'string' && name.trim() !== '');

          // Combinamos com o que já foi achado em 'operators'
          importedOperators = [...importedOperators, ...namesFromEmployees];
        }

        // Atualizar estado de operadores removendo duplicatas
        if (importedOperators.length > 0) {
          const uniqueOperators = Array.from(new Set(importedOperators));
          setOperators(uniqueOperators);
        }

        alert('Backup carregado! Dados de produção e lista de operadores restaurados.');
      } catch (err) {
        console.error(err);
        alert('Erro ao processar o arquivo de backup. Verifique se o formato é válido.');
      }

      // Limpar o input para permitir selecionar o mesmo arquivo novamente se necessário
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    };
    reader.readAsText(file);
  };

  // --- NOVA LÓGICA DE EXCLUSÃO ---
  const handleDeleteEntry = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro permanentemente?')) {
      setProductionData(prev => prev.filter(item => item.id !== id));
      // Se estava selecionado, remove da seleção
      setSelectedIds(prev => prev.filter(selectedId => selectedId !== id));
    }
  };

  const handleBatchDelete = () => {
    if (selectedIds.length === 0) return;

    if (window.confirm(`Você está prestes a excluir ${selectedIds.length} registros. Confirmar exclusão?`)) {
      const idsToDelete = new Set(selectedIds);
      setProductionData(prev => prev.filter(item => !idsToDelete.has(item.id)));
      setSelectedIds([]); // Limpa a seleção
    }
  };
  // -------------------------------

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  // Filter logic based on the clickable cards
  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    const currentMonthStr = dayStr.substring(0, 7);

    // Logic for Week: From Sunday to Today
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay()); 

    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'month') return e.date.startsWith(currentMonthStr);
      if (selectedTimeframe === 'week') {
        const entryDate = new Date(e.date + 'T00:00:00');
        return entryDate >= startOfWeek;
      }
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const now = new Date();
    const todayStr = now.toLocaleDateString('sv-SE');
    const monthPrefix = now.toISOString().slice(0, 7);

    // Week start (Sunday)
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay());

    return productionData.reduce((acc, e) => {
      // Monthly Total
      if (e.date.startsWith(monthPrefix)) {
        acc.month += e.netWeight;
      }
      // Daily Total
      if (e.date === todayStr) {
        acc.day += e.netWeight;
      }
      // Weekly Total
      const entryDate = new Date(e.date + 'T00:00:00');
      if (entryDate >= startOfWeek) {
        acc.week += e.netWeight;
      }
      return acc;
    }, { month: 0, day: 0, week: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => { setEditingEntry(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-700 text-white font-black px-5 py-2.5 rounded-xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
          >
            <Plus size={16} /> Novo Lançamento
          </button>
          <button onClick={() => setIsMenuOpen(true)} className="p-2.5 text-slate-400 hover:bg-slate-100 rounded-xl transition-all">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto px-4 mt-6 no-print">
        <div className="bg-slate-200/50 p-1 rounded-2xl inline-flex gap-1 overflow-x-auto no-scrollbar max-w-full">
          {[
            { id: 'dashboard', icon: <BarChart3 size={14} />, label: 'Dashboard' },
            { id: 'reports', icon: <FileText size={14} />, label: 'Relatórios' }
          ].map((tab) => (
            <button 
              key={tab.id} 
              onClick={() => { 
                setActiveTab(tab.id as any);
                setSelectedIds([]); 
              }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-4 space-y-6">
        {activeTab === 'dashboard' ? (
          <div className="space-y-6">
            {/* Top Cards Section - Interativos */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              {/* Card Meta - Reseta para Visão Geral (Mês) */}
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all relative overflow-hidden group ${selectedTimeframe === 'month' ? 'bg-blue-600 text-white shadow-xl shadow-blue-200 border-blue-500' : 'bg-white text-slate-800 border-slate-100 hover:border-blue-200'}`}
              >
                <div className="flex justify-between items-start mb-4 relative z-10">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'month' ? 'bg-white/20 text-white' : 'bg-blue-50 text-blue-600'}`}>
                    <TrendingUp size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>Meta do Mês</span>
                </div>
                <div className="relative z-10">
                  <div className="text-2xl font-black mb-1">{(totals.month / 1000).toFixed(1)} T</div>
                  <div className="w-full bg-black/10 h-1.5 rounded-full overflow-hidden">
                    <div className={`h-full rounded-full ${selectedTimeframe === 'month' ? 'bg-white' : 'bg-blue-600'}`} style={{ width: `${Math.min((totals.month / (goalValue || 1)) * 100, 100)}%` }}></div>
                  </div>
                  <div className={`text-[9px] font-bold mt-2 ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>
                    {totals.month >= goalValue 
                      ? 'Meta atingida! 🚀' 
                      : `Faltam ${formatWeight(goalValue - totals.month)} para a meta`}
                  </div>
                </div>
              </button>

              {/* Card Hoje */}
              <button 
                onClick={() => setSelectedTimeframe('day')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'day' ? 'bg-emerald-500 text-white shadow-xl shadow-emerald-200 border-emerald-400' : 'bg-white text-slate-800 border-slate-100 hover:border-emerald-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'day' ? 'bg-white/20 text-white' : 'bg-emerald-50 text-emerald-600'}`}>
                    <Calendar size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Hoje</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.day)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Produção do dia</p>
                </div>
              </button>

              {/* Card Semana */}
              <button 
                onClick={() => setSelectedTimeframe('week')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'week' ? 'bg-violet-500 text-white shadow-xl shadow-violet-200 border-violet-400' : 'bg-white text-slate-800 border-slate-100 hover:border-violet-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'week' ? 'bg-white/20 text-white' : 'bg-violet-50 text-violet-600'}`}>
                    <CalendarDays size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Esta Semana</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.week)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Dom - Sáb</p>
                </div>
              </button>

              {/* Card Mês (Estatística Pura) */}
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'month' ? 'ring-2 ring-blue-500 ring-offset-2' : 'bg-white hover:border-blue-200 border-slate-100'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className="p-2 rounded-xl bg-orange-50 text-orange-600">
                    <BarChart3 size={18} />
                  </div>
                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Este Mês</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1 text-slate-800">{formatWeight(totals.month)}</div>
                  <p className="text-[9px] font-bold text-slate-400">Acumulado mensal</p>
                </div>
              </button>
            </div>

            {/* Header do Gráfico dinâmico */}
            <div className="flex items-center gap-2 px-2">
              <span className="w-2 h-2 rounded-full bg-slate-300"></span>
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                Visualizando dados: <span className="text-blue-600">{
                  selectedTimeframe === 'day' ? 'Hoje' : 
                  selectedTimeframe === 'week' ? 'Esta Semana' : 
                  'Mês Atual'
                }</span>
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight },
                { title: '♻️ Eco B Manutenção', key: 'ecoBM', color: ['#8b5cf6', '#a78bfa', '#c4b5fd'], formatter: formatWeight },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes },
                { title: '📊 Prod vs Reciclagem', key: 'prod', color: COLORS, formatter: formatWeight }
              ].map((chart, idx) => {
                const chartData = stats.filter(s => s[chart.key as keyof OperatorStat] > 0);
                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-[400px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
                    <div className="flex-1">
                      {chartData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                          <PieChart>
                            <Pie 
                              data={chartData} 
                              cx="50%" 
                              cy="50%" 
                              innerRadius={60} 
                              outerRadius={85} 
                              dataKey={chart.key} 
                              nameKey="name" 
                              label={renderCustomizedLabel}
                              paddingAngle={2}
                            >
                              {chartData.map((_, i) => <Cell key={i} fill={chart.color[i % chart.color.length]} stroke="none" />)}
                            </Pie>
                            <Tooltip formatter={(val: any) => chart.formatter(val)} />
                            <Legend iconType="circle" />
                          </PieChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="h-full flex items-center justify-center text-slate-300 font-bold text-xs uppercase">Sem dados neste período</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between gap-4">
              <div className="relative flex-1 max-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Pesquisar registros..." 
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none" 
                />
              </div>
              <div className="flex items-center gap-2 no-print">
                {selectedIds.length > 0 && (
                  <button 
                    onClick={handleBatchDelete} 
                    className="flex items-center gap-2 px-4 py-2.5 bg-red-50 text-red-600 rounded-xl text-[10px] font-black uppercase hover:bg-red-100 transition-all animate-in fade-in"
                  >
                    <Trash2 size={16} /> Excluir ({selectedIds.length})
                  </button>
                )}
                <button onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[600px]">
                <thead>
                  <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4 w-10 no-print">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                        checked={selectedIds.length > 0 && selectedIds.length === productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).length}
                        onChange={(ev) => {
                          if (ev.target.checked) {
                            const filteredIds = productionData.filter(item => item.operator.toLowerCase().includes(searchTerm.toLowerCase())).map(item => item.id);
                            setSelectedIds(filteredIds);
                          } else {
                            setSelectedIds([]);
                          }
                        }}
                      />
                    </th>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Operador</th>
                    <th className="px-6 py-4">Líquido</th>
                    <th className="px-6 py-4">Eco A</th>
                    <th className="px-6 py-4">Borra</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-xs font-bold">
                  {productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).map((e) => (
                    <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/50' : ''}`}>
                      <td className="px-6 py-4 w-10 no-print">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                          checked={selectedIds.includes(e.id)}
                          onChange={() => {
                            setSelectedIds(prev => prev.includes(e.id) ? prev.filter(id => id !== e.id) : [...prev, e.id]);
                          }}
                        />
                      </td>
                      <td className="px-6 py-4">{e.date}</td>
                      <td className="px-6 py-4">{e.operator}</td>
                      <td className="px-6 py-4">{e.netWeight} kg</td>
                      <td className="px-6 py-4 text-emerald-600">{e.ecoA} kg</td>
                      <td className="px-6 py-4 text-red-500">{e.borraTotal} kg</td>
                      <td className="px-6 py-4 text-right space-x-2">
                        <button onClick={() => { setEditingEntry(e); setIsModalOpen(true); }} className="text-blue-500 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={14} /></button>
                        <button onClick={() => handleDeleteEntry(e.id)} className="text-red-400 p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      <div className={`fixed inset-0 z-50 transition-all ${isMenuOpen ? 'visible' : 'invisible'}`}>
        <div className={`absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} onClick={() => setIsMenuOpen(false)} />
        <div className={`absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl transition-transform duration-300 transform p-8 flex flex-col gap-8 ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2"><Settings size={22} /> Ajustes</h2>
            <button onClick={() => setIsMenuOpen(false)} className="p-2 text-slate-400"><X size={24} /></button>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nova Meta Mensal (KG)</label>
              <input 
                type="number" 
                value={goalValue} 
                onChange={(e) => setGoalValue(parseFloat(e.target.value) || 0)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-black text-blue-600 outline-none" 
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Gerenciar Operadores</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  value={newOpName} 
                  onChange={e => setNewOpName(e.target.value)}
                  placeholder="Novo operador..."
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-4 py-2 text-xs font-bold" 
                />
                <button 
                  onClick={() => { if (newOpName && !operators.includes(newOpName)) { setOperators(prev => [...prev, newOpName]); setNewOpName(''); } }}
                  className="bg-blue-600 text-white p-3 rounded-2xl"
                >
                  <Plus size={18} />
                </button>
              </div>

              <div className="mt-2 max-h-48 overflow-y-auto custom-scrollbar space-y-2 pr-1">
                {operators.map((op, idx) => (
                  <div key={idx} className="flex items-center justify-between bg-slate-50 p-3 rounded-xl border border-slate-100 hover:border-blue-100 transition-colors group">
                    <span className="text-xs font-bold text-slate-600">{op}</span>
                    <button 
                      onClick={() => setOperators(prev => prev.filter(o => o !== op))}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                      title="Remover operador"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                ))}
                {operators.length === 0 && (
                  <p className="text-[10px] text-slate-400 text-center py-2">Nenhum operador cadastrado</p>
                )}
              </div>
            </div>

            <div className="pt-8 border-t border-slate-100 space-y-3">
              <button onClick={() => {
                const data = { productionData, shifts, goalValue, operators };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'backup_manupackaging.json';
                a.click();
              }} className="w-full flex items-center justify-center gap-3 bg-slate-100 py-4 rounded-2xl text-[10px] font-black uppercase text-slate-600"><Download size={16} /> Exportar Backup</button>

              <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 bg-blue-50 py-4 rounded-2xl text-[10px] font-black uppercase text-blue-600"><Upload size={16} /> Importar Backup</button>

              <button onClick={() => { localStorage.removeItem('manupackaging_session'); setIsAuthenticated(false); }} className="w-full flex items-center justify-center gap-3 bg-red-50 py-4 rounded-2xl text-[10px] font-black uppercase text-red-600"><LogOut size={16} /> Sair do Sistema</button>
            </div>
          </div>
        </div>
      </div>

      <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />

      <LaunchModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingEntry(null); }} 
        onSave={handleSaveEntry} 
        operators={operators} 
        activeMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        availableShifts={shifts} 
        initialData={editingEntry} 
      />

      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, Settings, BarChart3, FileText, Search, 
  Printer, ShieldCheck, Download, Upload, Trash2, Cpu, 
  Save, X, Edit2, LogOut, Calendar, CalendarDays, TrendingUp
} from 'lucide-react';
import { 
  Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { ProductionEntry, Shift } from './types';
import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.1;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'month' | 'day' | 'week'>('month');

  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    const saved = localStorage.getItem('manupackaging_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);

        // 1. Importar dados de produção
        if (data.productionData && Array.isArray(data.productionData)) {
          setProductionData(data.productionData);
        }

        // 2. Importar Metas e Turnos
        if (data.goalValue) setGoalValue(Number(data.goalValue));
        if (data.shifts && Array.isArray(data.shifts)) setShifts(data.shifts);

        // 3. Lógica inteligente para Operadores
        let importedOperators: string[] = [];

        // Caso A: Backup novo (lista simples de strings)
        if (data.operators && Array.isArray(data.operators)) {
          importedOperators = data.operators;
        }

        // Caso B: Backup antigo (lista de objetos 'employees')
        // Extraímos apenas o nome dos funcionários para manter a compatibilidade
        if (data.employees && Array.isArray(data.employees)) {
          const namesFromEmployees = data.employees
            .map((emp: any) => emp.name)
            .filter((name: any) => typeof name === 'string' && name.trim() !== '');

          // Combinamos com o que já foi achado em 'operators'
          importedOperators = [...importedOperators, ...namesFromEmployees];
        }

        // Atualizar estado de operadores removendo duplicatas
        if (importedOperators.length > 0) {
          const uniqueOperators = Array.from(new Set(importedOperators));
          setOperators(uniqueOperators);
        }

        alert('Backup carregado! Dados de produção e lista de operadores restaurados.');
      } catch (err) {
        console.error(err);
        alert('Erro ao processar o arquivo de backup. Verifique se o formato é válido.');
      }

      // Limpar o input para permitir selecionar o mesmo arquivo novamente se necessário
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    };
    reader.readAsText(file);
  };

  // --- NOVA LÓGICA DE EXCLUSÃO ---
  const handleDeleteEntry = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro permanentemente?')) {
      setProductionData(prev => prev.filter(item => item.id !== id));
      // Se estava selecionado, remove da seleção
      setSelectedIds(prev => prev.filter(selectedId => selectedId !== id));
    }
  };

  const handleBatchDelete = () => {
    if (selectedIds.length === 0) return;

    if (window.confirm(`Você está prestes a excluir ${selectedIds.length} registros. Confirmar exclusão?`)) {
      const idsToDelete = new Set(selectedIds);
      setProductionData(prev => prev.filter(item => !idsToDelete.has(item.id)));
      setSelectedIds([]); // Limpa a seleção
    }
  };
  // -------------------------------

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  // Filter logic based on the clickable cards
  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    const currentMonthStr = dayStr.substring(0, 7);

    // Logic for Week: From Sunday to Today
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay()); 

    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'month') return e.date.startsWith(currentMonthStr);
      if (selectedTimeframe === 'week') {
        const entryDate = new Date(e.date + 'T00:00:00');
        return entryDate >= startOfWeek;
      }
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const now = new Date();
    const todayStr = now.toLocaleDateString('sv-SE');
    const monthPrefix = now.toISOString().slice(0, 7);

    // Week start (Sunday)
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay());

    return productionData.reduce((acc, e) => {
      // Monthly Total
      if (e.date.startsWith(monthPrefix)) {
        acc.month += e.netWeight;
      }
      // Daily Total
      if (e.date === todayStr) {
        acc.day += e.netWeight;
      }
      // Weekly Total
      const entryDate = new Date(e.date + 'T00:00:00');
      if (entryDate >= startOfWeek) {
        acc.week += e.netWeight;
      }
      return acc;
    }, { month: 0, day: 0, week: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => { setEditingEntry(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-700 text-white font-black px-5 py-2.5 rounded-xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
          >
            <Plus size={16} /> Novo Lançamento
          </button>
          <button onClick={() => setIsMenuOpen(true)} className="p-2.5 text-slate-400 hover:bg-slate-100 rounded-xl transition-all">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto px-4 mt-6 no-print">
        <div className="bg-slate-200/50 p-1 rounded-2xl inline-flex gap-1 overflow-x-auto no-scrollbar max-w-full">
          {[
            { id: 'dashboard', icon: <BarChart3 size={14} />, label: 'Dashboard' },
            { id: 'reports', icon: <FileText size={14} />, label: 'Relatórios' }
          ].map((tab) => (
            <button 
              key={tab.id} 
              onClick={() => { 
                setActiveTab(tab.id as any);
                setSelectedIds([]); 
              }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-6xl mx-auto p-4 space-y-6">
        {activeTab === 'dashboard' ? (
          <div className="space-y-6">
            {/* Top Cards Section - Interativos */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              {/* Card Meta - Reseta para Visão Geral (Mês) */}
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all relative overflow-hidden group ${selectedTimeframe === 'month' ? 'bg-blue-600 text-white shadow-xl shadow-blue-200 border-blue-500' : 'bg-white text-slate-800 border-slate-100 hover:border-blue-200'}`}
              >
                <div className="flex justify-between items-start mb-4 relative z-10">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'month' ? 'bg-white/20 text-white' : 'bg-blue-50 text-blue-600'}`}>
                    <TrendingUp size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>Meta do Mês</span>
                </div>
                <div className="relative z-10">
                  <div className="text-2xl font-black mb-1">{(totals.month / 1000).toFixed(1)} T</div>
                  <div className="w-full bg-black/10 h-1.5 rounded-full overflow-hidden">
                    <div className={`h-full rounded-full ${selectedTimeframe === 'month' ? 'bg-white' : 'bg-blue-600'}`} style={{ width: `${Math.min((totals.month / (goalValue || 1)) * 100, 100)}%` }}></div>
                  </div>
                  <div className={`text-[9px] font-bold mt-2 ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>
                    {totals.month >= goalValue 
                      ? 'Meta atingida! 🚀' 
                      : `Faltam ${formatWeight(goalValue - totals.month)} para a meta`}
                  </div>
                </div>
              </button>

              {/* Card Hoje */}
              <button 
                onClick={() => setSelectedTimeframe('day')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'day' ? 'bg-emerald-500 text-white shadow-xl shadow-emerald-200 border-emerald-400' : 'bg-white text-slate-800 border-slate-100 hover:border-emerald-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'day' ? 'bg-white/20 text-white' : 'bg-emerald-50 text-emerald-600'}`}>
                    <Calendar size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Hoje</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.day)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Produção do dia</p>
                </div>
              </button>

              {/* Card Semana */}
              <button 
                onClick={() => setSelectedTimeframe('week')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'week' ? 'bg-violet-500 text-white shadow-xl shadow-violet-200 border-violet-400' : 'bg-white text-slate-800 border-slate-100 hover:border-violet-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'week' ? 'bg-white/20 text-white' : 'bg-violet-50 text-violet-600'}`}>
                    <CalendarDays size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Esta Semana</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.week)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Dom - Sáb</p>
                </div>
              </button>

              {/* Card Mês (Estatística Pura) */}
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'month' ? 'ring-2 ring-blue-500 ring-offset-2' : 'bg-white hover:border-blue-200 border-slate-100'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className="p-2 rounded-xl bg-orange-50 text-orange-600">
                    <BarChart3 size={18} />
                  </div>
                  <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Este Mês</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1 text-slate-800">{formatWeight(totals.month)}</div>
                  <p className="text-[9px] font-bold text-slate-400">Acumulado mensal</p>
                </div>
              </button>
            </div>

            {/* Header do Gráfico dinâmico */}
            <div className="flex items-center gap-2 px-2">
              <span className="w-2 h-2 rounded-full bg-slate-300"></span>
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                Visualizando dados: <span className="text-blue-600">{
                  selectedTimeframe === 'day' ? 'Hoje' : 
                  selectedTimeframe === 'week' ? 'Esta Semana' : 
                  'Mês Atual'
                }</span>
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight },
                { title: '♻️ Eco B Manutenção', key: 'ecoBM', color: ['#8b5cf6', '#a78bfa', '#c4b5fd'], formatter: formatWeight },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes },
                { title: '📊 Líquido vs Eco B', key: 'comparison_prod_ecob', color: ['#3b82f6', '#8b5cf6'], formatter: formatWeight }
              ].map((chart, idx) => {
                let chartData: any[] = [];
                let dataKey = chart.key;

                if (chart.key === 'comparison_prod_ecob') {
                  const totalProd = filteredDataForCharts.reduce((acc, c) => acc + (c.netWeight || 0), 0);
                  const totalEcoB = filteredDataForCharts.reduce((acc, c) => acc + (c.ecoBP || 0) + (c.ecoBM || 0), 0);
                  chartData = [
                    { name: 'Produção', value: totalProd },
                    { name: 'Eco B', value: totalEcoB }
                  ].filter(d => d.value > 0);
                  dataKey = 'value';
                } else {
                  chartData = stats.filter(s => s[chart.key as keyof OperatorStat] > 0);
                }

                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-[400px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
                    <div className="flex-1">
                      {chartData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                          <PieChart>
                            <Pie 
                              data={chartData} 
                              cx="50%" 
                              cy="50%" 
                              innerRadius={60} 
                              outerRadius={85} 
                              dataKey={dataKey} 
                              nameKey="name" 
                              label={renderCustomizedLabel}
                              paddingAngle={2}
                            >
                              {chartData.map((_, i) => <Cell key={i} fill={chart.color[i % chart.color.length]} stroke="none" />)}
                            </Pie>
                            <Tooltip formatter={(val: any) => chart.formatter(val)} />
                            <Legend iconType="circle" />
                          </PieChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="h-full flex items-center justify-center text-slate-300 font-bold text-xs uppercase">Sem dados neste período</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex items-center justify-between gap-4">
              <div className="relative flex-1 max-md">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                <input 
                  type="text" 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)}
                  placeholder="Pesquisar registros..." 
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none" 
                />
              </div>
              <div className="flex items-center gap-2 no-print">
                {selectedIds.length > 0 && (
                  <button 
                    onClick={handleBatchDelete} 
                    className="flex items-center gap-2 px-4 py-2.5 bg-red-50 text-red-600 rounded-xl text-[10px] font-black uppercase hover:bg-red-100 transition-all animate-in fade-in"
                  >
                    <Trash2 size={16} /> Excluir ({selectedIds.length})
                  </button>
                )}
                <button onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[600px]">
                <thead>
                  <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4 w-10 no-print">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                        checked={selectedIds.length > 0 && selectedIds.length === productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).length}
                        onChange={(ev) => {
                          if (ev.target.checked) {
                            const filteredIds = productionData.filter(item => item.operator.toLowerCase().includes(searchTerm.toLowerCase())).map(item => item.id);
                            setSelectedIds(filteredIds);
                          } else {
                            setSelectedIds([]);
                          }
                        }}
                      />
                    </th>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Operador</th>
                    <th className="px-6 py-4">Líquido</th>
                    <th className="px-6 py-4">Eco A</th>
                    <th className="px-6 py-4">Borra</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-xs font-bold">
                  {productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).map((e) => (
                    <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/50' : ''}`}>
                      <td className="px-6 py-4 w-10 no-print">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                          checked={selectedIds.includes(e.id)}
                          onChange={() => {
                            setSelectedIds(prev => prev.includes(e.id) ? prev.filter(id => id !== e.id) : [...prev, e.id]);
                          }}
                        />
                      </td>
                      <td className="px-6 py-4">{e.date}</td>
                      <td className="px-6 py-4">{e.operator}</td>
                      <td className="px-6 py-4">{e.netWeight} kg</td>
                      <td className="px-6 py-4 text-emerald-600">{e.ecoA} kg</td>
                      <td className="px-6 py-4 text-red-500">{e.borraTotal} kg</td>
                      <td className="px-6 py-4 text-right space-x-2">
                        <button onClick={() => { setEditingEntry(e); setIsModalOpen(true); }} className="text-blue-500 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={14} /></button>
                        <button onClick={() => handleDeleteEntry(e.id)} className="text-red-400 p-1.5 hover:bg-red-50 rounded-lg"><Trash2 size={14} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      <div className={`fixed inset-0 z-50 transition-all ${isMenuOpen ? 'visible' : 'invisible'}`}>
        <div className={`absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity ${isMenuOpen ? 'opacity-100' : 'opacity-0'}`} onClick={() => setIsMenuOpen(false)} />
        <div className={`absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl transition-transform duration-300 transform p-8 flex flex-col gap-8 ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="flex items-center justify-between">
            <h2 className="text-xl font-black text-slate-800 flex items-center gap-2"><Settings size={22} /> Ajustes</h2>
            <button onClick={() => setIsMenuOpen(false)} className="p-2 text-slate-400"><X size={24} /></button>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nova Meta Mensal (KG)</label>
              <input 
                type="number" 
                value={goalValue} 
                onChange={(e) => setGoalValue(parseFloat(e.target.value) || 0)}
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 text-sm font-black text-blue-600 outline-none" 
              />
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Gerenciar Operadores</label>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  value={newOpName} 
                  onChange={e => setNewOpName(e.target.value)}
                  placeholder="Novo operador..."
                  className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-4 py-2 text-xs font-bold" 
                />
                <button 
                  onClick={() => { if (newOpName && !operators.includes(newOpName)) { setOperators(prev => [...prev, newOpName]); setNewOpName(''); } }}
                  className="bg-blue-600 text-white p-3 rounded-2xl"
                >
                  <Plus size={18} />
                </button>
              </div>

              <div className="mt-2 max-h-48 overflow-y-auto custom-scrollbar space-y-2 pr-1">
                {operators.map((op, idx) => (
                  <div key={idx} className="flex items-center justify-between bg-slate-50 p-3 rounded-xl border border-slate-100 hover:border-blue-100 transition-colors group">
                    <span className="text-xs font-bold text-slate-600">{op}</span>
                    <button 
                      onClick={() => setOperators(prev => prev.filter(o => o !== op))}
                      className="text-slate-300 hover:text-red-500 transition-colors p-1"
                      title="Remover operador"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                ))}
                {operators.length === 0 && (
                  <p className="text-[10px] text-slate-400 text-center py-2">Nenhum operador cadastrado</p>
                )}
              </div>
            </div>

            <div className="pt-8 border-t border-slate-100 space-y-3">
              <button onClick={() => {
                const data = { productionData, shifts, goalValue, operators };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'backup_manupackaging.json';
                a.click();
              }} className="w-full flex items-center justify-center gap-3 bg-slate-100 py-4 rounded-2xl text-[10px] font-black uppercase text-slate-600"><Download size={16} /> Exportar Backup</button>

              <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 bg-blue-50 py-4 rounded-2xl text-[10px] font-black uppercase text-blue-600"><Upload size={16} /> Importar Backup</button>

              <button onClick={() => { localStorage.removeItem('manupackaging_session'); setIsAuthenticated(false); }} className="w-full flex items-center justify-center gap-3 bg-red-50 py-4 rounded-2xl text-[10px] font-black uppercase text-red-600"><LogOut size={16} /> Sair do Sistema</button>
            </div>
          </div>
        </div>
      </div>

      <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />

      <LaunchModal 
        isOpen={isModalOpen} 
        onClose={() => { setIsModalOpen(false); setEditingEntry(null); }} 
        onSave={handleSaveEntry} 
        operators={operators} 
        activeMachines={['Cast 1', 'Cast 2', 'Erema 1']} 
        availableShifts={shifts} 
        initialData={editingEntry} 
      />

      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, Settings, BarChart3, FileText, Search, 
  Printer, ShieldCheck, Download, Upload, Trash2, Cpu, 
  Save, X, Edit2, LogOut, Calendar, CalendarDays, TrendingUp
} from 'lucide-react';
import { 
  Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { ProductionEntry, Shift } from './types';
import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.1;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'month' | 'day' | 'week'>('month');

  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    const saved = localStorage.getItem('manupackaging_data');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);

        // 1. Importar dados de produção
        if (data.productionData && Array.isArray(data.productionData)) {
          setProductionData(data.productionData);
        }

        // 2. Importar Metas e Turnos
        if (data.goalValue) setGoalValue(Number(data.goalValue));
        if (data.shifts && Array.isArray(data.shifts)) setShifts(data.shifts);

        // 3. Lógica inteligente para Operadores
        let importedOperators: string[] = [];

        // Caso A: Backup novo (lista simples de strings)
        if (data.operators && Array.isArray(data.operators)) {
          importedOperators = data.operators;
        }

        // Caso B: Backup antigo (lista de objetos 'employees')
        // Extraímos apenas o nome dos funcionários para manter a compatibilidade
        if (data.employees && Array.isArray(data.employees)) {
          const namesFromEmployees = data.employees
            .map((emp: any) => emp.name)
            .filter((name: any) => typeof name === 'string' && name.trim() !== '');

          // Combinamos com o que já foi achado em 'operators'
          importedOperators = [...importedOperators, ...namesFromEmployees];
        }

        // Atualizar estado de operadores removendo duplicatas
        if (importedOperators.length > 0) {
          const uniqueOperators = Array.from(new Set(importedOperators));
          setOperators(uniqueOperators);
        }

        alert('Backup carregado! Dados de produção e lista de operadores restaurados.');
      } catch (err) {
        console.error(err);
        alert('Erro ao processar o arquivo de backup. Verifique se o formato é válido.');
      }

      // Limpar o input para permitir selecionar o mesmo arquivo novamente se necessário
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    };
    reader.readAsText(file);
  };

  // --- NOVA LÓGICA DE EXCLUSÃO ---
  const handleDeleteEntry = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro permanentemente?')) {
      setProductionData(prev => prev.filter(item => item.id !== id));
      // Se estava selecionado, remove da seleção
      setSelectedIds(prev => prev.filter(selectedId => selectedId !== id));
    }
  };

  const handleBatchDelete = () => {
    if (selectedIds.length === 0) return;

    if (window.confirm(`Você está prestes a excluir ${selectedIds.length} registros. Confirmar exclusão?`)) {
      const idsToDelete = new Set(selectedIds);
      setProductionData(prev => prev.filter(item => !idsToDelete.has(item.id)));
      setSelectedIds([]); // Limpa a seleção
    }
  };
  // -------------------------------

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  // Filter logic based on the clickable cards
  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    const currentMonthStr = dayStr.substring(0, 7);

    // Logic for Week: From Sunday to Today
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay()); 

    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'month') return e.date.startsWith(currentMonthStr);
      if (selectedTimeframe === 'week') {
        const entryDate = new Date(e.date + 'T00:00:00');
        return entryDate >= startOfWeek;
      }
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const now = new Date();
    const todayStr = now.toLocaleDateString('sv-SE');
    const monthPrefix = now.toISOString().slice(0, 7);

    // Week start (Sunday)
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay());

    return productionData.reduce((acc, e) => {
      // Monthly Total
      if (e.date.startsWith(monthPrefix)) {
        acc.month += e.netWeight;
      }
      // Daily Total
      if (e.date === todayStr) {
        acc.day += e.netWeight;
      }
      // Weekly Total
      const entryDate = new Date(e.date + 'T00:00:00');
      if (entryDate >= startOfWeek) {
        acc.week += e.netWeight;
      }
      return acc;
    }, { month: 0, day: 0, week: 0 });
