                            <Pie 
                              data={chartData} 
                              cx="50%" 
                              cy="50%" 
                              innerRadius={60} 
                              outerRadius={85} 
                              dataKey={dataKey} 
                              nameKey="name" 
                              label={renderCustomizedLabel}
                              paddingAngle={2}
                            >
