                )}
                <button onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[600px]">
                <thead>
                  <tr className="bg-slate-50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-6 py-4 w-10 no-print">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                        checked={selectedIds.length > 0 && selectedIds.length === productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).length}
                        onChange={(ev) => {
                          if (ev.target.checked) {
                            const filteredIds = productionData.filter(item => item.operator.toLowerCase().includes(searchTerm.toLowerCase())).map(item => item.id);
                            setSelectedIds(filteredIds);
                          } else {
                            setSelectedIds([]);
                          }
                        }}
                      />
                    </th>
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Operador</th>
                    <th className="px-6 py-4">Líquido</th>
                    <th className="px-6 py-4">Eco A</th>
                    <th className="px-6 py-4">Borra</th>
                    <th className="px-6 py-4 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-xs font-bold">
                  {productionData.filter(e => e.operator.toLowerCase().includes(searchTerm.toLowerCase())).map((e) => (
                    <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/50' : ''}`}>
                      <td className="px-6 py-4 w-10 no-print">
                        <input 
                          type="checkbox" 
                          className="w-4 h-4 rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                          checked={selectedIds.includes(e.id)}
                          onChange={() => {
                            setSelectedIds(prev => prev.includes(e.id) ? prev.filter(id => id !== e.id) : [...prev, e.id]);
                          }}
