                      <td className="px-6 py-4 text-right space-x-2">
                        <button onClick={() => { setEditingEntry(e); setIsModalOpen(true); }} className="text-blue-500 p-1.5 hover:bg-blue-50 rounded-lg"><Edit2 size={14} /></button>
