import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.25;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'month' | 'day' | 'week'>('month');

  // Inicialização robusta: Garante que todos os itens tenham ID, mesmo dados antigos do localStorage
  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    try {
      const saved = localStorage.getItem('manupackaging_data');
      let data = saved ? JSON.parse(saved) : INITIAL_DATA;

      if (Array.isArray(data)) {
        // Migração de dados: Adiciona ID se faltar
        data = data.map((item: any) => ({
          ...item,
          id: item.id || Math.random().toString(36).substr(2, 9)
        }));
      }
      return data;
    } catch (e) {
      console.error("Erro ao carregar dados", e);
      return INITIAL_DATA;
    }
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  // Função de exclusão de relatório
  const handleDeleteReportItem = (id: string) => {
    if (!id) {
      alert("Erro: Item sem ID identificado.");
      return;
    }

    // Confirmação nativa do navegador
    if (window.confirm('TEM CERTEZA? \nDeseja realmente excluir este registro do relatório?')) {
      // Atualiza o estado removendo o item
      setProductionData(prevData => prevData.filter(item => item.id !== id));
      setSelectedIds(prev => prev.filter(sid => sid !== id));
    }
  };

  const handleDeleteSelected = () => {
    if (selectedIds.length === 0) return;
    if (window.confirm(`TEM CERTEZA? \nDeseja excluir os ${selectedIds.length} registros selecionados?`)) {
      setProductionData(prev => prev.filter(item => !selectedIds.includes(item.id)));
      setSelectedIds([]);
    }
  };

  const toggleSelectAll = (filtered: ProductionEntry[]) => {
    if (selectedIds.length === filtered.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filtered.map(i => i.id));
    }
  };

  const toggleSelectId = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.productionData && Array.isArray(data.productionData)) {
          // Sanitização na importação também
          const sanitizedData = data.productionData.map((item: any) => ({
            ...item,
            id: item.id || Math.random().toString(36).substr(2, 9)
          }));
          setProductionData(sanitizedData);
        }
        if (data.goalValue) setGoalValue(Number(data.goalValue));
        if (data.shifts && Array.isArray(data.shifts)) setShifts(data.shifts);

        let importedOperators: string[] = [];
        if (data.operators && Array.isArray(data.operators)) {
          importedOperators = data.operators;
        }
        if (data.employees && Array.isArray(data.employees)) {
          const namesFromEmployees = data.employees
            .map((emp: any) => emp.name)
            .filter((name: any) => typeof name === 'string' && name.trim() !== '');
          importedOperators = [...importedOperators, ...namesFromEmployees];
        }
        if (importedOperators.length > 0) {
          const uniqueOperators = Array.from(new Set(importedOperators));
          setOperators(uniqueOperators);
        }
        alert('Backup carregado com sucesso!');
      } catch (err) {
        console.error(err);
        alert('Erro ao processar o arquivo de backup.');
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  const getShiftDuration = (shiftName: string) => {
    const shift = shifts.find(s => s.name === shiftName);
    if (!shift) return 720;
    const [h1, m1] = shift.startTime.split(':').map(Number);
    const [h2, m2] = shift.endTime.split(':').map(Number);
    let minutes = (h2 * 60 + m2) - (h1 * 60 + m1);
    if (minutes < 0) minutes += 1440;
    return minutes === 0 ? 1440 : minutes;
  };

  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    const currentMonthStr = dayStr.substring(0, 7);
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay()); 

    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'month') return e.date.startsWith(currentMonthStr);
      if (selectedTimeframe === 'week') {
        const entryDate = new Date(e.date + 'T00:00:00');
        return entryDate >= startOfWeek;
      }
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const filteredReports = useMemo(() => {
    return productionData.filter(e => 
      e.operator.toLowerCase().includes(searchTerm.toLowerCase()) ||
      e.machine.toLowerCase().includes(searchTerm.toLowerCase()) ||
      e.date.includes(searchTerm)
    );
  }, [productionData, searchTerm]);

  const reportSums = useMemo(() => {
    return filteredReports.reduce((acc, e) => {
      acc.grossWeight += (e.grossWeight || 0);
      acc.tara += (e.tara || 0);
      acc.netWeight += (e.netWeight || 0);
      acc.volumes += (e.volumes || 0);
      acc.tubetes += (e.tubetes || 0);
      acc.ecoA += (e.ecoA || 0);
      acc.ecoBP += (e.ecoBP || 0);
      acc.ecoBM += (e.ecoBM || 0);
      acc.borraTotal += (e.borraTotal || 0);
      acc.manutencaoMin += (e.manutencaoMin || 0);
      acc.processoMin += (e.processoMin || 0);
      acc.outrosMin += (e.outrosMin || 0);
      return acc;
    }, {
      grossWeight: 0, tara: 0, netWeight: 0, volumes: 0, tubetes: 0,
      ecoA: 0, ecoBP: 0, ecoBM: 0, borraTotal: 0, manutencaoMin: 0, processoMin: 0, outrosMin: 0
    });
  }, [filteredReports]);

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const now = new Date();
    const todayStr = now.toLocaleDateString('sv-SE');
    const monthPrefix = now.toISOString().slice(0, 7);
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay());

    return productionData.reduce((acc, e) => {
      if (e.date.startsWith(monthPrefix)) acc.month += e.netWeight;
      if (e.date === todayStr) acc.day += e.netWeight;
      const entryDate = new Date(e.date + 'T00:00:00');
      if (entryDate >= startOfWeek) acc.week += e.netWeight;
      return acc;
    }, { month: 0, day: 0, week: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
