import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Plus, Settings, BarChart3, FileText, Search, 
  Printer, ShieldCheck, Download, Upload, Trash2, Cpu, 
  Save, X, Edit2, LogOut, Calendar, CalendarDays, TrendingUp, AlertTriangle, CheckSquare, Square, FileSpreadsheet
} from 'lucide-react';
import { 
  Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend 
} from 'recharts';
import { ProductionEntry, Shift } from './types';
import { INITIAL_DATA, GOAL_VALUE as DEFAULT_GOAL, DEFAULT_OPERATORS } from './constants';
import LaunchModal from './components/LaunchModal';
import ShiftModal from './components/ShiftModal';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4', '#f97316', '#64748b'];

const renderCustomizedLabel = ({ cx, cy, midAngle, innerRadius, outerRadius, percent }: any) => {
  if (!percent || percent < 0.01) return null;
  const RADIAN = Math.PI / 180;
  const radius = outerRadius * 1.25;
  const x = cx + radius * Math.cos(-midAngle * RADIAN);
  const y = cy + radius * Math.sin(-midAngle * RADIAN);
  return (
    <text x={x} y={y} fill="#64748b" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central" className="text-[10px] font-black">
      {`${(percent * 100).toFixed(1)}%`}
    </text>
  );
};

interface OperatorStat {
  name: string;
  prod: number;
  ecoA: number;
  ecoBP: number;
  ecoBM: number;
  borra: number;
  p_manut: number;
  p_proc: number;
  p_outros: number;
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(() => !!localStorage.getItem('manupackaging_session'));
  const [activeTab, setActiveTab] = useState<'dashboard' | 'reports'>('dashboard');
  const [selectedTimeframe, setSelectedTimeframe] = useState<'month' | 'day' | 'week'>('month');

  // Inicialização robusta: Garante que todos os itens tenham ID, mesmo dados antigos do localStorage
  const [productionData, setProductionData] = useState<ProductionEntry[]>(() => {
    try {
      const saved = localStorage.getItem('manupackaging_data');
      let data = saved ? JSON.parse(saved) : INITIAL_DATA;

      if (Array.isArray(data)) {
        // Migração de dados: Adiciona ID se faltar
        data = data.map((item: any) => ({
          ...item,
          id: item.id || Math.random().toString(36).substr(2, 9)
        }));
      }
      return data;
    } catch (e) {
      console.error("Erro ao carregar dados", e);
      return INITIAL_DATA;
    }
  });

  const [goalValue, setGoalValue] = useState<number>(() => {
    const saved = localStorage.getItem('manupackaging_goal');
    return saved ? parseFloat(saved) : DEFAULT_GOAL;
  });

  const [operators, setOperators] = useState<string[]>(() => {
    const saved = localStorage.getItem('manupackaging_operators');
    return saved ? JSON.parse(saved) : DEFAULT_OPERATORS;
  });

  const [shifts, setShifts] = useState<Shift[]>(() => {
    const saved = localStorage.getItem('manupackaging_shifts');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Diurno 1', startTime: '07:00', endTime: '19:00', type: 'Diurno' },
      { id: '2', name: 'Noturno 1', startTime: '19:00', endTime: '07:00', type: 'Noturno' }
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isShiftModalOpen, setIsShiftModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<ProductionEntry | null>(null);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  const [newOpName, setNewOpName] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('manupackaging_data', JSON.stringify(productionData)); }, [productionData]);
  useEffect(() => { localStorage.setItem('manupackaging_shifts', JSON.stringify(shifts)); }, [shifts]);
  useEffect(() => { localStorage.setItem('manupackaging_goal', goalValue.toString()); }, [goalValue]);
  useEffect(() => { localStorage.setItem('manupackaging_operators', JSON.stringify(operators)); }, [operators]);

  const handleSaveEntry = (newEntry: Omit<ProductionEntry, 'id'> & { id?: string }) => {
    if (newEntry.id) {
      setProductionData(prev => prev.map(e => e.id === newEntry.id ? (newEntry as ProductionEntry) : e));
    } else {
      setProductionData(prev => [{ ...newEntry, id: Math.random().toString(36).substr(2, 9) } as ProductionEntry, ...prev]);
    }
  };

  // Função de exclusão de relatório
  const handleDeleteReportItem = (id: string) => {
    if (!id) {
      alert("Erro: Item sem ID identificado.");
      return;
    }

    // Confirmação nativa do navegador
    if (window.confirm('TEM CERTEZA? \nDeseja realmente excluir este registro do relatório?')) {
      // Atualiza o estado removendo o item
      setProductionData(prevData => prevData.filter(item => item.id !== id));
      setSelectedIds(prev => prev.filter(sid => sid !== id));
    }
  };

  const handleDeleteSelected = () => {
    if (selectedIds.length === 0) return;
    if (window.confirm(`TEM CERTEZA? \nDeseja excluir os ${selectedIds.length} registros selecionados?`)) {
      setProductionData(prev => prev.filter(item => !selectedIds.includes(item.id)));
      setSelectedIds([]);
    }
  };

  const toggleSelectAll = (filtered: ProductionEntry[]) => {
    if (selectedIds.length === filtered.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filtered.map(i => i.id));
    }
  };

  const toggleSelectId = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.productionData && Array.isArray(data.productionData)) {
          // Sanitização na importação também
          const sanitizedData = data.productionData.map((item: any) => ({
            ...item,
            id: item.id || Math.random().toString(36).substr(2, 9)
          }));
          setProductionData(sanitizedData);
        }
        if (data.goalValue) setGoalValue(Number(data.goalValue));
        if (data.shifts && Array.isArray(data.shifts)) setShifts(data.shifts);

        let importedOperators: string[] = [];
        if (data.operators && Array.isArray(data.operators)) {
          importedOperators = data.operators;
        }
        if (data.employees && Array.isArray(data.employees)) {
          const namesFromEmployees = data.employees
            .map((emp: any) => emp.name)
            .filter((name: any) => typeof name === 'string' && name.trim() !== '');
          importedOperators = [...importedOperators, ...namesFromEmployees];
        }
        if (importedOperators.length > 0) {
          const uniqueOperators = Array.from(new Set(importedOperators));
          setOperators(uniqueOperators);
        }
        alert('Backup carregado com sucesso!');
      } catch (err) {
        console.error(err);
        alert('Erro ao processar o arquivo de backup.');
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsText(file);
  };

  const formatWeight = (val: number) => val >= 1000 ? (val / 1000).toFixed(1) + ' T' : val.toLocaleString() + ' KG';
  const formatMinutes = (val: number) => val >= 60 ? `${Math.floor(val / 60)}h ${val % 60}m` : `${val} min`;

  const getShiftDuration = (shiftName: string) => {
    const shift = shifts.find(s => s.name === shiftName);
    if (!shift) return 720;
    const [h1, m1] = shift.startTime.split(':').map(Number);
    const [h2, m2] = shift.endTime.split(':').map(Number);
    let minutes = (h2 * 60 + m2) - (h1 * 60 + m1);
    if (minutes < 0) minutes += 1440;
    return minutes === 0 ? 1440 : minutes;
  };

  const filteredDataForCharts = useMemo(() => {
    const now = new Date();
    const dayStr = now.toLocaleDateString('sv-SE');
    const currentMonthStr = dayStr.substring(0, 7);
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay()); 

    return productionData.filter(e => {
      if (selectedTimeframe === 'day') return e.date === dayStr;
      if (selectedTimeframe === 'month') return e.date.startsWith(currentMonthStr);
      if (selectedTimeframe === 'week') {
        const entryDate = new Date(e.date + 'T00:00:00');
        return entryDate >= startOfWeek;
      }
      return true;
    });
  }, [productionData, selectedTimeframe]);

  const filteredReports = useMemo(() => {
    return productionData.filter(e => {
      const matchesSearch = e.operator.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            e.machine.toLowerCase().includes(searchTerm.toLowerCase()) ||
                            e.date.includes(searchTerm);

      const matchesStart = filterStartDate ? e.date >= filterStartDate : true;
      const matchesEnd = filterEndDate ? e.date <= filterEndDate : true;

      return matchesSearch && matchesStart && matchesEnd;
    });
  }, [productionData, searchTerm, filterStartDate, filterEndDate]);

  const reportSums = useMemo(() => {
    return filteredReports.reduce((acc, e) => {
      acc.grossWeight += (e.grossWeight || 0);
      acc.tara += (e.tara || 0);
      acc.netWeight += (e.netWeight || 0);
      acc.volumes += (e.volumes || 0);
      acc.tubetes += (e.tubetes || 0);
      acc.ecoA += (e.ecoA || 0);
      acc.ecoBP += (e.ecoBP || 0);
      acc.ecoBM += (e.ecoBM || 0);
      acc.borraTotal += (e.borraTotal || 0);
      acc.manutencaoMin += (e.manutencaoMin || 0);
      acc.processoMin += (e.processoMin || 0);
      acc.outrosMin += (e.outrosMin || 0);
      return acc;
    }, {
      grossWeight: 0, tara: 0, netWeight: 0, volumes: 0, tubetes: 0,
      ecoA: 0, ecoBP: 0, ecoBM: 0, borraTotal: 0, manutencaoMin: 0, processoMin: 0, outrosMin: 0
    });
  }, [filteredReports]);

  const handleExportCSV = () => {
    if (filteredReports.length === 0) return;

    const headers = [
      'Data', 'Operador', 'Maquina', 'Turno', 'Peso Bruto', 'Tara', 'Peso Liquido', 
      'Volumes', 'Tubetes', 'Eco A', 'Eco B (P)', 'Eco B (M)', 'Borra Total', 
      'Manut (Min)', 'Proc (Min)', 'Outros (Min)'
    ];

    const rows = filteredReports.map(e => [
      e.date,
      e.operator,
      e.machine.toUpperCase(),
      e.shift,
      e.grossWeight,
      e.tara,
      e.netWeight,
      e.volumes,
      e.tubetes,
      e.ecoA,
      e.ecoBP,
      e.ecoBM,
      e.borraTotal,
      e.manutencaoMin,
      e.processoMin,
      e.outrosMin
    ]);

    // Linha de totais
    const totalRow = [
      'TOTAIS', '', '', '', 
      reportSums.grossWeight, reportSums.tara, reportSums.netWeight, 
      reportSums.volumes, reportSums.tubetes, reportSums.ecoA, 
      reportSums.ecoBP, reportSums.ecoBM, reportSums.borraTotal, 
      reportSums.manutencaoMin, reportSums.processoMin, reportSums.outrosMin
    ];

    const csvContent = [headers, ...rows, totalRow]
      .map(row => row.join(';'))
      .join('\n');

    const blob = new Blob(['\uFEFF' + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `relatorio_producao_${new Date().toLocaleDateString('sv-SE')}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const stats = useMemo(() => {
    const initialStats: Record<string, OperatorStat> = {};
    operators.forEach(op => {
      initialStats[op] = { name: op, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
    });

    filteredDataForCharts.forEach(e => {
      if (!initialStats[e.operator]) {
        initialStats[e.operator] = { name: e.operator, prod: 0, ecoA: 0, ecoBP: 0, ecoBM: 0, borra: 0, p_manut: 0, p_proc: 0, p_outros: 0 };
      }
      initialStats[e.operator].prod += (e.netWeight || 0);
      initialStats[e.operator].ecoA += (e.ecoA || 0);
      initialStats[e.operator].ecoBP += (e.ecoBP || 0);
      initialStats[e.operator].ecoBM += (e.ecoBM || 0);
      initialStats[e.operator].borra += (e.borraTotal || 0);
      initialStats[e.operator].p_manut += (e.manutencaoMin || 0);
      initialStats[e.operator].p_proc += (e.processoMin || 0);
      initialStats[e.operator].p_outros += (e.outrosMin || 0);
    });

    return Object.values(initialStats);
  }, [filteredDataForCharts, operators]);

  const totals = useMemo(() => {
    const now = new Date();
    const todayStr = now.toLocaleDateString('sv-SE');
    const monthPrefix = now.toISOString().slice(0, 7);
    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay());

    return productionData.reduce((acc, e) => {
      if (e.date.startsWith(monthPrefix)) acc.month += e.netWeight;
      if (e.date === todayStr) acc.day += e.netWeight;
      const entryDate = new Date(e.date + 'T00:00:00');
      if (entryDate >= startOfWeek) acc.week += e.netWeight;
      return acc;
    }, { month: 0, day: 0, week: 0 });
  }, [productionData]);

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white rounded-3xl p-8 w-full max-w-md shadow-2xl space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center text-white mx-auto shadow-lg mb-4">
              <ShieldCheck size={32} />
            </div>
            <h1 className="text-2xl font-black text-slate-800">Manupackaging</h1>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">Painel de Acesso</p>
          </div>
          <button 
            onClick={() => { localStorage.setItem('manupackaging_session', 'true'); setIsAuthenticated(true); }}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-blue-200 uppercase text-xs"
          >
            Entrar no Sistema
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-24">
      <header className="bg-white px-6 py-4 flex items-center justify-between sticky top-0 z-40 border-b border-slate-100 no-print">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg">
            <Cpu size={20} />
          </div>
          <h1 className="text-lg font-black text-slate-800 tracking-tighter uppercase">Controle de Produção</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={() => { setEditingEntry(null); setIsModalOpen(true); }}
            className="bg-blue-600 hover:bg-blue-700 text-white font-black px-5 py-2.5 rounded-xl text-[10px] flex items-center gap-2 shadow-lg shadow-blue-100 transition-all uppercase"
          >
            <Plus size={16} /> Novo Lançamento
          </button>
          <button onClick={() => setIsMenuOpen(true)} className="p-2.5 text-slate-400 hover:bg-slate-100 rounded-xl transition-all">
            <Settings size={20} />
          </button>
        </div>
      </header>

      <div className="max-w-6xl mx-auto px-4 mt-6 no-print">
        <div className="bg-slate-200/50 p-1 rounded-2xl inline-flex gap-1 overflow-x-auto no-scrollbar max-w-full">
          {[
            { id: 'dashboard', icon: <BarChart3 size={14} />, label: 'Dashboard' },
            { id: 'reports', icon: <FileText size={14} />, label: 'Relatórios' }
          ].map((tab) => (
            <button 
              key={tab.id} 
              onClick={() => { setActiveTab(tab.id as any); }}
              className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${activeTab === tab.id ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
            >
              {tab.icon} {tab.label}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-[100vw] mx-auto p-4 space-y-6 overflow-x-hidden">
        {activeTab === 'dashboard' ? (
          <div className="space-y-6 max-w-6xl mx-auto">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              <button 
                onClick={() => setSelectedTimeframe('month')}
                className={`text-left p-5 rounded-3xl border transition-all relative overflow-hidden group ${selectedTimeframe === 'month' ? 'bg-blue-600 text-white shadow-xl shadow-blue-200 border-blue-500' : 'bg-white text-slate-800 border-slate-100 hover:border-blue-200'}`}
              >
                <div className="flex justify-between items-start mb-4 relative z-10">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'month' ? 'bg-white/20 text-white' : 'bg-blue-50 text-blue-600'}`}>
                    <TrendingUp size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>Meta do Mês</span>
                </div>
                <div className="relative z-10">
                  <div className="text-2xl font-black mb-1">{(totals.month / 1000).toFixed(1)} T</div>
                  <div className="w-full bg-black/10 h-1.5 rounded-full overflow-hidden">
                    <div className={`h-full rounded-full ${selectedTimeframe === 'month' ? 'bg-white' : 'bg-blue-600'}`} style={{ width: `${Math.min((totals.month / (goalValue || 1)) * 100, 100)}%` }}></div>
                  </div>
                  <div className={`text-[9px] font-bold mt-2 ${selectedTimeframe === 'month' ? 'text-blue-100' : 'text-slate-400'}`}>
                    {totals.month >= goalValue ? 'Meta atingida! 🚀' : `Faltam ${formatWeight(goalValue - totals.month)} para a meta`}
                  </div>
                </div>
              </button>

              <button 
                onClick={() => setSelectedTimeframe('day')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'day' ? 'bg-emerald-500 text-white shadow-xl shadow-emerald-200 border-emerald-400' : 'bg-white text-slate-800 border-slate-100 hover:border-emerald-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'day' ? 'bg-white/20 text-white' : 'bg-emerald-50 text-emerald-600'}`}>
                    <Calendar size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Hoje</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.day)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'day' ? 'text-emerald-100' : 'text-slate-400'}`}>Produção do dia</p>
                </div>
              </button>

              <button 
                onClick={() => setSelectedTimeframe('week')}
                className={`text-left p-5 rounded-3xl border transition-all ${selectedTimeframe === 'week' ? 'bg-violet-500 text-white shadow-xl shadow-violet-200 border-violet-400' : 'bg-white text-slate-800 border-slate-100 hover:border-violet-200'}`}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className={`p-2 rounded-xl ${selectedTimeframe === 'week' ? 'bg-white/20 text-white' : 'bg-violet-50 text-violet-600'}`}>
                    <CalendarDays size={18} />
                  </div>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Esta Semana</span>
                </div>
                <div>
                  <div className="text-2xl font-black mb-1">{formatWeight(totals.week)}</div>
                  <p className={`text-[9px] font-bold ${selectedTimeframe === 'week' ? 'text-violet-100' : 'text-slate-400'}`}>Dom - Sáb</p>
                </div>
              </button>
            </div>

            <div className="flex items-center gap-2 px-2">
              <span className="w-2 h-2 rounded-full bg-slate-300"></span>
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                Visualizando dados: <span className="text-blue-600">{
                  selectedTimeframe === 'day' ? 'Hoje' : 
                  selectedTimeframe === 'week' ? 'Esta Semana' : 
                  'Mês Atual'
                }</span>
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight },
                { title: '♻️ Eco B Manutenção', key: 'ecoBM', color: ['#8b5cf6', '#a78bfa', '#c4b5fd'], formatter: formatWeight },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes },
                { title: '📊 Líquido vs Eco B', key: 'comparison_prod_ecob', color: ['#3b82f6', '#8b5cf6'], formatter: formatWeight },
                { title: '📊 Líquido vs Borra', key: 'comparison_prod_borra', color: ['#3b82f6', '#ef4444'], formatter: formatWeight },
                { title: '⏱️ Tempo Máquina (Min)', key: 'comparison_time', color: ['#3b82f6', '#ef4444'], formatter: formatMinutes }
              ].map((chart, idx) => {
                let chartData: any[] = [];
                let dataKey = chart.key;

                if (chart.key === 'comparison_prod_ecob') {
                  const totalProd = filteredDataForCharts.reduce((acc, c) => acc + (c.netWeight || 0), 0);
                  const totalEcoB = filteredDataForCharts.reduce((acc, c) => acc + (c.ecoBP || 0) + (c.ecoBM || 0), 0);
                  chartData = [{ name: 'Produção', value: totalProd }, { name: 'Eco B', value: totalEcoB }].filter(d => d.value > 0);
                  dataKey = 'value';
                } else if (chart.key === 'comparison_prod_borra') {
                  const totalProd = filteredDataForCharts.reduce((acc, c) => acc + (c.netWeight || 0), 0);
                  const totalBorra = filteredDataForCharts.reduce((acc, c) => acc + (c.borraTotal || 0), 0);
                  chartData = [{ name: 'Produção', value: totalProd }, { name: 'Borra', value: totalBorra }].filter(d => d.value > 0);
                  dataKey = 'value';
                } else if (chart.key === 'comparison_time') {
                  let totalAvailable = 0;
                  let totalDowntime = 0;
                  filteredDataForCharts.forEach(item => {
                     const shiftDuration = getShiftDuration(item.shift);
                     if (item.isNoWorkDay) {
                        totalAvailable += shiftDuration;
                        totalDowntime += shiftDuration;
                     } else {
                        const stops = (item.manutencaoMin || 0) + (item.processoMin || 0) + (item.outrosMin || 0);
                        totalAvailable += shiftDuration;
                        totalDowntime += stops;
                     }
                  });
                  const totalRunning = Math.max(0, totalAvailable - totalDowntime);
                  chartData = [{ name: 'Produção', value: totalRunning }, { name: 'Parada', value: totalDowntime }].filter(d => d.value > 0);
                  dataKey = 'value';
                } else {
                  chartData = stats.filter(s => s[chart.key as keyof OperatorStat] > 0);
                }

                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-[400px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
                    <div className="flex-1">
                      {chartData.length > 0 ? (
                        <ResponsiveContainer width="100%" height="100%">
                          <PieChart>
                            <Pie 
                              data={chartData} cx="50%" cy="50%" innerRadius={60} outerRadius={85} 
                              dataKey={dataKey} nameKey="name" label={renderCustomizedLabel} paddingAngle={2}
                            >
                              {chartData.map((_, i) => <Cell key={i} fill={chart.color[i % chart.color.length]} stroke="none" />)}
                            </Pie>
                            <Tooltip formatter={(val: any) => chart.formatter(val)} />
                            <Legend iconType="circle" formatter={(value, entry: any) => <span className="text-[10px] font-bold text-slate-600 ml-1">{value} ({chart.formatter(entry.payload.value)})</span>} />
                          </PieChart>
                        </ResponsiveContainer>
                      ) : (
                        <div className="h-full flex items-center justify-center text-slate-300 font-bold text-xs uppercase">Sem dados neste período</div>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex flex-wrap items-center justify-between gap-4">
              <div className="flex flex-wrap items-center gap-4 flex-1 min-w-[300px]">
                <div className="flex flex-col gap-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Data Inicial</label>
                  <input 
                    type="date" 
                    value={filterStartDate}
                    onChange={(e) => setFilterStartDate(e.target.value)}
                    className="bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-xs font-bold focus:outline-none"
                  />
                </div>
                <div className="flex flex-col gap-1">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Data Final</label>
                  <input 
                    type="date" 
                    value={filterEndDate}
                    onChange={(e) => setFilterEndDate(e.target.value)}
                    className="bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-xs font-bold focus:outline-none"
                  />
                </div>
                <div className="flex flex-col gap-1 flex-1 min-w-[150px]">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Pesquisar</label>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
                    <input 
                      type="text" 
                      value={searchTerm} 
                      onChange={(e) => setSearchTerm(e.target.value)}
                      placeholder="Pesquisar registros..." 
                      className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold focus:outline-none" 
                    />
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-2 no-print self-end mb-1">
                {selectedIds.length > 0 && (
                  <button 
                    onClick={handleDeleteSelected}
                    className="flex items-center gap-2 bg-red-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase shadow-lg shadow-red-100 transition-all"
                  >
                    <Trash2 size={14} /> Excluir ({selectedIds.length})
                  </button>
                )}
                <button 
                  onClick={handleExportCSV}
                  className="p-2.5 bg-emerald-600 text-white rounded-xl flex items-center gap-2 text-[10px] font-black uppercase transition-all hover:bg-emerald-700 shadow-lg shadow-emerald-100"
                  title="Exportar Excel/CSV"
                >
                  <FileSpreadsheet size={18} /> Exportar CSV
                </button>
                <button type="button" onClick={() => window.print()} className="p-2.5 bg-slate-800 text-white rounded-xl">
                  <Printer size={18} />
                </button>
              </div>
            </div>
            <div className="overflow-x-auto custom-scrollbar">
              <table className="w-full text-left border-collapse min-w-[1500px]">
                <thead>
                  <tr className="bg-slate-50 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                    <th className="px-4 py-4 text-center no-print">
                      <button onClick={() => toggleSelectAll(filteredReports)} className="text-slate-400 hover:text-blue-500">
                        {selectedIds.length > 0 && selectedIds.length === filteredReports.length ? <CheckSquare size={16} className="text-blue-600" /> : <Square size={16} />}
                      </button>
                    </th>
                    <th className="px-4 py-4">Data</th>
                    <th className="px-4 py-4">Operador</th>
                    <th className="px-4 py-4">Máquina</th>
                    <th className="px-4 py-4">Turno</th>
                    <th className="px-4 py-4 text-right">Peso Bruto</th>
                    <th className="px-4 py-4 text-right">Tara</th>
                    <th className="px-4 py-4 text-right">Peso Líquido</th>
                    <th className="px-4 py-4 text-right">Volumes</th>
                    <th className="px-4 py-4 text-right">Tubetes</th>
                    <th className="px-4 py-4 text-right">Eco A</th>
                    <th className="px-4 py-4 text-right">Eco B (P)</th>
                    <th className="px-4 py-4 text-right">Eco B (M)</th>
                    <th className="px-4 py-4 text-right">Borra Total</th>
                    <th className="px-4 py-4 text-right">Manut. (Min)</th>
                    <th className="px-4 py-4 text-right">Proc. (Min)</th>
                    <th className="px-4 py-4 text-right">Outros (Min)</th>
                    <th className="px-4 py-4 text-right no-print">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 text-[10px] font-bold">
                  {filteredReports.length > 0 ? (
                    <>
                      {filteredReports.map((e) => (
                        <tr key={e.id} className={`hover:bg-slate-50 transition-colors ${selectedIds.includes(e.id) ? 'bg-blue-50/30' : ''}`}>
                          <td className="px-4 py-4 text-center no-print">
                             <button onClick={() => toggleSelectId(e.id)} className="text-slate-300 hover:text-blue-500">
                               {selectedIds.includes(e.id) ? <CheckSquare size={14} className="text-blue-600" /> : <Square size={14} />}
                             </button>
                          </td>
                          <td className="px-4 py-4 whitespace-nowrap">{e.date}</td>
                          <td className="px-4 py-4 whitespace-nowrap">{e.operator}</td>
