                          <td className="px-4 py-4 text-right text-emerald-600">{e.ecoBM}</td>
                          <td className="px-4 py-4 text-right text-red-500">{e.borraTotal}</td>
                          <td className="px-4 py-4 text-right">{e.manutencaoMin}</td>
