            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {[
                { title: '🏆 Produção Líquida', key: 'prod', color: COLORS, formatter: formatWeight, description: 'Distribuição da produção total de material acabado entre os operadores no período.' },
                { title: '♻️ Eco A (KG)', key: 'ecoA', color: ['#10b981', '#34d399', '#6ee7b7'], formatter: formatWeight, description: 'Volume total de material reciclado do tipo Eco A gerado durante o processo.' },
                { title: '♻️ Eco B Produção', key: 'ecoBP', color: ['#3b82f6', '#60a5fa', '#93c5fd'], formatter: formatWeight, description: 'Resíduos tipo Eco B originados diretamente da operação normal das máquinas.' },
                { title: '♻️ Eco B Manutenção', key: 'ecoBM', color: ['#8b5cf6', '#a78bfa', '#c4b5fd'], formatter: formatWeight, description: 'Resíduos tipo Eco B gerados especificamente em processos de manutenção e ajuste.' },
                { title: '🗑️ Borra Total', key: 'borra', color: ['#f43f5e', '#fb7185', '#fda4af'], formatter: formatWeight, description: 'Desperdício não reaproveitável (purga) gerado por cada operador/máquina.' },
                { title: '⏱️ Paradas (Min)', key: 'p_manut', color: ['#ef4444', '#f59e0b', '#64748b'], formatter: formatMinutes, description: 'Tempo total em minutos que as máquinas ficaram inoperantes por diversos motivos.' },
                { title: '📊 Líquido vs Eco B', key: 'comparison_prod_ecob', color: ['#3b82f6', '#8b5cf6'], formatter: formatWeight, description: 'Comparação proporcional entre o material final produzido e o volume de Eco B gerado.' },
                { title: '📊 Líquido vs Borra', key: 'comparison_prod_borra', color: ['#3b82f6', '#ef4444'], formatter: formatWeight, description: 'Análise de eficiência comparando o peso líquido produzido contra o desperdício total.' },
                { title: '⏱️ Tempo Máquina (Min)', key: 'comparison_time', color: ['#3b82f6', '#ef4444'], formatter: formatMinutes, description: 'Indicador de disponibilidade: tempo de operation ativa vs tempo total de paradas.' }
              ].map((chart, idx) => {
                let chartData: any[] = [];
                let dataKey = chart.key;
                const isOperatorChart = !chart.key.startsWith('comparison_');

                if (chart.key === 'comparison_prod_ecob') {
                  const totalProd = filteredDataForCharts.reduce((acc, c) => acc + (c.netWeight || 0), 0);
                  const totalEcoB = filteredDataForCharts.reduce((acc, c) => acc + (c.ecoBP || 0) + (c.ecoBM || 0), 0);
                  chartData = [{ name: 'Produção', value: totalProd }, { name: 'Eco B', value: totalEcoB }].filter(d => d.value > 0);
                  dataKey = 'value';
                } else if (chart.key === 'comparison_prod_borra') {
                  const totalProd = filteredDataForCharts.reduce((acc, c) => acc + (c.netWeight || 0), 0);
                  const totalBorra = filteredDataForCharts.reduce((acc, c) => acc + (c.borraTotal || 0), 0);
                  chartData = [{ name: 'Produção', value: totalProd }, { name: 'Borra', value: totalBorra }].filter(d => d.value > 0);
                  dataKey = 'value';
                } else if (chart.key === 'comparison_time') {
                  let totalAvailable = 0;
                  let totalDowntime = 0;
                  filteredDataForCharts.forEach(item => {
                     const shiftDuration = getShiftDuration(item.shift);
                     if (item.isNoWorkDay) {
                        totalAvailable += shiftDuration;
                        totalDowntime += shiftDuration;
                     } else {
                        const stops = (item.manutencaoMin || 0) + (item.processoMin || 0) + (item.outrosMin || 0);
                        totalAvailable += shiftDuration;
                        totalDowntime += stops;
                     }
                  });
                  const totalRunning = Math.max(0, totalAvailable - totalDowntime);
                  chartData = [{ name: 'Produção', value: totalRunning }, { name: 'Parada', value: totalDowntime }].filter(d => d.value > 0);
                  dataKey = 'value';
                } else {
                  // Filtra e ordena para criar o ranking
                  chartData = stats
                    .filter(s => (s[chart.key as keyof OperatorStat] as number) > 0)
                    .sort((a, b) => (b[chart.key as keyof OperatorStat] as number) - (a[chart.key as keyof OperatorStat] as number));
                }

                return (
                  <div key={idx} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 min-h-[460px] flex flex-col">
                    <h3 className="font-black text-xs uppercase tracking-widest text-slate-800 mb-4">{chart.title}</h3>
