                            <Legend 
                              iconType="circle" 
                              formatter={(value, entry: any, index: number) => (
                                <span className="text-[10px] font-bold text-slate-600 ml-1">
                                  {isOperatorChart ? `${index + 1}º ` : ''}{value} ({chart.formatter(entry.payload.value)})
