                    <button onClick={() => setOperators(prev => prev.filter(o => o !== op))} className="text-slate-300 hover:text-red-500 transition-colors p-1" title="Remover operador"><Trash2 size={14} /></button>
                  </div>
                ))}
              </div>
            </div>
            <div className="pt-8 border-t border-slate-100 space-y-3">
              <button 
                onClick={handleSaveDashboardPDF} 
                disabled={isGeneratingPDF || activeTab !== 'dashboard'}
                className={`w-full flex items-center justify-center gap-3 py-4 rounded-2xl text-[10px] font-black uppercase transition-all ${activeTab !== 'dashboard' ? 'bg-slate-50 text-slate-300 cursor-not-allowed' : 'bg-blue-600 text-white shadow-lg shadow-blue-100'}`}
              >
                <FileDown size={16} /> {isGeneratingPDF ? 'Processando PDF...' : 'Salvar Dashboard PDF'}
              </button>
              <button onClick={() => {
                const data = { productionData, shifts, goalValue, operators };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a'); a.href = url; a.download = 'backup_manupackaging.json'; a.click();
              }} className="w-full flex items-center justify-center gap-3 bg-slate-100 py-4 rounded-2xl text-[10px] font-black uppercase text-slate-600"><Download size={16} /> Exportar Backup</button>
              <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-3 bg-blue-50 py-4 rounded-2xl text-[10px] font-black uppercase text-blue-600"><Upload size={16} /> Importar Backup</button>
              <button onClick={() => { localStorage.removeItem('manupackaging_session'); setIsAuthenticated(false); }} className="w-full flex items-center justify-center gap-3 bg-red-50 py-4 rounded-2xl text-[10px] font-black uppercase text-red-600"><LogOut size={16} /> Sair do Sistema</button>
            </div>
          </div>
        </div>
      </div>

      {/* Modal de Confirmação Customizado */}
      {confirmDialog.isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl w-full max-w-sm shadow-2xl p-6 space-y-6 animate-in zoom-in-95 duration-200">
            <div className="flex flex-col items-center text-center space-y-4">
              <div className="w-16 h-16 bg-red-50 text-red-600 rounded-full flex items-center justify-center shadow-inner">
                <AlertCircle size={32} />
              </div>
              <div className="space-y-2">
                <h3 className="text-lg font-black text-slate-800 uppercase tracking-tight">{confirmDialog.title}</h3>
                <p className="text-xs text-slate-500 font-medium leading-relaxed px-4">{confirmDialog.message}</p>
              </div>
            </div>
            <div className="flex gap-3 pt-2">
              <button 
                onClick={() => setConfirmDialog(prev => ({ ...prev, isOpen: false }))}
                className="flex-1 px-4 py-3 bg-slate-50 text-slate-500 rounded-2xl font-black text-[10px] uppercase hover:bg-slate-100 transition-all"
              >
                Cancelar
              </button>
              <button 
                onClick={confirmDialog.onConfirm}
                className="flex-1 px-4 py-3 bg-red-600 text-white rounded-2xl font-black text-[10px] uppercase shadow-lg shadow-red-200 hover:bg-red-700 transition-all"
              >
                Confirmar Excluir
              </button>
            </div>
          </div>
        </div>
      )}

      <input type="file" ref={fileInputRef} onChange={handleImport} className="hidden" accept=".json" />
      <LaunchModal isOpen={isModalOpen} onClose={() => { setIsModalOpen(false); setEditingEntry(null); }} onSave={handleSaveEntry} operators={operators} activeMachines={['Cast 1', 'Cast 2', 'Erema 1']} availableShifts={shifts} initialData={editingEntry} />
      <ShiftModal isOpen={isShiftModalOpen} onClose={() => setIsShiftModalOpen(false)} onSave={(s) => setShifts(prev => [...prev, { ...s, id: Math.random().toString() }])} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { X, Save, Edit2, Package, Layers, Trash2, Clock, Wrench, CalendarX } from 'lucide-react';
import { ProductionEntry, Shift } from '../types';

interface LaunchModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (entry: Omit<ProductionEntry, 'id'> & { id?: string }) => void;
  operators: string[];
  activeMachines: string[];
  availableShifts: Shift[];
  initialData?: ProductionEntry | null;
}

const getYesterdayStr = () => {
  const d = new Date();
  d.setDate(d.getDate() - 1);
  return d.toLocaleDateString('sv-SE');
};

const LaunchModal: React.FC<LaunchModalProps> = ({ isOpen, onClose, onSave, operators, activeMachines, availableShifts, initialData }) => {
  const [formData, setFormData] = useState({
    date: getYesterdayStr(),
    operator: '',
    machine: '',
    shift: '',
    grossWeight: 0,
    tara: 0,
    netWeight: 0,
    volumes: 0,
    tubetes: 0,
    ecoA: 0,
    ecoBP: 0,
    ecoBM: 0,
    borraTotal: 0,
    manutencaoMin: 0,
    manutencaoMotivo: '',
    processoMin: 0,
    processoMotivo: '',
    outrosMin: 0,
    outrosMotivo: '',
    isMaintenanceEntry: false,
    isNoWorkDay: false,
    noWorkReason: '',
  });

  useEffect(() => {
    if (isOpen) {
      if (initialData) {
        setFormData({
          date: initialData.date,
          operator: initialData.operator,
          machine: initialData.machine,
          shift: initialData.shift,
          grossWeight: initialData.grossWeight,
          tara: initialData.tara,
          netWeight: initialData.netWeight,
          volumes: initialData.volumes,
          tubetes: initialData.tubetes,
          ecoA: initialData.ecoA,
          ecoBP: initialData.ecoBP,
          ecoBM: initialData.ecoBM,
          borraTotal: initialData.borraTotal,
          manutencaoMin: initialData.manutencaoMin,
          manutencaoMotivo: initialData.manutencaoMotivo || '',
          processoMin: initialData.processoMin,
          processoMotivo: initialData.processoMotivo || '',
          outrosMin: initialData.outrosMin,
          outrosMotivo: initialData.outrosMotivo || '',
          isMaintenanceEntry: initialData.isMaintenanceEntry || false,
          isNoWorkDay: initialData.isNoWorkDay || false,
          noWorkReason: initialData.noWorkReason || '',
        });
      } else {
        setFormData({
          date: getYesterdayStr(),
          operator: '',
          machine: activeMachines.length > 0 ? activeMachines[0] : '',
          shift: availableShifts.length > 0 ? availableShifts[0].name : '',
          grossWeight: 0,
          tara: 0,
          netWeight: 0,
          volumes: 0,
          tubetes: 0,
          ecoA: 0,
          ecoBP: 0,
          ecoBM: 0,
          borraTotal: 0,
          manutencaoMin: 0,
          manutencaoMotivo: '',
          processoMin: 0,
          processoMotivo: '',
          outrosMin: 0,
          outrosMotivo: '',
          isMaintenanceEntry: false,
          isNoWorkDay: false,
          noWorkReason: '',
        });
      }
    }
  }, [isOpen, initialData, activeMachines, availableShifts]);

  useEffect(() => {
    setFormData(prev => ({
      ...prev,
      netWeight: (prev.isMaintenanceEntry || prev.isNoWorkDay) ? 0 : Math.max(0, prev.grossWeight - prev.tara)
    }));
  }, [formData.grossWeight, formData.tara, formData.isMaintenanceEntry, formData.isNoWorkDay]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.operator) {
      alert('Por favor, selecione um operador.');
      return;
    }
    if (!formData.machine) {
      alert('Nenhuma máquina ativa selecionada.');
      return;
    }
    if (!formData.shift) {
      alert('Por favor, selecione um turno.');
      return;
    }

    const isSpecialEntry = formData.isMaintenanceEntry || formData.isNoWorkDay;
    const finalData = isSpecialEntry ? {
      ...formData,
      grossWeight: 0,
      tara: 0,
      netWeight: 0,
      volumes: 0,
      tubetes: 0,
      ecoA: 0,
      ecoBP: 0,
      ecoBM: 0,
      borraTotal: 0,
      manutencaoMin: formData.isNoWorkDay ? 0 : formData.manutencaoMin,
      processoMin: formData.isNoWorkDay ? 0 : formData.processoMin,
      outrosMin: formData.isNoWorkDay ? 0 : formData.outrosMin,
    } : formData;

    onSave(initialData ? { ...finalData, id: initialData.id } : finalData);
    onClose();
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value, type } = e.target as HTMLInputElement;
    let val: any;

    if (type === 'checkbox') {
      val = (e.target as HTMLInputElement).checked;

      if (name === 'isNoWorkDay' && val) {
        setFormData(prev => ({ ...prev, [name]: val, isMaintenanceEntry: false }));
        return;
      }
      if (name === 'isMaintenanceEntry' && val) {
        setFormData(prev => ({ ...prev, [name]: val, isNoWorkDay: false }));
        return;
      }
    } else {
      val = type === 'number' ? parseFloat(value) || 0 : value;
    }

    setFormData(prev => ({ ...prev, [name]: val }));
  };

  const totalParadas = formData.manutencaoMin + formData.processoMin + formData.outrosMin;
  const isHiddenProduction = formData.isMaintenanceEntry || formData.isNoWorkDay;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm overflow-y-auto">
      <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl relative overflow-hidden my-auto">
        <div className="bg-[#1e293b] text-white p-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            {initialData ? <Edit2 size={20} /> : <Save size={20} />}
            <h2 className="text-lg font-semibold tracking-tight uppercase">{initialData ? 'Editar Lançamento' : 'Novo Lançamento'}</h2>
          </div>
          <button onClick={onClose} className="hover:bg-white/10 p-1 rounded-full transition-colors">
            <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-5 max-h-[80vh] overflow-y-auto custom-scrollbar">

          <div className="grid grid-cols-2 gap-3">
            <div className={`p-3 rounded-xl flex items-center justify-between transition-colors border ${formData.isMaintenanceEntry ? 'bg-orange-50 border-orange-200' : 'bg-slate-50 border-slate-200'}`}>
              <div className="flex items-center gap-2">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center ${formData.isMaintenanceEntry ? 'bg-orange-100 text-orange-600' : 'bg-slate-200 text-slate-500'}`}>
                  <Wrench size={16} />
                </div>
                <div><h3 className="text-[9px] font-black text-slate-800 uppercase">Manutenção</h3></div>
              </div>
              <label className="relative inline-flex items-center cursor-pointer">
                <input type="checkbox" name="isMaintenanceEntry" checked={formData.isMaintenanceEntry} onChange={handleChange} className="sr-only peer" />
                <div className="w-8 h-4 bg-slate-200 rounded-full peer peer-checked:after:translate-x-full after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:rounded-full after:h-3 after:w-3 after:transition-all peer-checked:bg-orange-600"></div>
              </label>
            </div>

            <div className={`p-3 rounded-xl flex items-center justify-between transition-colors border ${formData.isNoWorkDay ? 'bg-red-50 border-red-200' : 'bg-slate-50 border-slate-200'}`}>
              <div className="flex items-center gap-2">
                <div className={`w-8 h-8 rounded-full flex items-center justify-center ${formData.isNoWorkDay ? 'bg-red-100 text-red-600' : 'bg-slate-200 text-slate-500'}`}>
                  <CalendarX size={16} />
                </div>
                <div><h3 className="text-[9px] font-black text-slate-800 uppercase">Parado</h3></div>
              </div>
              <label className="relative inline-flex items-center cursor-pointer">
                <input type="checkbox" name="isNoWorkDay" checked={formData.isNoWorkDay} onChange={handleChange} className="sr-only peer" />
                <div className="w-8 h-4 bg-slate-200 rounded-full peer peer-checked:after:translate-x-full after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:rounded-full after:h-3 after:w-3 after:transition-all peer-checked:bg-red-600"></div>
              </label>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Data</label>
              <input type="date" name="date" value={formData.date} onChange={handleChange} className="w-full mt-1 bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-blue-500/20" />
            </div>
            <div>
              <label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Operador</label>
              <select name="operator" value={formData.operator} onChange={handleChange} className="w-full mt-1 bg-slate-50 border border-slate-200 rounded-xl px-3 py-2 text-sm font-bold">
                <option value="">Selecione...</option>
                {operators.map(op => <option key={op} value={op}>{op}</option>)}
              </select>
            </div>
