  const totals = useMemo(() => {
    const now = new Date();
    const yesterday = new Date(now);
    yesterday.setDate(now.getDate() - 1);
    const yesterdayStr = yesterday.toLocaleDateString('sv-SE');

    const startOfWeek = new Date(now);
    startOfWeek.setHours(0,0,0,0);
    startOfWeek.setDate(now.getDate() - now.getDay());
    return productionData.reduce((acc, e) => {
      if (e.date.startsWith(dashboardMonth)) acc.month += e.netWeight;
      if (e.date === yesterdayStr) acc.day += e.netWeight;
      const entryDate = new Date(e.date + 'T00:00:00');
      if (entryDate >= startOfWeek) acc.week += e.netWeight;
      return acc;
    }, { month: 0, day: 0, week: 0 });
  }, [productionData, dashboardMonth]);

  useEffect(() => {
    if (totals.month >= goalValue && totals.month > 0) {
      const duration = 5 * 1000;
      const animationEnd = Date.now() + duration;
      const defaults = { startVelocity: 30, spread: 360, ticks: 60, zIndex: 100 };
      const randomInRange = (min: number, max: number) => Math.random() * (max - min) + min;
      const interval: any = setInterval(function() {
        const timeLeft = animationEnd - Date.now();
        if (timeLeft <= 0) return clearInterval(interval);
        const particleCount = 50 * (timeLeft / duration);
        confetti({ ...defaults, particleCount, origin: { x: randomInRange(0.1, 0.3), y: Math.random() - 0.2 } });
        confetti({ ...defaults, particleCount, origin: { x: randomInRange(0.7, 0.9), y: Math.random() - 0.2 } });
      }, 250);
      return () => clearInterval(interval);
    }
  }, [totals.month, goalValue]);

  const changeMonth = (direction: number) => {
    const [year, month] = dashboardMonth.split('-').map(Number);
    const date = new Date(year, month - 1 + direction, 1);
    setDashboardMonth(date.toISOString().slice(0, 7));
