                     const shiftDuration = getShiftDuration(item.shift);
                     if (item.isNoWorkDay) { totalAvailable += shiftDuration; totalDowntime += shiftDuration; } else { const stops = (item.manutencaoMin || 0) + (item.processoMin || 0) + (item.outrosMin || 0); totalAvailable += shiftDuration; totalDowntime += stops; }
                  });
                  const totalRunning = Math.max(0, totalAvailable - totalDowntime);
                  chartData = [{ name: 'Produção', value: totalRunning }, { name: 'Parada', value: totalDowntime }].filter(d => d.value > 0);
                  dataKey = 'value';
                } else {
                  chartData = stats.filter(s => (s[chart.key as keyof OperatorStat] as number) > 0).sort((a, b) => (b[chart.key as keyof OperatorStat] as number) - (a[chart.key as keyof OperatorStat] as number));
