                <button onClick={() => { if (newOpName && !operators.includes(newOpName)) { setOperators(prev => [...prev, newOpName]); setNewOpName(''); } }} className="bg-blue-600 text-white p-3 rounded-2xl"><Plus size={18} /></button>
              </div>
              <div className="mt-2 max-h-48 overflow-y-auto custom-scrollbar space-y-2 pr-1">
                {operators.map((op, idx) => (
                  <div key={idx} className="flex items-center justify-between bg-slate-50 p-3 rounded-xl border border-slate-100 hover:border-blue-100 transition-colors group">
                    <span className="text-xs font-bold text-slate-600">{op}</span>
                    <button onClick={() => setOperators(prev => prev.filter(o => o !== op))} className="text-slate-300 hover:text-red-500 transition-colors p-1" title="Remover operador"><Trash2 size={14} /></button>
