                    <div className="mt-4 pt-3 border-t border-slate-50">
                      <p className="text-[9px] font-medium text-slate-400 italic leading-relaxed flex items-start gap-1.5"><Info size={10} className="mt-0.5 shrink-0 text-blue-400" />{chart.description}</p>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
