                      <button onClick={() => toggleSelectAll(filteredReports)} className="text-slate-400 hover:text-blue-500">{selectedIds.length > 0 && selectedIds.length === filteredReports.length ? <CheckSquare size={16} className="text-blue-600" /> : <Square size={16} />}</button>
                    </th>
                    <th className="px-4 py-4">Data</th>
