        <div className={`absolute right-0 top-0 bottom-0 w-80 bg-white shadow-2xl transition-transform duration-300 transform p-8 flex flex-col gap-8 ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
